fn protected_scope_is_related(
    compiled: &CompiledUnit,
    scope: &str,
    declaring_class: &str,
) -> Result<bool, String> {
    Ok(class_is_or_extends(compiled, scope, declaring_class)?
        || class_is_or_extends(compiled, declaring_class, scope)?)
}

fn protected_scope_is_related_in_state(
    compiled: &CompiledUnit,
    state: &ExecutionState,
    scope: &str,
    declaring_class: &str,
) -> Result<bool, String> {
    Ok(
        class_is_a_in_state(compiled, state, scope, declaring_class)?
            || class_is_a_in_state(compiled, state, declaring_class, scope)?,
    )
}

/// Renders the calling scope for access-violation messages: PHP says
/// `"global scope"` outside a class and `"scope Class"` inside one.
fn scope_description(scope: Option<&str>) -> String {
    match scope {
        Some(scope) => format!("scope {scope}"),
        None => "global scope".to_owned(),
    }
}

fn lookup_method_in_hierarchy<'a>(
    compiled: &'a CompiledUnit,
    class: &'a php_ir::module::ClassEntry,
    method: &str,
    caller_scope: Option<&str>,
) -> Result<Option<ResolvedMethod<'a>>, String> {
    if let Some(resolved) =
        lookup_private_method_in_caller_scope(compiled, class, method, caller_scope)?
    {
        return Ok(Some(resolved));
    }
    lookup_method_in_hierarchy_inner(compiled, class, method, caller_scope, &mut Vec::new())
}

fn lookup_private_method_in_caller_scope<'a>(
    compiled: &'a CompiledUnit,
    class: &'a php_ir::module::ClassEntry,
    method: &str,
    caller_scope: Option<&str>,
) -> Result<Option<ResolvedMethod<'a>>, String> {
    let Some(scope) = caller_scope else {
        return Ok(None);
    };
    if !class_is_or_extends(compiled, &class.name, scope)? {
        return Ok(None);
    }
    let Some(scope_class) = compiled.lookup_class(scope) else {
        return Ok(None);
    };
    let normalized = normalize_method_name(method);
    let Some(scope_method) = scope_class
        .methods
        .iter()
        .find(|entry| entry.flags.is_private && normalize_method_name(&entry.name) == normalized)
    else {
        return Ok(None);
    };
    Ok(Some(ResolvedMethod {
        class: scope_class,
        method: scope_method,
    }))
}

fn lookup_method_in_hierarchy_inner<'a>(
    compiled: &'a CompiledUnit,
    class: &'a php_ir::module::ClassEntry,
    method: &str,
    caller_scope: Option<&str>,
    seen: &mut Vec<String>,
) -> Result<Option<ResolvedMethod<'a>>, String> {
    let class_name = normalize_class_name(&class.name);
    if seen.iter().any(|name| name == &class_name) {
        return Err(format!(
            "E_PHP_VM_CLASS_INHERITANCE_CYCLE: class {} participates in an inheritance cycle",
            class.name
        ));
    }
    seen.push(class_name.clone());
    let normalized = normalize_method_name(method);
    if let Some(method) = class
        .methods
        .iter()
        .find(|entry| normalize_method_name(&entry.name) == normalized)
    {
        if method.flags.is_private
            && caller_scope.is_some_and(|scope| normalize_class_name(scope) != class_name)
            && class.parent.is_some()
            && let Some(parent) = parent_class(compiled, class)?
            && let Some(parent_method) = lookup_method_in_hierarchy_inner(
                compiled,
                parent,
                method.name.as_str(),
                caller_scope,
                seen,
            )?
        {
            seen.pop();
            return Ok(Some(parent_method));
        }
        seen.pop();
        return Ok(Some(ResolvedMethod { class, method }));
    }
    if let Some(parent) = parent_class(compiled, class)? {
        let resolved =
            lookup_method_in_hierarchy_inner(compiled, parent, method, caller_scope, seen)?;
        seen.pop();
        return Ok(resolved);
    }
    seen.pop();
    Ok(None)
}

fn parent_class<'a>(
    compiled: &'a CompiledUnit,
    class: &php_ir::module::ClassEntry,
) -> Result<Option<&'a php_ir::module::ClassEntry>, String> {
    let Some(parent) = class.parent.as_deref() else {
        return Ok(None);
    };
    if internal_runtime_parent_is_known(class, parent) {
        return Ok(None);
    }
    if internal_runtime_class_entry(&normalize_class_name(parent)).is_some() {
        return Ok(None);
    }
    compiled.lookup_class(parent).map(Some).ok_or_else(|| {
        format!(
            "E_PHP_VM_UNKNOWN_PARENT_CLASS: class {} extends missing class {}",
            class.name, parent
        )
    })
}

fn lookup_property_in_hierarchy<'a>(
    compiled: &'a CompiledUnit,
    class: &'a php_ir::module::ClassEntry,
    property: &str,
    caller_scope: Option<&str>,
) -> Result<Option<ResolvedProperty<'a>>, String> {
    if let Some(resolved) =
        lookup_private_property_in_caller_scope(compiled, class, property, caller_scope)?
    {
        return Ok(Some(resolved));
    }
    lookup_property_in_hierarchy_inner(compiled, class, property, caller_scope, &mut Vec::new())
}

fn lookup_private_property_in_caller_scope<'a>(
    compiled: &'a CompiledUnit,
    class: &'a php_ir::module::ClassEntry,
    property: &str,
    caller_scope: Option<&str>,
) -> Result<Option<ResolvedProperty<'a>>, String> {
    let Some(scope) = caller_scope else {
        return Ok(None);
    };
    if !class_is_or_extends(compiled, &class.name, scope)? {
        return Ok(None);
    }
    let Some(scope_class) = compiled.lookup_class(scope) else {
        return Ok(None);
    };
    let Some(scope_property) = scope_class
        .properties
        .iter()
        .find(|entry| entry.flags.is_private && entry.name == property)
    else {
        return Ok(None);
    };
    Ok(Some(ResolvedProperty {
        class: scope_class,
        property: scope_property,
    }))
}

fn lookup_property_in_hierarchy_inner<'a>(
    compiled: &'a CompiledUnit,
    class: &'a php_ir::module::ClassEntry,
    property: &str,
    caller_scope: Option<&str>,
    seen: &mut Vec<String>,
) -> Result<Option<ResolvedProperty<'a>>, String> {
    let class_name = normalize_class_name(&class.name);
    if seen.iter().any(|name| name == &class_name) {
        return Err(format!(
            "E_PHP_VM_CLASS_INHERITANCE_CYCLE: class {} participates in an inheritance cycle",
            class.name
        ));
    }
    seen.push(class_name.clone());
    if let Some(entry) = class.properties.iter().find(|entry| entry.name == property) {
        if entry.flags.is_private
            && caller_scope.is_some_and(|scope| normalize_class_name(scope) != class_name)
            && class.parent.is_some()
            && let Some(parent) = parent_class(compiled, class)?
            && let Some(parent_property) = lookup_property_in_hierarchy_inner(
                compiled,
                parent,
                entry.name.as_str(),
                caller_scope,
                seen,
            )?
        {
            seen.pop();
            return Ok(Some(parent_property));
        }
        seen.pop();
        return Ok(Some(ResolvedProperty {
            class,
            property: entry,
        }));
    }
    if let Some(parent) = parent_class(compiled, class)? {
        let resolved =
            lookup_property_in_hierarchy_inner(compiled, parent, property, caller_scope, seen)?;
        seen.pop();
        return Ok(resolved);
    }
    seen.pop();
    Ok(None)
}

fn lookup_constant_in_hierarchy<'a>(
    compiled: &'a CompiledUnit,
    class: &'a php_ir::module::ClassEntry,
    constant: &str,
    caller_scope: Option<&str>,
) -> Result<Option<ResolvedConstant<'a>>, String> {
    lookup_constant_in_hierarchy_inner(compiled, class, constant, caller_scope, &mut Vec::new())
}

fn lookup_constant_in_hierarchy_inner<'a>(
    compiled: &'a CompiledUnit,
    class: &'a php_ir::module::ClassEntry,
    constant: &str,
    caller_scope: Option<&str>,
    seen: &mut Vec<String>,
) -> Result<Option<ResolvedConstant<'a>>, String> {
    let class_name = normalize_class_name(&class.name);
    if seen.iter().any(|name| name == &class_name) {
        return Err(format!(
            "E_PHP_VM_CLASS_INHERITANCE_CYCLE: class {} participates in an inheritance cycle",
            class.name
        ));
    }
    seen.push(class_name.clone());
    if let Some(entry) = class.constants.iter().find(|entry| entry.name == constant) {
        if entry.flags.is_private
            && caller_scope.is_some_and(|scope| normalize_class_name(scope) != class_name)
            && class.parent.is_some()
            && let Some(parent) = parent_class(compiled, class)?
            && let Some(parent_constant) = lookup_constant_in_hierarchy_inner(
                compiled,
                parent,
                entry.name.as_str(),
                caller_scope,
                seen,
            )?
        {
            seen.pop();
            return Ok(Some(parent_constant));
        }
        seen.pop();
        return Ok(Some(ResolvedConstant {
            class,
            constant: entry,
        }));
    }
    if let Some(parent) = parent_class(compiled, class)? {
        let resolved =
            lookup_constant_in_hierarchy_inner(compiled, parent, constant, caller_scope, seen)?;
        seen.pop();
        if resolved
            .as_ref()
            .is_some_and(|resolved| resolved.constant.flags.is_private)
        {
            return Ok(None);
        }
        return Ok(resolved);
    }
    seen.pop();
    Ok(None)
}

fn validate_property_access(
    compiled: &CompiledUnit,
    stack: &CallStack,
    class: &php_ir::module::ClassEntry,
    property: &php_ir::module::ClassPropertyEntry,
) -> Result<(), String> {
    if property.flags.is_private {
        let scope = current_scope_class(compiled, stack);
        if scope.as_deref() != Some(normalize_class_name(&class.name).as_str()) {
            return Err(format!(
                "E_PHP_VM_PRIVATE_PROPERTY_ACCESS: Cannot access private property {}::${}",
                class.display_name, property.name
            ));
        }
    }
    if property.flags.is_protected {
        let Some(scope) = current_scope_class(compiled, stack) else {
            return Err(format!(
                "E_PHP_VM_PROTECTED_PROPERTY_ACCESS: Cannot access protected property {}::${}",
                class.display_name, property.name
            ));
        };
        if !protected_scope_is_related(compiled, &scope, &class.name)? {
            return Err(format!(
                "E_PHP_VM_PROTECTED_PROPERTY_ACCESS: Cannot access protected property {}::${}",
                class.display_name, property.name
            ));
        }
    }
    Ok(())
}

fn validate_property_access_in_state(
    compiled: &CompiledUnit,
    state: &ExecutionState,
    stack: &CallStack,
    class: &php_ir::module::ClassEntry,
    property: &php_ir::module::ClassPropertyEntry,
) -> Result<(), String> {
    if property.flags.is_private {
        let scope = current_scope_class(compiled, stack);
        if scope.as_deref() != Some(normalize_class_name(&class.name).as_str()) {
            return Err(format!(
                "E_PHP_VM_PRIVATE_PROPERTY_ACCESS: Cannot access private property {}::${}",
                class.display_name, property.name
            ));
        }
    }
    if property.flags.is_protected {
        let Some(scope) = current_scope_class(compiled, stack) else {
            return Err(format!(
                "E_PHP_VM_PROTECTED_PROPERTY_ACCESS: Cannot access protected property {}::${}",
                class.display_name, property.name
            ));
        };
        if !protected_scope_is_related_in_state(compiled, state, &scope, &class.name)? {
            return Err(format!(
                "E_PHP_VM_PROTECTED_PROPERTY_ACCESS: Cannot access protected property {}::${}",
                class.display_name, property.name
            ));
        }
    }
    Ok(())
}

fn validate_property_set_access(
    compiled: &CompiledUnit,
    stack: &CallStack,
    class: &php_ir::module::ClassEntry,
    property: &php_ir::module::ClassPropertyEntry,
) -> Result<(), String> {
    if property.flags.set_is_private {
        let scope = current_scope_class(compiled, stack);
        if scope.as_deref() != Some(normalize_class_name(&class.name).as_str()) {
            return Err(format!(
                "E_PHP_VM_PRIVATE_PROPERTY_SET_ACCESS: property {}::${} setter is private",
                class.name, property.name
            ));
        }
    }
    if property.flags.set_is_protected {
        let Some(scope) = current_scope_class(compiled, stack) else {
            return Err(format!(
                "E_PHP_VM_PROTECTED_PROPERTY_SET_ACCESS: property {}::${} setter is protected",
                class.name, property.name
            ));
        };
        if !protected_scope_is_related(compiled, &scope, &class.name)? {
            return Err(format!(
                "E_PHP_VM_PROTECTED_PROPERTY_SET_ACCESS: property {}::${} setter is protected",
                class.name, property.name
            ));
        }
    }
    Ok(())
}

