fn iterator_function_accepts_source(
    compiled: &CompiledUnit,
    state: &ExecutionState,
    value: &Value,
) -> Result<bool, String> {
    match effective_value(value) {
        Value::Array(_) | Value::Generator(_) => Ok(true),
        Value::Object(object) => {
            if let Some(spl_class) = spl_runtime_marker(&object) {
                return Ok(internal_spl_iterator_instanceof(&spl_class, "Traversable")
                    .or_else(|| internal_spl_container_instanceof(&spl_class, "Traversable"))
                    .or_else(|| internal_spl_heap_instanceof(&spl_class, "Traversable"))
                    .or_else(|| internal_spl_file_instanceof(&spl_class, "Traversable"))
                    .unwrap_or(false));
            }
            object_instanceof_in_state(compiled, state, &Value::Object(object), "Traversable")
        }
        _ => Ok(false),
    }
}

fn property_storage_name(
    class: &php_ir::module::ClassEntry,
    property: &php_ir::module::ClassPropertyEntry,
) -> String {
    if property.flags.is_private {
        format!("private:{}:{}", class.display_name, property.name)
    } else {
        property.name.clone()
    }
}

#[cfg(feature = "jit-cranelift")]
fn property_load_pre_guard_status(
    compiled: &CompiledUnit,
    state: &ExecutionState,
    value: &Value,
    metadata: &php_jit::JitPropertyLoadMetadata,
) -> Option<i32> {
    if state.lookup_epoch().raw() != metadata.layout_version {
        return Some(JIT_PROPERTY_LOAD_STATUS_LAYOUT_EXIT);
    }
    let effective = match value {
        Value::Reference(cell) => cell.get(),
        other => other.clone(),
    };
    let Value::Object(object) = effective else {
        return Some(JIT_PROPERTY_LOAD_STATUS_CLASS_EXIT);
    };
    if normalize_class_name(&object.class_name()) != metadata.receiver_class {
        return Some(JIT_PROPERTY_LOAD_STATUS_CLASS_EXIT);
    }
    let Some(class) = lookup_class_in_state(compiled, state, &object.class_name()) else {
        return Some(JIT_PROPERTY_LOAD_STATUS_CLASS_EXIT);
    };
    if class.id.raw() != metadata.class_id {
        return Some(JIT_PROPERTY_LOAD_STATUS_CLASS_EXIT);
    }
    None
}

fn property_fetch_callsite(
    compiled: &CompiledUnit,
    function: FunctionId,
    block: BlockId,
    instruction: InstrId,
) -> String {
    let unit = compiled.unit();
    let function_name = unit
        .functions
        .get(function.index())
        .map(|entry| entry.name.as_str())
        .unwrap_or("<unknown>");
    format!(
        "unit{}:{}:b{}:i{}",
        unit.id.raw(),
        function_name,
        block.raw(),
        instruction.raw()
    )
}

fn method_call_callsite(
    compiled: &CompiledUnit,
    function: FunctionId,
    block: BlockId,
    instruction: InstrId,
) -> String {
    let unit = compiled.unit();
    let function_name = unit
        .functions
        .get(function.index())
        .map(|entry| entry.name.as_str())
        .unwrap_or("<unknown>");
    format!(
        "unit{}:{}:b{}:i{}",
        unit.id.raw(),
        function_name,
        block.raw(),
        instruction.raw()
    )
}

fn class_has_public_magic_get(compiled: &CompiledUnit, class: &php_ir::module::ClassEntry) -> bool {
    lookup_method_in_hierarchy(compiled, class, "__get", None)
        .ok()
        .flatten()
        .is_some_and(|resolved| {
            !resolved.method.flags.is_static
                && !resolved.method.flags.is_private
                && !resolved.method.flags.is_protected
        })
}

fn class_has_public_magic_set(compiled: &CompiledUnit, class: &php_ir::module::ClassEntry) -> bool {
    lookup_method_in_hierarchy(compiled, class, "__set", None)
        .ok()
        .flatten()
        .is_some_and(|resolved| {
            !resolved.method.flags.is_static
                && !resolved.method.flags.is_private
                && !resolved.method.flags.is_protected
        })
}

fn class_allows_dynamic_properties(
    compiled: &CompiledUnit,
    state: &ExecutionState,
    class: &php_ir::module::ClassEntry,
) -> bool {
    let mut current = Some(Arc::new(class.clone()));
    while let Some(entry) = current {
        if entry
            .attributes
            .iter()
            .any(attribute_is_allow_dynamic_properties)
        {
            return true;
        }
        current = entry
            .parent
            .as_deref()
            .and_then(|parent| lookup_class_in_state(compiled, state, parent));
    }
    false
}

fn attribute_is_allow_dynamic_properties(attribute: &php_ir::module::AttributeEntry) -> bool {
    [&attribute.resolved_name, &attribute.fallback_name]
        .into_iter()
        .filter_map(|name| name.as_deref())
        .chain(std::iter::once(attribute.name.as_str()))
        .any(|name| normalize_class_name(name) == "allowdynamicproperties")
}

fn dynamic_property_deprecation_diagnostic(
    compiled: &CompiledUnit,
    state: &ExecutionState,
    class: &php_ir::module::ClassEntry,
    object: &ObjectRef,
    property: &str,
    stack: &CallStack,
) -> Option<RuntimeDiagnostic> {
    (!class_allows_dynamic_properties(compiled, state, class)).then(|| {
        RuntimeDiagnostic::new(
            "E_PHP_VM_DYNAMIC_PROPERTY_DEPRECATED",
            RuntimeSeverity::Deprecation,
            format!(
                "E_PHP_VM_DYNAMIC_PROPERTY_DEPRECATED: creating dynamic property {}::${property}",
                object.class_name()
            ),
            RuntimeSourceSpan::default(),
            stack_trace(compiled, stack),
            None,
        )
    })
}

fn class_has_public_magic_call(
    compiled: &CompiledUnit,
    class: &php_ir::module::ClassEntry,
) -> bool {
    lookup_method_in_hierarchy(compiled, class, "__call", None)
        .ok()
        .flatten()
        .is_some_and(|resolved| {
            !resolved.method.flags.is_static
                && !resolved.method.flags.is_private
                && !resolved.method.flags.is_protected
        })
}

fn property_has_hooks_or_active(
    state: &ExecutionState,
    object: &ObjectRef,
    class: &php_ir::module::ClassEntry,
    property: &php_ir::module::ClassPropertyEntry,
) -> bool {
    property.hooks.get.is_some()
        || property.hooks.set.is_some()
        || property_hook_is_active(state, object, class, property)
}

#[allow(clippy::too_many_arguments)]
fn property_fetch_layout_metadata(
    receiver_class: &php_ir::module::ClassEntry,
    declaring_class: &php_ir::module::ClassEntry,
    property: &php_ir::module::ClassPropertyEntry,
    visibility_context: Option<&str>,
    layout_version: InvalidationEpoch,
    has_magic_get: bool,
    has_property_hooks: bool,
    dynamic_property_fallback: bool,
    typed_property_initialized: bool,
) -> PropertyFetchLayoutMetadata {
    PropertyFetchLayoutMetadata {
        class_id: receiver_class.id.raw(),
        layout_version: layout_version.raw(),
        property_slot_index: declaring_class
            .properties
            .iter()
            .position(|entry| entry.name == property.name)
            .map(|index| index as u32),
        visibility_context: visibility_context.map(str::to_owned),
        typed_property_initialized,
        has_property_hooks,
        has_magic_get,
        dynamic_property_fallback,
    }
}

#[allow(clippy::too_many_arguments)]
fn property_assign_layout_metadata(
    receiver_class: &php_ir::module::ClassEntry,
    declaring_class: &php_ir::module::ClassEntry,
    property: &php_ir::module::ClassPropertyEntry,
    visibility_context: Option<&str>,
    layout_version: InvalidationEpoch,
    has_magic_set: bool,
    has_property_hooks: bool,
    dynamic_property_fallback: bool,
    reference_slot: bool,
) -> PropertyAssignLayoutMetadata {
    PropertyAssignLayoutMetadata {
        class_id: receiver_class.id.raw(),
        layout_version: layout_version.raw(),
        property_slot_index: declaring_class
            .properties
            .iter()
            .position(|entry| entry.name == property.name)
            .map(|index| index as u32),
        visibility_context: visibility_context.map(str::to_owned),
        typed_property: property.type_.is_some(),
        readonly_or_init_only: property.flags.is_readonly || declaring_class.flags.is_readonly,
        reference_slot,
        has_property_hooks,
        has_magic_set,
        dynamic_property_fallback,
    }
}

#[allow(clippy::too_many_arguments)]
fn property_fetch_profile_observation(
    callsite: &str,
    property: &str,
    receiver_class: &str,
    class: &php_ir::module::ClassEntry,
    declared_property: Option<(
        &php_ir::module::ClassEntry,
        &php_ir::module::ClassPropertyEntry,
    )>,
    visibility_context: Option<&str>,
    layout_version: InvalidationEpoch,
    has_magic_get: bool,
    has_property_hook: bool,
    dynamic_property_fallback: bool,
    declared_visible_property: bool,
    uninitialized_typed_property: bool,
    non_eligible_reasons: Vec<&'static str>,
) -> PropertyFetchProfileObservation {
    let (declared_property_name, property_slot_index) =
        declared_property.map_or((None, None), |(declaring_class, property)| {
            (
                Some(property.name.clone()),
                declaring_class
                    .properties
                    .iter()
                    .position(|entry| entry.name == property.name),
            )
        });
    PropertyFetchProfileObservation {
        callsite: callsite.to_owned(),
        property: property.to_owned(),
        receiver_class: receiver_class.to_owned(),
        class_id: class.id.raw(),
        declared_property_name,
        visibility_context: visibility_context.map(str::to_owned),
        property_slot_index,
        class_layout_version: layout_version.raw(),
        has_magic_get,
        has_property_hook,
        dynamic_property_fallback,
        declared_visible_property,
        uninitialized_typed_property,
        non_eligible_reasons,
    }
}

#[allow(clippy::too_many_arguments)]
fn method_call_profile_observation(
    callsite: &str,
    method: &str,
    receiver_class: &str,
    class: &php_ir::module::ClassEntry,
    resolved_method: Option<(
        &CompiledUnit,
        &php_ir::module::ClassEntry,
        &php_ir::module::ClassMethodEntry,
    )>,
    visibility_context: Option<&str>,
    layout_version: InvalidationEpoch,
    has_magic_call: bool,
    magic_call_fallback: bool,
    simple_positional_arguments: bool,
    has_by_ref_argument: bool,
    callee_jit_eligible: bool,
    direct_vm_call_helper_available: bool,
    non_eligible_reasons: Vec<&'static str>,
) -> MethodCallProfileObservation {
    let (
        declaring_class,
        method_id,
        method_slot_index,
        method_is_final,
        method_is_private,
        method_is_static,
    ) = resolved_method.map_or(
        (None, None, None, false, false, false),
        |(_owner, declaring_class, method_entry)| {
            (
                Some(declaring_class.name.clone()),
                Some(method_entry.function.raw()),
                declaring_class.methods.iter().position(|entry| {
                    entry.name == method_entry.name && entry.function == method_entry.function
                }),
                method_entry.flags.is_final,
                method_entry.flags.is_private,
                method_entry.flags.is_static,
            )
        },
    );
    MethodCallProfileObservation {
        callsite: callsite.to_owned(),
        method: method.to_owned(),
        receiver_class: receiver_class.to_owned(),
        class_id: class.id.raw(),
        declaring_class,
        method_id,
        method_slot_index,
        visibility_context: visibility_context.map(str::to_owned),
        override_layout_version: layout_version.raw(),
        method_is_final,
        method_is_private,
        method_is_static,
        has_magic_call,
        magic_call_fallback,
        simple_positional_arguments,
        has_by_ref_argument,
        callee_jit_eligible,
        direct_vm_call_helper_available,
        non_eligible_reasons,
    }
}

fn method_call_args_are_simple_positional(args: &[IrCallArg]) -> bool {
    args.iter().all(|arg| arg.name.is_none() && !arg.unpack)
}

fn method_call_has_by_ref_argument(
    _args: &[IrCallArg],
    owner: Option<&CompiledUnit>,
    function: Option<FunctionId>,
) -> bool {
    let Some((owner, function)) = owner.zip(function) else {
        return false;
    };
    owner
        .unit()
        .functions
        .get(function.index())
        .is_some_and(|callee| callee.params.iter().any(|param| param.by_ref))
}

#[allow(clippy::too_many_arguments)]
fn method_call_guard_metadata(
    args: &[CallArgument],
    receiver_class: &php_ir::module::ClassEntry,
    declaring_class: &php_ir::module::ClassEntry,
    method_entry: &php_ir::module::ClassMethodEntry,
    visibility_context: Option<&str>,
    epoch: InvalidationEpoch,
    has_magic_call: bool,
    has_by_ref_argument: bool,
) -> MethodCallGuardMetadata {
    MethodCallGuardMetadata {
        receiver_class_id: receiver_class.id.raw(),
        class_layout_epoch: epoch.raw(),
        method_table_epoch: epoch.raw(),
        method_slot_index: declaring_class
            .methods
            .iter()
            .position(|entry| {
                entry.name == method_entry.name && entry.function == method_entry.function
            })
            .and_then(|index| index.try_into().ok()),
        visibility_context: visibility_context.map(str::to_owned),
        method_is_final: method_entry.flags.is_final,
        method_is_private: method_entry.flags.is_private,
        method_is_static: method_entry.flags.is_static,
        receiver_has_override: receiver_class.name == declaring_class.name
            && receiver_class.parent.is_some(),
        argument_shape: method_call_shape(args),
        by_ref_compatible: !has_by_ref_argument,
        has_magic_call,
    }
}

fn method_call_cache_target_owner<'a>(
    compiled: &'a CompiledUnit,
    state: &'a ExecutionState,
    target: &MethodCallCacheTarget,
) -> Option<&'a CompiledUnit> {
    match target {
        MethodCallCacheTarget::CurrentUnit { .. } => Some(compiled),
        MethodCallCacheTarget::DynamicUnit { unit_index, .. } => {
            state.dynamic_units.get(*unit_index)
        }
    }
}

fn method_direct_call_target_is_eligible(
    compiled: &CompiledUnit,
    state: &ExecutionState,
    target: &MethodCallCacheTarget,
    class: &php_ir::module::ClassEntry,
    receiver_class: &str,
    args: &[IrCallArg],
    values: &[CallArgument],
    has_magic_call: bool,
    epoch: InvalidationEpoch,
) -> bool {
    let resolved = target.resolved_target();
    let guard = &resolved.guard;
    if target.receiver_class_id() != class.id.raw() || target.receiver_class() != receiver_class {
        return false;
    }
    if guard.class_layout_epoch != epoch.raw() || guard.method_table_epoch != epoch.raw() {
        return false;
    }
    if guard.has_magic_call != has_magic_call {
        return false;
    }
    if guard.argument_shape != method_call_shape(values) {
        return false;
    }
    if !method_call_args_are_simple_positional(args) {
        return false;
    }
    let owner = method_call_cache_target_owner(compiled, state, target);
    let Some(owner) = owner else {
        return false;
    };
    if method_call_has_by_ref_argument(args, Some(owner), Some(target.function())) {
        return false;
    }
    let Some(declaring_class) = owner.lookup_class(&resolved.declaring_class) else {
        return false;
    };
    let Some(method_entry) = declaring_class
        .methods
        .iter()
        .find(|method| method.function == resolved.function)
    else {
        return false;
    };
    if guard.method_slot_index
        != declaring_class
            .methods
            .iter()
            .position(|entry| {
                entry.name == method_entry.name && entry.function == method_entry.function
            })
            .and_then(|index| index.try_into().ok())
    {
        return false;
    }
    guard.method_is_final == method_entry.flags.is_final
        && guard.method_is_private == method_entry.flags.is_private
        && guard.method_is_static == method_entry.flags.is_static
        && guard.by_ref_compatible
}

fn method_callee_shape_is_jit_eligible(owner: &CompiledUnit, function: FunctionId) -> bool {
    owner
        .unit()
        .functions
        .get(function.index())
        .is_some_and(|callee| {
            !callee.flags.is_top_level
                && !callee.flags.is_closure
                && !callee.flags.is_generator
                && !callee.returns_by_ref
                && matches!(
                    callee.return_type.as_ref(),
                    None | Some(
                        IrReturnType::Int
                            | IrReturnType::String
                            | IrReturnType::Bool
                            | IrReturnType::Null
                    )
                )
                && callee.captures.is_empty()
                && callee.params.iter().all(|param| {
                    !param.by_ref
                        && !param.variadic
                        && param.default.is_none()
                        && matches!(
                            param.type_.as_ref(),
                            None | Some(
                                IrReturnType::Int
                                    | IrReturnType::String
                                    | IrReturnType::Bool
                                    | IrReturnType::Null
                            )
                        )
                })
        })
}

fn method_tiny_inline_rejection_reason(
    owner: &CompiledUnit,
    class: &php_ir::module::ClassEntry,
    method_entry: &php_ir::module::ClassMethodEntry,
    args: &[IrCallArg],
    has_magic_call: bool,
) -> Option<&'static str> {
    if has_magic_call {
        return Some("magic_call_present");
    }
    if method_entry.flags.is_static {
        return Some("static_method");
    }
    if !(method_entry.flags.is_final || method_entry.flags.is_private || class.flags.is_final) {
        return Some("not_final_or_private");
    }
    if !method_call_args_are_simple_positional(args) {
        return Some("named_or_unpacked_arguments");
    }
    let Some(function) = owner.unit().functions.get(method_entry.function.index()) else {
        return Some("method_body_unavailable");
    };
    if function.flags.is_generator {
        return Some("generator_method");
    }
    if function.returns_by_ref
        || function
            .params
            .iter()
            .any(|param| param.by_ref || param.variadic)
    {
        return Some("refs_or_variadics");
    }
    if method_body_has_inline_blocker(function) {
        return Some("control_flow_or_escape");
    }
    if method_body_returns_scalar_constant(owner, function)
        || method_body_returns_this_property(function)
    {
        None
    } else {
        Some("not_tiny_leaf_return")
    }
}

fn method_body_has_inline_blocker(function: &IrFunction) -> bool {
    function.blocks.iter().any(|block| {
        block.instructions.iter().any(|instruction| {
            matches!(
                instruction.kind,
                InstructionKind::CallFunction { .. }
                    | InstructionKind::CallMethod { .. }
                    | InstructionKind::CallStaticMethod { .. }
                    | InstructionKind::CallClosure { .. }
                    | InstructionKind::CallCallable { .. }
                    | InstructionKind::Pipe { .. }
                    | InstructionKind::EnterTry { .. }
                    | InstructionKind::LeaveTry
                    | InstructionKind::EndFinally { .. }
                    | InstructionKind::Throw { .. }
                    | InstructionKind::Yield { .. }
                    | InstructionKind::YieldFrom { .. }
                    | InstructionKind::Include { .. }
                    | InstructionKind::Eval { .. }
                    | InstructionKind::AssignProperty { .. }
                    | InstructionKind::AssignPropertyDim { .. }
                    | InstructionKind::AssignStaticProperty { .. }
                    | InstructionKind::BindReferenceProperty { .. }
                    | InstructionKind::BindReferenceStaticProperty { .. }
                    | InstructionKind::UnsetProperty { .. }
                    | InstructionKind::UnsetPropertyDim { .. }
            )
        })
    })
}

fn method_body_returns_scalar_constant(owner: &CompiledUnit, function: &IrFunction) -> bool {
    let Some(block) = single_return_block(function) else {
        return false;
    };
    let Some(value) = block
        .terminator
        .as_ref()
        .and_then(|terminator| match terminator.kind {
            TerminatorKind::Return { value, .. } => value,
            _ => None,
        })
    else {
        return false;
    };
    match value {
        Operand::Constant(constant) => owner
            .unit()
            .constants
            .get(constant.index())
            .is_some_and(is_tiny_inline_scalar_constant),
        Operand::Register(register) => block.instructions.iter().any(|instruction| {
            matches!(
                instruction.kind,
                InstructionKind::LoadConst { dst, constant }
                    if dst == register
                        && owner
                            .unit()
                            .constants
                            .get(constant.index())
                            .is_some_and(is_tiny_inline_scalar_constant)
            )
        }),
        Operand::Local(_) => false,
    }
}

fn method_body_returns_this_property(function: &IrFunction) -> bool {
    let Some(block) = single_return_block(function) else {
        return false;
    };
    let Some(Operand::Register(return_register)) =
        block
            .terminator
            .as_ref()
            .and_then(|terminator| match terminator.kind {
                TerminatorKind::Return { value, .. } => value,
                _ => None,
            })
    else {
        return false;
    };
    block.instructions.iter().any(|instruction| {
        matches!(
            &instruction.kind,
            InstructionKind::FetchProperty {
                dst,
                object: Operand::Local(local),
                ..
            } if *dst == return_register
                && function
                    .locals
                    .get(local.index())
                    .is_some_and(|name| name == "this")
        )
    })
}

fn single_return_block(function: &IrFunction) -> Option<&php_ir::block::BasicBlock> {
    (function.blocks.len() == 1)
        .then(|| function.blocks.first())
        .flatten()
        .filter(|block| {
            matches!(
                block.terminator.as_ref().map(|terminator| &terminator.kind),
                Some(TerminatorKind::Return { .. })
            )
        })
}

fn is_tiny_inline_scalar_constant(constant: &IrConstant) -> bool {
    matches!(
        constant,
        IrConstant::Null
            | IrConstant::Bool(_)
            | IrConstant::Int(_)
            | IrConstant::Float(_)
            | IrConstant::String(_)
            | IrConstant::StringBytes(_)
    )
}

fn property_hook_is_active(
    state: &ExecutionState,
    object: &ObjectRef,
    class: &php_ir::module::ClassEntry,
    property: &php_ir::module::ClassPropertyEntry,
) -> bool {
    let class_name = normalize_class_name(&class.name);
    state.property_hook_stack.iter().any(|active| {
        active.object_id == object.id()
            && active.class_name == class_name
            && active.property == property.name
    })
}

fn normalize_method_name(method: &str) -> String {
    method.to_ascii_lowercase()
}

fn is_fiber_runtime_class(class_name: &str) -> bool {
    normalize_class_name(class_name) == "fiber"
}

fn is_closure_runtime_class(class_name: &str) -> bool {
    normalize_class_name(class_name) == "closure"
}

/// Returns true when a statically named `new` expression can lower to the
/// dense `NewObject` opcode. Builtin runtime classes keep their dedicated
/// rich-interpreter construction paths; everything else resolves through
/// the shared userland instantiation helpers at execution time (including
/// autoload, abstract/interface/enum guards, and constructor dispatch).
pub(crate) fn dense_new_object_lowering_supported(class_name: &str) -> bool {
    !(is_special_static_class_name(class_name)
        || is_closure_runtime_class(class_name)
        || is_fiber_runtime_class(class_name)
        || is_reflection_runtime_class(class_name)
        || is_phar_runtime_class(class_name)
        || is_zip_runtime_class(class_name)
        || is_xml_runtime_class(class_name)
        || is_pdo_runtime_class(class_name)
        || is_sqlite_runtime_class(class_name)
        || is_spl_iterator_runtime_class(class_name)
        || is_spl_container_runtime_class(class_name)
        || is_spl_heap_runtime_class(class_name)
        || is_spl_file_runtime_class(class_name)
        || is_std_class_runtime_class(class_name)
        || is_php_token_runtime_class(class_name)
        || is_fileinfo_runtime_class(class_name)
        || is_imagick_runtime_class(class_name)
        || is_xsl_runtime_class(class_name)
        || is_soap_runtime_class(class_name)
        || is_date_time_runtime_class(class_name))
}

fn is_std_class_object(object: &ObjectRef) -> bool {
    normalize_class_name(&object.class_name()) == "stdclass"
}

fn closure_static_method_value(
    compiled: &CompiledUnit,
    state: &mut ExecutionState,
    stack: &CallStack,
    method: &str,
    args: Vec<CallArgument>,
    output: &mut OutputBuffer,
    source_span: RuntimeSourceSpan,
) -> Result<Value, String> {
    match normalize_method_name(method).as_str() {
        "getcurrent" => {
            let values = call_args_to_positional("Closure::getCurrent", args)?;
            if !values.is_empty() {
                return Err(format!(
                    "E_PHP_VM_TOO_MANY_ARGS: Closure::getCurrent expects 0 argument(s), {} given",
                    values.len()
                ));
            }
            current_closure_value(compiled, state, stack)
        }
        "fromcallable" => {
            let mut values = call_args_to_positional("Closure::fromCallable", args)?;
            if values.len() != 1 {
                let id = if values.is_empty() {
                    "E_PHP_VM_TOO_FEW_ARGS"
                } else {
                    "E_PHP_VM_TOO_MANY_ARGS"
                };
                return Err(format!(
                    "{id}: Closure::fromCallable expects exactly 1 argument, {} given",
                    values.len()
                ));
            }
            let callable = resolve_closure_from_callable_relative_value(
                compiled,
                state,
                stack,
                values.remove(0),
                output,
                source_span,
            )?;
            let callable = acquire_callable_value(compiled, state, stack, callable)
                .map_err(closure_from_callable_error)?;
            Ok(closure_from_acquired_callable(callable))
        }
        "bind" => {
            let mut values = call_args_to_positional("Closure::bind", args)?;
            if values.len() < 2 {
                return Err(format!(
                    "E_PHP_VM_TOO_FEW_ARGS: Closure::bind expects at least 2 arguments, {} given",
                    values.len()
                ));
            }
            if values.len() > 3 {
                return Err(format!(
                    "E_PHP_VM_TOO_MANY_ARGS: Closure::bind expects at most 3 arguments, {} given",
                    values.len()
                ));
            }
            if let Some(scope) = values.get(2) {
                match callable_resolve_reference(scope.clone()) {
                    Value::Null | Value::String(_) | Value::Object(_) => {}
                    other => {
                        return Err(format!(
                            "E_PHP_VM_PARAM_TYPE_MISMATCH: Closure::bind(): Argument #3 ($newScope) must be of type object|string|null, {} given",
                            value_type_name(&other)
                        ));
                    }
                }
            }
            let closure = callable_resolve_reference(values.remove(0));
            let Value::Callable(callable) = closure else {
                return Err(format!(
                    "E_PHP_VM_PARAM_TYPE_MISMATCH: Closure::bind(): Argument #1 ($closure) must be of type Closure, {} given",
                    value_type_name(&closure)
                ));
            };
            let new_this = callable_resolve_reference(values.remove(0));
            let bound_this = match new_this {
                Value::Null => None,
                Value::Object(object) => Some(object),
                other => {
                    return Err(format!(
                        "E_PHP_VM_PARAM_TYPE_MISMATCH: Closure::bind(): Argument #2 ($newThis) must be of type ?object, {} given",
                        value_type_name(&other)
                    ));
                }
            };
            Ok(bind_closure_callable_value(*callable, bound_this))
        }
        _ => Err(format!(
            "E_PHP_VM_UNKNOWN_METHOD: method Closure::{method} is not defined"
        )),
    }
}

fn bind_closure_callable_value(callable: CallableValue, bound_this: Option<ObjectRef>) -> Value {
    match callable {
        CallableValue::Closure(payload) => {
            // Scope/declaring carry the canonical lookup name; the
            // late-static-binding called class keeps the PHP-visible display
            // spelling, matching what method activation stores in frames.
            let rebound_class = bound_this.as_ref().map(ObjectRef::class_name_handle);
            let rebound_display = bound_this.as_ref().map(object_called_class_handle);
            let context = ClosureContext {
                owner_unit: payload.context.owner_unit,
                scope_class: rebound_class.clone().or(payload.context.scope_class),
                called_class: rebound_display.or(payload.context.called_class),
                declaring_class: rebound_class.or(payload.context.declaring_class),
            };
            Value::closure(
                ClosurePayload::new(payload.function, payload.captures)
                    .with_debug(payload.debug.map(|debug| *debug))
                    .with_bound_this(bound_this.clone())
                    .with_context(context),
            )
        }
        CallableValue::BoundMethod {
            target,
            method,
            scope,
        } => {
            let rebound_target = match bound_this {
                Some(object) => CallableMethodTarget::Object(object),
                None => target,
            };
            Value::bound_method_callable(rebound_target, method, scope)
        }
        other => Value::Callable(Box::new(other)),
    }
}

fn callable_closure_should_warn_unbind_this(callable: &CallableValue) -> bool {
    let CallableValue::Closure(payload) = callable else {
        return false;
    };
    payload.bound_this.is_some()
        && payload
            .captures
            .iter()
            .any(|capture| capture.name == "this")
}

fn closure_from_acquired_callable(callable: Value) -> Value {
    match callable {
        Value::String(name) => {
            let name = name.to_string_lossy();
            if let Some((class_name, method)) = name.split_once("::") {
                Value::bound_method_callable(
                    CallableMethodTarget::Class(class_name.to_owned()),
                    method.to_owned(),
                    None,
                )
            } else if is_callable_builtin_name(&normalize_function_name(&name)) {
                Value::internal_builtin_callable(normalize_function_name(&name))
            } else {
                Value::user_function_callable(normalize_function_name(&name))
            }
        }
        other => other,
    }
}

fn closure_from_callable_error(message: String) -> String {
    let (id, reason) = message
        .split_once(": ")
        .filter(|(id, _)| id.starts_with("E_"))
        .map_or(
            (
                "E_PHP_VM_FIRST_CLASS_CALLABLE_NOT_CALLABLE",
                message.as_str(),
            ),
            |(id, reason)| (id, reason),
        );
    let mut reason = reason.to_owned();
    if let Some(first) = reason.get_mut(0..1) {
        first.make_ascii_lowercase();
    }
    format!("{id}: Failed to create closure from callable: {reason}")
}

fn resolve_closure_from_callable_relative_value(
    compiled: &CompiledUnit,
    state: &mut ExecutionState,
    stack: &CallStack,
    value: Value,
    output: &mut OutputBuffer,
    source_span: RuntimeSourceSpan,
) -> Result<Value, String> {
    match value {
        Value::String(name) => {
            let name_text = name.to_string_lossy();
            let Some(resolved) = resolve_relative_callable_value(
                compiled,
                state,
                stack,
                &name_text,
                output,
                source_span,
            )?
            else {
                return Ok(Value::String(name));
            };
            Ok(resolved)
        }
        Value::Array(array) => {
            let mut resolved = PhpArray::new();
            for (key, value) in array.iter() {
                let value = if key == ArrayKey::Int(0) {
                    match effective_value(value) {
                        Value::String(class_name) => resolve_relative_callable_class_name(
                            compiled,
                            state,
                            stack,
                            &class_name.to_string_lossy(),
                            output,
                            source_span.clone(),
                        )?
                        .map(Value::string)
                        .unwrap_or_else(|| value.clone()),
                        _ => value.clone(),
                    }
                } else {
                    value.clone()
                };
                resolved.insert(key.clone(), value);
            }
            Ok(Value::Array(resolved))
        }
        other => Ok(other),
    }
}

fn resolve_relative_callable_value(
    compiled: &CompiledUnit,
    state: &mut ExecutionState,
    stack: &CallStack,
    name: &str,
    output: &mut OutputBuffer,
    source_span: RuntimeSourceSpan,
) -> Result<Option<Value>, String> {
    let Some((class_name, method)) = name.split_once("::") else {
        return Ok(None);
    };
    let Some(resolved_class) = resolve_relative_callable_class_name(
        compiled,
        state,
        stack,
        class_name,
        output,
        source_span,
    )?
    else {
        return Ok(None);
    };
    if let Some(object) = current_this_object(compiled, stack)
        && lookup_resolved_method_in_state(compiled, state, &resolved_class, method, None)?
            .is_some_and(|resolved| !resolved.method.flags.is_static)
    {
        validate_object_method_callable_acquisition(
            compiled,
            state,
            stack,
            &object.class_name(),
            method,
            true,
        )?;
        return Ok(Some(Value::bound_method_callable(
            CallableMethodTarget::Object(object),
            method.to_owned(),
            current_scope_class(compiled, stack),
        )));
    }
    Ok(Some(Value::string(format!("{resolved_class}::{method}"))))
}

fn resolve_relative_callable_class_name(
    compiled: &CompiledUnit,
    state: &mut ExecutionState,
    stack: &CallStack,
    class_name: &str,
    output: &mut OutputBuffer,
    source_span: RuntimeSourceSpan,
) -> Result<Option<String>, String> {
    match normalize_class_name(class_name).as_str() {
        "self" => {
            emit_relative_callable_deprecation(compiled, output, stack, state, "self", source_span);
            current_scope_class(compiled, stack)
                .ok_or_else(|| {
                    "E_PHP_VM_INVALID_STATIC_SCOPE: self:: is not available outside class scope"
                        .to_owned()
                })
                .map(Some)
        }
        "static" => {
            emit_relative_callable_deprecation(
                compiled,
                output,
                stack,
                state,
                "static",
                source_span,
            );
            current_called_class(compiled, stack)
                .ok_or_else(|| {
                    "E_PHP_VM_INVALID_STATIC_SCOPE: static:: is not available outside class scope"
                        .to_owned()
                })
                .map(Some)
        }
        "parent" => {
            emit_relative_callable_deprecation(
                compiled,
                output,
                stack,
                state,
                "parent",
                source_span,
            );
            let scope = current_scope_class(compiled, stack).ok_or_else(|| {
                "E_PHP_VM_INVALID_STATIC_SCOPE: parent:: is not available outside class scope"
                    .to_owned()
            })?;
            let class = lookup_class_in_state(compiled, state, &scope)
                .ok_or_else(|| format!("E_PHP_VM_UNKNOWN_CLASS: class {scope} is not defined"))?;
            class
                .parent
                .clone()
                .ok_or_else(|| {
                    format!(
                        "E_PHP_VM_NO_PARENT_CLASS: class {} has no parent",
                        class.name
                    )
                })
                .map(Some)
        }
        _ => Ok(None),
    }
}

fn emit_relative_callable_deprecation(
    compiled: &CompiledUnit,
    output: &mut OutputBuffer,
    stack: &CallStack,
    state: &mut ExecutionState,
    keyword: &str,
    source_span: RuntimeSourceSpan,
) {
    if !error_reporting_allows(state, php_runtime::PHP_E_DEPRECATED) {
        return;
    }
    let diagnostic = RuntimeDiagnostic::new(
        "E_PHP_VM_RELATIVE_CALLABLE_DEPRECATED",
        RuntimeSeverity::Deprecation,
        format!("Use of \"{keyword}\" in callables is deprecated"),
        source_span,
        stack_trace(compiled, stack),
        None,
    );
    emit_vm_diagnostic(
        output,
        state,
        &diagnostic,
        php_runtime::PhpDiagnosticChannel::Deprecated,
        php_runtime::PHP_E_DEPRECATED,
    );
    state.diagnostics.push(diagnostic);
}

fn emit_zip_open_empty_file_deprecation(
    compiled: &CompiledUnit,
    output: &mut OutputBuffer,
    stack: &CallStack,
    state: &mut ExecutionState,
    source_span: RuntimeSourceSpan,
) {
    if !error_reporting_allows(state, php_runtime::PHP_E_DEPRECATED) {
        return;
    }
    let diagnostic = RuntimeDiagnostic::new(
        "E_PHP_VM_ZIP_EMPTY_FILE_DEPRECATED",
        RuntimeSeverity::Deprecation,
        "ZipArchive::open(): Using empty file as ZipArchive is deprecated",
        source_span,
        stack_trace(compiled, stack),
        None,
    );
    emit_vm_diagnostic(
        output,
        state,
        &diagnostic,
        php_runtime::PhpDiagnosticChannel::Deprecated,
        php_runtime::PHP_E_DEPRECATED,
    );
    state.diagnostics.push(diagnostic);
}

fn current_closure_value(
    compiled: &CompiledUnit,
    state: &ExecutionState,
    stack: &CallStack,
) -> Result<Value, String> {
    let frame = stack
        .current()
        .ok_or_else(|| "E_PHP_VM_CURRENT_CLOSURE: Current function is not a closure".to_owned())?;
    let function = compiled
        .unit()
        .functions
        .get(frame.function.index())
        .ok_or_else(|| "E_PHP_VM_CURRENT_CLOSURE: Current function is not a closure".to_owned())?;
    if !function.flags.is_closure {
        return Err("E_PHP_VM_CURRENT_CLOSURE: Current function is not a closure".to_owned());
    }

    let mut captures = Vec::with_capacity(function.captures.len());
    for metadata in &function.captures {
        let slot = frame
            .locals
            .iter()
            .find(|(index, _)| *index == metadata.local.index())
            .map(|(_, slot)| slot)
            .ok_or_else(|| format!("invalid local local:{}", metadata.local.raw()))?;
        if metadata.by_ref {
            let Slot::Reference(cell) = slot else {
                return Err(format!(
                    "E_PHP_VM_BY_REF_CAPTURE_MISSING_CELL: closure capture ${} has no reference cell",
                    metadata.name
                ));
            };
            captures.push(ClosureCaptureValue::by_reference(
                metadata.name.clone(),
                cell.clone(),
            ));
        } else {
            captures.push(ClosureCaptureValue::by_value(
                metadata.name.clone(),
                slot.read(),
            ));
        }
    }

    let bound_this = (!function.flags.is_static)
        .then(|| current_this_object(compiled, stack))
        .flatten();
    Ok(Value::closure(
        ClosurePayload::new(frame.function.raw(), captures)
            .with_debug(closure_debug_info(compiled, frame.function))
            .with_bound_this(bound_this)
            .with_context(ClosureContext {
                owner_unit: dynamic_unit_index_for_compiled(state, compiled),
                scope_class: current_scope_class(compiled, stack).map(Arc::from),
                // Display spelling: `static::class` inside the closure must
                // reproduce the PHP-visible name, like method frames do.
                called_class: current_called_class_display(compiled, stack).map(Arc::from),
                declaring_class: current_scope_class(compiled, stack).map(Arc::from),
            }),
    ))
}

fn new_fiber_object(args: Vec<CallArgument>) -> Result<FiberRef, String> {
    if let Some(name) = args.iter().find_map(|arg| arg.name.as_deref()) {
        return Err(format!(
            "E_PHP_VM_UNKNOWN_NAMED_ARG: Fiber::__construct has no builtin parameter ${name}"
        ));
    }
    if args.len() != 1 {
        let id = if args.is_empty() {
            "E_PHP_VM_TOO_FEW_ARGS"
        } else {
            "E_PHP_VM_TOO_MANY_ARGS"
        };
        return Err(format!(
            "{id}: Fiber::__construct expects exactly 1 argument(s), {} given",
            args.len()
        ));
    }
    let callable = args
        .into_iter()
        .next()
        .expect("checked exactly one argument")
        .value;
    if !fiber_constructor_accepts_callable(&callable) {
        return Err(format!(
            "E_PHP_VM_FIBER_CONSTRUCTOR_NOT_CALLABLE: Fiber::__construct expects callable, {} given",
            value_type_name(&callable)
        ));
    }
    Ok(FiberRef::new(callable))
}

fn fiber_constructor_accepts_callable(value: &Value) -> bool {
    matches!(
        value,
        Value::Callable(_) | Value::String(_) | Value::Array(_) | Value::Object(_)
    )
}

fn validate_fiber_arg_count(
    method: &str,
    args: &[CallArgument],
    expected: usize,
) -> Result<(), String> {
    validate_fiber_arg_count_range(method, args, expected, expected)
}

fn validate_fiber_arg_count_range(
    method: &str,
    args: &[CallArgument],
    min: usize,
    max: usize,
) -> Result<(), String> {
    if let Some(name) = args.iter().find_map(|arg| arg.name.as_deref()) {
        return Err(format!(
            "E_PHP_VM_UNKNOWN_NAMED_ARG: Fiber::{method} has no builtin parameter ${name}"
        ));
    }
    if args.len() < min || args.len() > max {
        let id = if args.len() < min {
            "E_PHP_VM_TOO_FEW_ARGS"
        } else {
            "E_PHP_VM_TOO_MANY_ARGS"
        };
        let expected = if min == max {
            format!("exactly {min}")
        } else if min == 0 {
            format!("at most {max}")
        } else {
            format!("between {min} and {max}")
        };
        return Err(format!(
            "{id}: Fiber::{method} expects {expected} argument(s), {} given",
            args.len()
        ));
    }
    Ok(())
}

fn validate_generator_arg_count(
    method: &str,
    args: &[CallArgument],
    expected: usize,
) -> Result<(), String> {
    if let Some(name) = args.iter().find_map(|arg| arg.name.as_deref()) {
        return Err(format!(
            "E_PHP_VM_UNKNOWN_NAMED_ARG: Generator::{method} has no builtin parameter ${name}"
        ));
    }
    if args.len() != expected {
        let id = if args.len() < expected {
            "E_PHP_VM_TOO_FEW_ARGS"
        } else {
            "E_PHP_VM_TOO_MANY_ARGS"
        };
        return Err(format!(
            "{id}: Generator::{method} expects exactly {expected} argument(s), {} given",
            args.len()
        ));
    }
    Ok(())
}

#[cold]
fn include_failure(
    output: &mut OutputBuffer,
    compiled: &CompiledUnit,
    span: IrSpan,
    kind: IncludeKind,
    message: impl Into<String>,
    state: &ExecutionState,
    stack_trace: Vec<RuntimeStackFrame>,
) -> VmResult {
    let message = message.into();
    let severity = if matches!(kind, IncludeKind::Include | IncludeKind::IncludeOnce) {
        RuntimeSeverity::Warning
    } else {
        RuntimeSeverity::FatalError
    };
    let source_span = runtime_source_span(compiled, span);
    let diagnostic = RuntimeDiagnostic::new(
        include_failure_id(&message).to_owned(),
        severity,
        message.clone(),
        source_span,
        stack_trace,
        None,
    );
    emit_include_failure_output(output, compiled, span, kind, state, &diagnostic);
    VmResult::runtime_error_with_diagnostic(output.clone(), message.clone(), diagnostic)
}

fn load_phar_include(
    uri: &str,
    cwd: &Path,
    filesystem: &php_runtime::FilesystemCapabilities,
) -> Result<LoadedInclude, VmError> {
    let parsed = php_runtime::phar::parse_uri(uri, cwd, filesystem).map_err(|error| {
        include_vm_error(error.diagnostic_id(), error.message()).with_context("path", uri)
    })?;
    let bytes = php_runtime::phar::read_entry(&parsed.archive_path, &parsed.entry_path).map_err(
        |error| include_vm_error(error.diagnostic_id(), error.message()).with_context("path", uri),
    )?;
    let source = String::from_utf8(bytes).map_err(|_| {
        include_vm_error(
            "E_PHP_VM_INCLUDE_READ",
            format!("{uri}: PHAR entry is not valid UTF-8 PHP source"),
        )
        .with_context("path", uri)
    })?;
    Ok(LoadedInclude {
        canonical_path: parsed.synthetic_path,
        source,
    })
}

fn include_vm_error(code: &'static str, message: impl Into<String>) -> VmError {
    VmError::fatal(code, "include", message)
}

fn include_failure_id(message: &str) -> &str {
    message
        .split_once(':')
        .and_then(|(id, _)| id.starts_with("E_").then_some(id))
        .unwrap_or("E_PHP_VM_INCLUDE_ERROR")
}

fn include_failure_allows_continuation(kind: IncludeKind, result: &VmResult) -> bool {
    matches!(kind, IncludeKind::Include | IncludeKind::IncludeOnce)
        && result
            .diagnostics
            .iter()
            .any(|diagnostic| diagnostic.severity() == RuntimeSeverity::Warning)
        && result
            .diagnostics
            .iter()
            .all(|diagnostic| diagnostic.severity() == RuntimeSeverity::Warning)
}

#[cold]
fn emit_include_failure_output(
    output: &mut OutputBuffer,
    compiled: &CompiledUnit,
    span: IrSpan,
    kind: IncludeKind,
    state: &ExecutionState,
    diagnostic: &RuntimeDiagnostic,
) {
    let Some((target, reason)) = include_failure_target_and_reason(diagnostic.message()) else {
        let channel =
            php_runtime::PhpDiagnosticChannel::from_runtime_severity(diagnostic.severity());
        let level = match diagnostic.severity() {
            RuntimeSeverity::FatalError => php_runtime::PHP_E_ERROR,
            _ => php_runtime::PHP_E_WARNING,
        };
        emit_vm_diagnostic(output, state, diagnostic, channel, level);
        return;
    };
    let (file, line) = source_span_file_line(compiled, span)
        .unwrap_or_else(|| ("<unknown>".to_owned(), i64::from(span.start)));
    if display_errors_enabled(state) && error_reporting_allows(state, php_runtime::PHP_E_WARNING) {
        let function_name = include_kind_function_name(kind);
        output.write_bytes(
            format!(
                "\nWarning: {function_name}({target}): Failed to open stream: {reason} in {file} on line {line}\n",
            )
            .as_bytes(),
        );
        if matches!(kind, IncludeKind::Include | IncludeKind::IncludeOnce) {
            let include_path = include_path_warning_display(state);
            output.write_bytes(
                format!(
                    "\nWarning: {function_name}(): Failed opening '{target}' for inclusion (include_path='{include_path}') in {file} on line {line}\n"
                )
                .as_bytes(),
            );
        }
    }
    if matches!(kind, IncludeKind::Require | IncludeKind::RequireOnce)
        && display_errors_enabled(state)
        && error_reporting_allows(state, php_runtime::PHP_E_ERROR)
    {
        let include_path = include_path_warning_display(state);
        output.write_bytes(
            format!(
                "\nFatal error: Uncaught Error: Failed opening required '{target}' (include_path='{include_path}') in {file}:{line}\nStack trace:\n#0 {{main}}\n  thrown in {file} on line {line}\n"
            )
            .as_bytes(),
        );
    }
}

#[cold]
fn include_failure_target_and_reason(message: &str) -> Option<(&str, String)> {
    let id = include_failure_id(message);
    if !matches!(id, "E_PHP_VM_INCLUDE_MISSING" | "E_PHP_VM_INCLUDE_READ") {
        return None;
    }
    let payload = message.split_once(": ")?.1;
    let (target, reason) = payload.rsplit_once(": ")?;
    let reason = if reason.contains("No such file or directory") || reason == "not found" {
        "No such file or directory".to_owned()
    } else if reason.contains("Is a directory") {
        "Is a directory".to_owned()
    } else {
        reason
            .split_once(" (os error")
            .map(|(reason, _)| reason)
            .unwrap_or(reason)
            .to_owned()
    };
    Some((target, reason))
}

fn include_path_warning_display(state: &ExecutionState) -> &str {
    match state.ini.get("include_path") {
        Some(".") | None => ".:",
        Some(value) => value,
    }
}

fn include_kind_function_name(kind: IncludeKind) -> &'static str {
    match kind {
        IncludeKind::Include => "include",
        IncludeKind::IncludeOnce => "include_once",
        IncludeKind::Require => "require",
        IncludeKind::RequireOnce => "require_once",
    }
}

fn include_cache_resolution_outcome(
    before: IncludeCacheStats,
    after: IncludeCacheStats,
) -> &'static str {
    if after.resolution_hits > before.resolution_hits {
        "hit"
    } else if after.resolution_misses > before.resolution_misses {
        "miss"
    } else {
        "unchanged"
    }
}

fn include_cache_compile_outcome(
    before: IncludeCacheStats,
    after: IncludeCacheStats,
) -> &'static str {
    if after.compile_hits > before.compile_hits {
        "hit"
    } else if after.compile_misses > before.compile_misses {
        "miss"
    } else if after.compile_errors > before.compile_errors {
        "error"
    } else {
        "unchanged"
    }
}

fn entry_instruction_count(unit: &IrUnit) -> usize {
    unit.functions
        .get(unit.entry.index())
        .map(|function| {
            function
                .blocks
                .iter()
                .map(|block| block.instructions.len() + usize::from(block.terminator.is_some()))
                .sum()
        })
        .unwrap_or(0)
}

fn format_include_stack(stack: &[PathBuf]) -> String {
    stack
        .iter()
        .map(|path| path.display().to_string())
        .collect::<Vec<_>>()
        .join(" -> ")
}

