fn error_handler_callback_from_value(
    compiled: &CompiledUnit,
    value: Value,
) -> Result<CallableValue, String> {
    match value {
        Value::Callable(callable) => match *callable {
            CallableValue::UserFunction { name } => {
                let normalized = normalize_function_name(&name);
                if compiled.lookup_function(&normalized).is_some() {
                    Ok(CallableValue::UserFunction { name: normalized })
                } else if BuiltinRegistry::new().contains(&normalized) {
                    Ok(CallableValue::InternalBuiltin { name: normalized })
                } else {
                    Err(format!(
                        "E_PHP_VM_ERROR_INVALID_CALLBACK: function {name} is not callable"
                    ))
                }
            }
            CallableValue::Closure(payload) => Ok(CallableValue::Closure(payload)),
            CallableValue::InternalBuiltin { name } => {
                if BuiltinRegistry::new().contains(&name) {
                    Ok(CallableValue::InternalBuiltin { name })
                } else {
                    Err(format!(
                        "E_PHP_VM_ERROR_INVALID_CALLBACK: builtin {name} is not callable"
                    ))
                }
            }
            other_callable => Err(format!(
                "E_PHP_VM_ERROR_INVALID_CALLBACK: value of type {} is not callable",
                value_type_name(&Value::Callable(Box::new(other_callable)))
            )),
        },
        Value::String(name) => {
            let name = normalize_function_name(&name.to_string_lossy());
            if compiled.lookup_function(&name).is_some() {
                Ok(CallableValue::UserFunction { name })
            } else if BuiltinRegistry::new().contains(&name) {
                Ok(CallableValue::InternalBuiltin { name })
            } else {
                Err(format!(
                    "E_PHP_VM_ERROR_INVALID_CALLBACK: function {name} is not callable"
                ))
            }
        }
        other => Err(format!(
            "E_PHP_VM_ERROR_INVALID_CALLBACK: value of type {} is not callable",
            value_type_name(&other)
        )),
    }
}

fn autoload_callback_from_value(
    compiled: &CompiledUnit,
    state: &ExecutionState,
    value: Value,
) -> Result<CallableValue, String> {
    match value {
        Value::Callable(callable) => match *callable {
            CallableValue::UserFunction { name } => {
                let normalized = normalize_function_name(&name);
                if compiled.lookup_function(&normalized).is_some()
                    || dynamic_function_in_state(state, &normalized).is_some()
                    || BuiltinRegistry::new().contains(&normalized)
                {
                    Ok(CallableValue::UserFunction { name: normalized })
                } else {
                    Err(format!(
                        "function \"{name}\" not found or invalid function name"
                    ))
                }
            }
            CallableValue::Closure(payload) => Ok(CallableValue::Closure(payload)),
            CallableValue::InternalBuiltin { name } => {
                if BuiltinRegistry::new().contains(&name) {
                    Ok(CallableValue::InternalBuiltin { name })
                } else {
                    Err(format!("builtin {name} is not callable"))
                }
            }
            other_callable => Err(format!(
                "value of type {} is not callable",
                value_type_name(&Value::Callable(Box::new(other_callable)))
            )),
        },
        Value::String(name) => {
            let name = name.to_string_lossy();
            if let Some((class_name, method)) = name.split_once("::") {
                autoload_class_method_callback(compiled, state, class_name, method, true)
            } else {
                let normalized = normalize_function_name(&name);
                if compiled.lookup_function(&normalized).is_some()
                    || dynamic_function_in_state(state, &normalized).is_some()
                {
                    Ok(CallableValue::UserFunction { name: normalized })
                } else if BuiltinRegistry::new().contains(&normalized)
                    || is_autoload_builtin_name(&normalized)
                {
                    Ok(CallableValue::InternalBuiltin { name: normalized })
                } else {
                    Err(format!(
                        "function \"{name}\" not found or invalid function name"
                    ))
                }
            }
        }
        Value::Array(array) => {
            let elements = array
                .iter()
                .map(|(_, value)| value.clone())
                .collect::<Vec<_>>();
            let [target, method]: [Value; 2] = match elements.try_into() {
                Ok(elements) => elements,
                Err(_) => {
                    return Err("callable arrays must contain exactly target and method".to_owned());
                }
            };
            let Some(method) = callable_string_value(method) else {
                return Err("callable array method must be string".to_owned());
            };
            match callable_resolve_reference(target) {
                Value::Object(object) => {
                    let class_name = object.class_name();
                    let resolved = autoload_resolve_method(compiled, state, &class_name, &method)?;
                    if resolved.method.flags.is_static {
                        Ok(CallableValue::BoundMethod {
                            target: CallableMethodTarget::Class(object.display_name()),
                            method,
                            scope: Some(normalize_class_name(&class_name)),
                        })
                    } else {
                        Ok(CallableValue::BoundMethod {
                            target: CallableMethodTarget::Object(object),
                            method,
                            scope: None,
                        })
                    }
                }
                Value::String(class_name) => {
                    let class_name = class_name.to_string_lossy();
                    autoload_class_method_callback(compiled, state, &class_name, &method, true)
                }
                other => Err(format!(
                    "callable array target must be object or class string, got {}",
                    value_type_name(&other)
                )),
            }
        }
        Value::Object(object) => {
            if lookup_method_in_state(compiled, state, &object.class_name(), "__invoke")
                .map(|method| method.is_some())?
            {
                Ok(CallableValue::BoundMethod {
                    target: CallableMethodTarget::Object(object),
                    method: "__invoke".to_owned(),
                    scope: None,
                })
            } else {
                Err(format!(
                    "object of class {} is not callable",
                    object.class_name()
                ))
            }
        }
        other => Err(format!(
            "value of type {} is not callable",
            value_type_name(&other)
        )),
    }
}

fn autoload_invalid_callback_error(function_name: &str, reason: &str) -> String {
    format!(
        "E_PHP_VM_AUTOLOAD_INVALID_CALLBACK: {function_name}(): Argument #1 ($callback) must be a valid callback or null, {reason}"
    )
}

fn autoload_class_method_callback(
    compiled: &CompiledUnit,
    state: &ExecutionState,
    class_name: &str,
    method: &str,
    require_static: bool,
) -> Result<CallableValue, String> {
    let resolved = autoload_resolve_method(compiled, state, class_name, method)?;
    if require_static && !resolved.method.flags.is_static {
        return Err(format!(
            "non-static method {}::{}() cannot be called statically",
            resolved.class.display_name, method
        ));
    }
    let target_display = lookup_class_in_state(compiled, state, class_name)
        .map(|class| class.display_name.clone())
        .unwrap_or_else(|| display_class_name(class_name));
    Ok(CallableValue::BoundMethod {
        target: CallableMethodTarget::Class(target_display),
        method: method.to_owned(),
        scope: Some(normalize_class_name(&resolved.class.name)),
    })
}

fn autoload_resolve_method(
    compiled: &CompiledUnit,
    state: &ExecutionState,
    class_name: &str,
    method: &str,
) -> Result<ResolvedMethodOwned, String> {
    let display_name = callable_class_display_name(compiled, state, class_name);
    let Some(class) = lookup_class_in_state(compiled, state, class_name) else {
        return Err(format!("class {display_name} does not exist"));
    };
    let Some(resolved) =
        lookup_resolved_method_in_state(compiled, state, &class.name, method, None)?
    else {
        return Err(format!(
            "class {} does not have a method \"{method}\"",
            class.display_name
        ));
    };
    if resolved.method.flags.is_private || resolved.method.flags.is_protected {
        return Err(format!(
            "cannot access {} method {}::{}()",
            method_visibility_name(resolved.method.flags),
            resolved.class.display_name,
            method
        ));
    }
    Ok(resolved)
}

fn register_dynamic_unit(
    state: &mut ExecutionState,
    compiled: &CompiledUnit,
    unit: CompiledUnit,
    load_kind: DeclarationLoadKind,
) -> usize {
    // Retain the owner before publishing symbol-table entries so every
    // indexed declaration always points at an already-valid unit slot.
    let unit_index = state.push_dynamic_unit(unit.clone());
    for entry in unit.function_table() {
        if state.dynamic_function_index.contains_key(&entry.name) {
            continue;
        }
        state.push_dynamic_function(DynamicFunctionEntry {
            name: entry.name.clone(),
            unit_index,
            function: entry.function,
            origin: function_declaration_origin(&unit, entry.function, &entry.name, load_kind),
        });
    }
    register_dynamic_classes(state, unit_index, &unit, load_kind);
    for entry in unit.constant_table() {
        if dynamic_constant_declared(compiled, state, &entry.name) {
            continue;
        }
        state.push_dynamic_constant(DynamicConstantEntry {
            name: entry.name.clone(),
            unit_index,
            value: entry.value,
            origin: constant_declaration_origin(&unit, &entry.name, load_kind),
        });
    }
    // Class/autoload epochs guard request-local caches and always advance;
    // the LOOKUP epoch stays constant when this thread has already observed
    // this exact unit's declarations (identical replay), so cross-request
    // slot entries keep validating.
    let replayed = state.worker_symbol_epoch
        && WORKER_SYMBOL_LEDGER
            .with(|ledger| !ledger.seen_units.borrow_mut().insert(unit.cache_identity()));
    state.class_table_epoch = state.class_table_epoch.saturating_add(1);
    if !replayed {
        state.bump_lookup_epoch();
    }
    unit_index
}

fn dynamic_constant_declared(compiled: &CompiledUnit, state: &ExecutionState, name: &str) -> bool {
    compiled.lookup_constant(name).is_some()
        || state.user_constants.contains_key(name)
        || state.dynamic_constant_index.contains_key(name)
}

fn current_instruction_diagnostic_span(
    compiled: &CompiledUnit,
    state: &ExecutionState,
    instruction_span: IrSpan,
) -> RuntimeSourceSpan {
    if compiled
        .unit()
        .files
        .first()
        .is_some_and(|file| file.path.starts_with("eval://"))
        && let Some(span) = state.eval_diagnostic_spans.last()
    {
        return span.clone();
    }
    runtime_source_span(compiled, instruction_span)
}

fn eval_diagnostic_source_span(compiled: &CompiledUnit, eval_span: IrSpan) -> RuntimeSourceSpan {
    if let Some((file, line)) = source_span_file_line(compiled, eval_span) {
        RuntimeSourceSpan {
            file: Some(format!("{file}({line}) : eval()'d code")),
            start: 1,
            end: 1,
        }
    } else {
        runtime_source_span(compiled, eval_span)
    }
}

fn validate_dynamic_declarations(
    compiled: &CompiledUnit,
    state: &ExecutionState,
    unit: &CompiledUnit,
) -> Result<(), String> {
    for entry in unit.function_table() {
        if compiled.lookup_function(&entry.name).is_some()
            || BuiltinRegistry::new().contains(&entry.name)
        {
            return Err(format!(
                "E_PHP_VM_FUNCTION_REDECLARATION: Cannot redeclare function {}()",
                entry.name
            ));
        }
        if let Some(existing) = dynamic_function_entry_by_normalized_name(state, &entry.name) {
            return Err(format!(
                "E_PHP_VM_FUNCTION_REDECLARATION: Cannot redeclare function {}() previously declared at {}",
                entry.name,
                existing.origin.display_site()
            ));
        }
    }
    for class in unit.class_table() {
        if is_lowered_internal_interface_skeleton(class) {
            continue;
        }
        if compiled.lookup_class(&class.name).is_some() {
            return Err(format!(
                "E_PHP_VM_CLASS_REDECLARATION: Cannot declare class {}, because the name is already in use",
                class.display_name
            ));
        }
        if let Some(existing) = dynamic_class_entry_in_state(state, &class.name) {
            return Err(format!(
                "E_PHP_VM_CLASS_REDECLARATION: Cannot declare class {}, because the name is already in use; previous declaration at {}",
                class.display_name,
                existing.origin.display_site()
            ));
        }
    }
    Ok(())
}

fn retain_dynamic_closure_unit(state: &mut ExecutionState, unit: CompiledUnit) -> usize {
    state.push_dynamic_unit(unit)
}

fn dynamic_or_retain_unit_index(state: &mut ExecutionState, compiled: &CompiledUnit) -> usize {
    dynamic_unit_index_for_compiled(state, compiled)
        .unwrap_or_else(|| retain_dynamic_closure_unit(state, compiled.clone()))
}

fn dynamic_unit_index_for_compiled(
    state: &ExecutionState,
    compiled: &CompiledUnit,
) -> Option<usize> {
    let identity = compiled.cache_identity();
    if let Some(&index) = state.dynamic_unit_index.get(&identity)
        && state
            .dynamic_units
            .get(index)
            .is_some_and(|unit| unit.ptr_eq(compiled))
    {
        return Some(index);
    }
    // Cache identities are process-unique. Retain a pointer-only collision
    // fallback so integer wraparound can never select the wrong unit.
    state
        .dynamic_units
        .iter()
        .rposition(|unit| unit.ptr_eq(compiled))
}

impl DeclarationOrigin {
    fn display_site(&self) -> String {
        let namespace = self
            .namespace
            .as_deref()
            .map_or_else(|| "global".to_string(), ToOwned::to_owned);
        format!(
            "{}:{} ({} {:?} {:?} bytes {}..{})",
            self.source_path,
            self.line,
            namespace,
            self.load_kind,
            self.kind,
            self.span.start,
            self.span.end
        )
    }
}

fn function_declaration_origin(
    compiled: &CompiledUnit,
    function: FunctionId,
    name: &str,
    load_kind: DeclarationLoadKind,
) -> DeclarationOrigin {
    let span = compiled
        .unit()
        .functions
        .get(function.index())
        .map_or(IrSpan::default(), |function| function.span);
    declaration_origin(compiled, span, name, DeclarationKind::Function, load_kind)
}

fn constant_declaration_origin(
    compiled: &CompiledUnit,
    name: &str,
    load_kind: DeclarationLoadKind,
) -> DeclarationOrigin {
    let span = compiled
        .unit()
        .constant_table
        .iter()
        .find(|entry| entry.name == name)
        .map_or(IrSpan::default(), |entry| entry.span);
    declaration_origin(
        compiled,
        span,
        name,
        DeclarationKind::GlobalConstant,
        load_kind,
    )
}

fn declaration_origin(
    compiled: &CompiledUnit,
    span: IrSpan,
    name: &str,
    kind: DeclarationKind,
    load_kind: DeclarationLoadKind,
) -> DeclarationOrigin {
    let (source_path, line) = source_span_file_line(compiled, span).unwrap_or_else(|| {
        let source_path = compiled
            .unit()
            .files
            .get(span.file.index())
            .map_or_else(|| "<unknown>".to_string(), |file| file.path.clone());
        (source_path, i64::from(span.start))
    });
    DeclarationOrigin {
        source_path,
        line,
        span,
        namespace: declaration_namespace(name),
        kind,
        load_kind,
    }
}

fn declaration_namespace(name: &str) -> Option<String> {
    let trimmed = name.trim_start_matches('\\');
    let (namespace, _) = trimmed.rsplit_once('\\')?;
    if namespace.is_empty() {
        None
    } else {
        Some(namespace.to_owned())
    }
}

fn declare_runtime_function(
    compiled: &CompiledUnit,
    state: &mut ExecutionState,
    function_name: &str,
    function: FunctionId,
) -> Result<(), String> {
    let normalized = normalize_function_name(function_name);
    if let Some(existing) = compiled.lookup_function(&normalized) {
        return Err(format!(
            "E_PHP_VM_FUNCTION_REDECLARATION: Cannot redeclare function {normalized}(){}",
            function_previous_declaration_suffix(compiled, existing)
        ));
    }
    if let Some(existing) = dynamic_function_entry_by_normalized_name(state, &normalized) {
        return Err(format!(
            "E_PHP_VM_FUNCTION_REDECLARATION: Cannot redeclare function {normalized}() (previously declared in {}:{})",
            existing.origin.source_path, existing.origin.line
        ));
    }
    if BuiltinRegistry::new().contains(&normalized) {
        return Err(format!(
            "E_PHP_VM_FUNCTION_REDECLARATION: Cannot redeclare function {normalized}()"
        ));
    }
    let unit_index = dynamic_or_retain_unit_index(state, compiled);
    state.push_dynamic_function(DynamicFunctionEntry {
        name: normalized,
        unit_index,
        function,
        origin: function_declaration_origin(
            compiled,
            function,
            function_name,
            DeclarationLoadKind::Conditional,
        ),
    });
    state.bump_lookup_epoch();
    Ok(())
}

fn function_previous_declaration_suffix(compiled: &CompiledUnit, function: FunctionId) -> String {
    let Some(function) = compiled.unit().functions.get(function.index()) else {
        return String::new();
    };
    let Some((file, line)) = source_span_file_line(compiled, function.span) else {
        return String::new();
    };
    format!(" (previously declared in {file}:{line})")
}

fn register_dynamic_classes(
    state: &mut ExecutionState,
    unit_index: usize,
    compiled: &CompiledUnit,
    load_kind: DeclarationLoadKind,
) {
    // Declarations living in compile-time-inferred linked files stand in for
    // what an autoloader would provide at class-link time; pre-registering
    // them would make them visible without any autoloader having run. Their
    // runtime declaration is decided by the linked-entry autoload gate.
    let inferred_files: std::collections::HashSet<php_ir::ids::FileId> = compiled
        .unit()
        .linked_file_entries
        .iter()
        .zip(compiled.unit().linked_entry_inferred_declarations.iter())
        .filter(|(_, inferred)| inferred.is_some())
        .filter_map(|(entry, _)| {
            compiled
                .unit()
                .functions
                .get(entry.index())
                .map(|function| function.span.file)
        })
        .collect();
    for class in compiled.unit().classes.iter().filter(|class| {
        class.span != php_ir::source_map::IrSpan::default()
            && !class.flags.is_conditional
            && !inferred_files.contains(&class.span.file)
    }) {
        let normalized = normalize_class_name(&class.name);
        if state.dynamic_class_index.contains_key(&normalized) {
            continue;
        }
        state.push_dynamic_class(DynamicClassEntry {
            lookup_name: normalized,
            class: Arc::new(class.clone()),
            unit_index,
            origin: declaration_origin(
                compiled,
                class.span,
                &class.name,
                DeclarationKind::ClassLike,
                load_kind,
            ),
        });
    }
}

fn is_lowered_internal_interface_skeleton(class: &php_ir::module::ClassEntry) -> bool {
    class.span == php_ir::source_map::IrSpan::default()
        && class.flags.is_interface
        && class.methods.is_empty()
        && class.properties.is_empty()
        && class.constants.is_empty()
        && matches!(
            normalize_class_name(&class.name).as_str(),
            "traversable"
                | "iterator"
                | "iteratoraggregate"
                | "arrayaccess"
                | "throwable"
                | "unitenum"
                | "backedenum"
                | "stringable"
        )
}

fn block_first_span(block: &php_ir::block::BasicBlock) -> Option<IrSpan> {
    block
        .instructions
        .first()
        .map(|instruction| instruction.span)
        .or_else(|| block.terminator.as_ref().map(|terminator| terminator.span))
}

fn declare_runtime_class(
    compiled: &CompiledUnit,
    state: &mut ExecutionState,
    class_name: &str,
) -> Result<(), String> {
    let normalized = normalize_class_name(class_name);
    if lookup_class_in_state(compiled, state, &normalized).is_some() {
        return Err(format!(
            "Cannot declare class {class_name}, because the name is already in use"
        ));
    }
    let Some(class) = compiled.lookup_unit_class(&normalized).cloned() else {
        return Err(format!(
            "class declaration metadata for {class_name} is missing"
        ));
    };
    let unit_index = dynamic_or_retain_unit_index(state, compiled);
    state.push_dynamic_class(DynamicClassEntry {
        lookup_name: normalized,
        origin: declaration_origin(
            compiled,
            class.span,
            &class.name,
            DeclarationKind::ClassLike,
            DeclarationLoadKind::Conditional,
        ),
        class: Arc::new(class),
        unit_index,
    });
    state.bump_class_table_epoch();
    Ok(())
}

fn dynamic_function_in_state(
    state: &ExecutionState,
    function_name: &str,
) -> Option<(CompiledUnit, FunctionId)> {
    let (unit_index, function) = dynamic_function_target_in_state(state, function_name)?;
    let owner = state.dynamic_units.get(unit_index)?.clone();
    Some((owner, function))
}

fn dynamic_function_entry_in_state<'a>(
    state: &'a ExecutionState,
    function_name: &str,
) -> Option<&'a DynamicFunctionEntry> {
    let normalized = normalize_function_name(function_name);
    dynamic_function_entry_by_normalized_name(state, &normalized)
}

fn dynamic_function_entry_by_normalized_name<'a>(
    state: &'a ExecutionState,
    normalized_name: &str,
) -> Option<&'a DynamicFunctionEntry> {
    let index = *state.dynamic_function_index.get(normalized_name)?;
    let entry = state.dynamic_functions.get(index)?;
    debug_assert_eq!(entry.name, normalized_name);
    Some(entry)
}

fn dynamic_function_target_in_state(
    state: &ExecutionState,
    function_name: &str,
) -> Option<(usize, FunctionId)> {
    let entry = dynamic_function_entry_in_state(state, function_name)?;
    Some((entry.unit_index, entry.function))
}

fn dynamic_class_entry_in_state<'a>(
    state: &'a ExecutionState,
    class_name: &str,
) -> Option<&'a DynamicClassEntry> {
    let normalized = normalize_class_name(class_name);
    dynamic_class_entry_by_normalized_name(state, &normalized)
}

fn dynamic_class_entry_by_normalized_name<'a>(
    state: &'a ExecutionState,
    normalized_name: &str,
) -> Option<&'a DynamicClassEntry> {
    let index = *state.dynamic_class_index.get(normalized_name)?;
    let entry = state.dynamic_classes.get(index)?;
    debug_assert_eq!(entry.lookup_name, normalized_name);
    Some(entry)
}

fn dynamic_class_in_loaded_units(
    state: &ExecutionState,
    class_name: &str,
) -> Option<Arc<php_ir::module::ClassEntry>> {
    let normalized = normalize_class_name(class_name);
    state.dynamic_units.iter().rev().find_map(|unit| {
        unit.lookup_class_arc(&normalized)
            .filter(|class| normalize_class_name(&class.name) == normalized)
    })
}

fn closure_owner_for_function(
    compiled: &CompiledUnit,
    state: &ExecutionState,
    function: u32,
    debug: Option<&ClosureDebugInfo>,
    owner_unit: Option<usize>,
) -> CompiledUnit {
    let function_id = FunctionId::new(function);
    if let Some(owner_unit) = owner_unit
        && let Some(unit) = state.dynamic_units.get(owner_unit)
        && unit
            .unit()
            .functions
            .get(function_id.index())
            .is_some_and(|entry| entry.flags.is_closure)
    {
        return unit.clone();
    }
    if compiled_unit_contains_closure(compiled, function_id, debug) {
        return compiled.clone();
    }
    state
        .dynamic_units
        .iter()
        .find(|unit| compiled_unit_contains_closure(unit, function_id, debug))
        .cloned()
        .unwrap_or_else(|| compiled.clone())
}

fn closure_function_has_this_local(compiled: &CompiledUnit, function: u32) -> bool {
    compiled
        .unit()
        .functions
        .get(FunctionId::new(function).index())
        .is_some_and(|entry| entry.locals.iter().any(|local| local == "this"))
}

fn compiled_unit_contains_closure(
    compiled: &CompiledUnit,
    function: FunctionId,
    debug: Option<&ClosureDebugInfo>,
) -> bool {
    let Some(entry) = compiled.unit().functions.get(function.index()) else {
        return false;
    };
    if !entry.flags.is_closure {
        return false;
    }
    let Some(debug) = debug else {
        return true;
    };
    compiled
        .unit()
        .files
        .get(entry.span.file.index())
        .is_some_and(|file| file.path == debug.file)
}

fn lookup_class_in_state(
    compiled: &CompiledUnit,
    state: &ExecutionState,
    class_name: &str,
) -> Option<Arc<php_ir::module::ClassEntry>> {
    lookup_class_in_state_ref(compiled, state, class_name).map(ClassLookup::into_arc)
}

fn lookup_class_in_state_ref(
    compiled: &CompiledUnit,
    state: &ExecutionState,
    class_name: &str,
) -> Option<ClassLookup> {
    let normalized = normalize_class_name(class_name);
    if let Some(entry) = dynamic_class_entry_by_normalized_name(state, &normalized) {
        return Some(ClassLookup::Shared(Arc::clone(&entry.class)));
    }
    if let Some(class) = compiled.lookup_class_arc(class_name) {
        return Some(ClassLookup::Shared(class));
    }
    if let Some(class) = dynamic_class_in_loaded_units(state, &normalized) {
        return Some(ClassLookup::Shared(class));
    }
    if state.failed_class_declarations.contains(&normalized) {
        return None;
    }
    internal_runtime_class_entry(&normalized)
        .or_else(|| internal_enum_class_entry(&normalized))
        .map(|class| ClassLookup::Owned(Box::new(class)))
}

fn internal_runtime_class_entry(normalized: &str) -> Option<php_ir::module::ClassEntry> {
    if is_std_class_runtime_class(normalized) {
        return Some(empty_internal_class_entry("stdClass", None, None, false));
    }
    if is_hash_context_runtime_class(normalized) {
        return Some(internal_hash_context_class_entry());
    }
    if is_php_token_runtime_class(normalized) {
        return Some(internal_php_token_class_entry());
    }
    if is_redis_runtime_class(normalized) {
        return Some(empty_internal_class_entry("Redis", None, None, false));
    }
    if is_memcached_runtime_class(normalized) {
        return Some(empty_internal_class_entry("Memcached", None, None, false));
    }
    if is_soap_runtime_class(normalized) {
        let display_name = soap_display_name(&normalize_class_name(normalized));
        return Some(empty_internal_class_entry(display_name, None, None, false));
    }
    if is_supported_spl_runtime_class(normalized) {
        return Some(internal_spl_class_entry(normalized));
    }
    if normalize_class_name(normalized) == "datetimeinterface"
        || is_date_time_runtime_class(normalized)
    {
        return Some(internal_date_time_class_entry(normalized));
    }
    if normalize_class_name(normalized) == "throwable"
        || internal_throwable_instanceof(normalized, "throwable").is_some()
    {
        return Some(internal_throwable_class_entry(normalized));
    }
    None
}

fn internal_runtime_parent_is_known(
    _class: &php_ir::module::ClassEntry,
    parent_name: &str,
) -> bool {
    internal_runtime_class_entry(&normalize_class_name(parent_name)).is_some()
}

fn internal_spl_class_entry(normalized: &str) -> php_ir::module::ClassEntry {
    if is_spl_interface_runtime_class(normalized) {
        let display_name = display_class_name(normalized);
        let mut entry = empty_internal_class_entry(&display_name, None, None, true);
        entry.interfaces = internal_class_interfaces(&display_name)
            .into_iter()
            .map(|interface| normalize_class_name(&interface))
            .collect();
        return entry;
    }
    let runtime_class = if is_spl_iterator_runtime_class(normalized) {
        spl_iterator_class(normalized)
    } else if is_spl_container_runtime_class(normalized) {
        spl_container_class(normalized)
    } else if is_spl_heap_runtime_class(normalized) {
        spl_heap_class(normalized)
    } else {
        spl_file_class(normalized)
    };
    let display_name = if is_spl_iterator_runtime_class(normalized) {
        spl_iterator_display_name(normalized)
    } else if is_spl_container_runtime_class(normalized) {
        spl_container_display_name(normalized)
    } else if is_spl_heap_runtime_class(normalized) {
        spl_heap_display_name(normalized)
    } else {
        spl_file_display_name(normalized)
    };
    let parent_display_name = runtime_class.parent.as_deref().map(display_class_name);
    let mut entry = empty_internal_class_entry(
        display_name,
        runtime_class.parent.clone(),
        parent_display_name,
        false,
    );
    entry.interfaces = runtime_class.interfaces.clone();
    entry
}

fn internal_throwable_class_entry(normalized: &str) -> php_ir::module::ClassEntry {
    let display_name = internal_throwable_display_name(normalized);
    let parent = internal_throwable_parent(normalized).map(normalize_class_name);
    let parent_display_name = internal_throwable_parent(normalized).map(display_class_name);
    empty_internal_class_entry(
        &display_name,
        parent,
        parent_display_name,
        normalize_class_name(normalized) == "throwable",
    )
}

fn empty_internal_class_entry(
    display_name: &str,
    parent: Option<String>,
    parent_display_name: Option<String>,
    is_interface: bool,
) -> php_ir::module::ClassEntry {
    php_ir::module::ClassEntry {
        id: ClassId::new(u32::MAX),
        name: normalize_class_name(display_name),
        display_name: display_name.to_owned(),
        parent,
        parent_display_name,
        interfaces: Vec::new(),
        methods: Vec::new(),
        properties: Vec::new(),
        constants: Vec::new(),
        enum_cases: Vec::new(),
        attributes: Vec::new(),
        enum_backing_type: None,
        constructor: None,
        flags: php_ir::module::ClassFlags {
            is_interface,
            ..php_ir::module::ClassFlags::default()
        },
        span: IrSpan::default(),
    }
}

fn internal_hash_context_class_entry() -> php_ir::module::ClassEntry {
    let mut entry = empty_internal_class_entry("HashContext", None, None, false);
    let constructor = FunctionId::new(u32::MAX);
    entry.methods.push(php_ir::module::ClassMethodEntry {
        name: "__construct".to_owned(),
        origin_class: entry.name.clone(),
        function: constructor,
        flags: php_ir::module::ClassMethodFlags {
            is_private: true,
            ..php_ir::module::ClassMethodFlags::default()
        },
        attributes: Vec::new(),
    });
    entry.constructor = Some(constructor);
    entry
}

fn internal_php_token_class_entry() -> php_ir::module::ClassEntry {
    let mut entry = empty_internal_class_entry("PhpToken", None, None, false);
    entry.interfaces.push(normalize_class_name("Stringable"));
    let constructor = FunctionId::new(u32::MAX);
    entry.methods.push(php_ir::module::ClassMethodEntry {
        name: "__construct".to_owned(),
        origin_class: entry.name.clone(),
        function: constructor,
        flags: php_ir::module::ClassMethodFlags {
            is_final: true,
            ..php_ir::module::ClassMethodFlags::default()
        },
        attributes: Vec::new(),
    });
    entry.constructor = Some(constructor);
    entry
}

