fn class_like_exists_direct(
    compiled: &CompiledUnit,
    state: &ExecutionState,
    class_name: &str,
    kind: AutoloadClassLookupKind,
) -> bool {
    if lookup_class_in_state(compiled, state, class_name).is_some_and(|class| match kind {
        AutoloadClassLookupKind::ClassLike => true,
        AutoloadClassLookupKind::Interface => class.flags.is_interface,
        AutoloadClassLookupKind::Enum => class.flags.is_enum,
        AutoloadClassLookupKind::Trait => class.flags.is_trait,
        AutoloadClassLookupKind::Class => !class.flags.is_interface && !class.flags.is_trait,
    }) {
        return true;
    }

    php_std::ExtensionRegistry::standard_library()
        .enabled_class(class_name)
        .is_some_and(|class| match kind {
            AutoloadClassLookupKind::ClassLike => true,
            AutoloadClassLookupKind::Interface => class.kind() == php_std::ClassKind::Interface,
            AutoloadClassLookupKind::Enum => class.kind() == php_std::ClassKind::Enum,
            AutoloadClassLookupKind::Trait => class.kind() == php_std::ClassKind::Trait,
            AutoloadClassLookupKind::Class => class.kind() == php_std::ClassKind::Class,
        })
}

fn class_dependency_display_name(
    compiled: &CompiledUnit,
    class: &php_ir::module::ClassEntry,
    normalized_dependency: &str,
) -> String {
    let normalized_dependency = normalize_class_name(normalized_dependency);
    if class
        .parent
        .as_deref()
        .is_some_and(|parent| normalize_class_name(parent) == normalized_dependency)
        && let Some(display) = class.parent_display_name.as_deref()
    {
        return display.to_owned();
    }
    let Some(file) = compiled.unit().files.get(class.span.file.index()) else {
        return normalized_dependency;
    };
    let Ok(source) = std::fs::read_to_string(&file.path) else {
        return normalized_dependency;
    };
    if let Some(display) =
        class_dependency_import_display_name(&source, class, &normalized_dependency)
    {
        return display;
    }
    let start = (class.span.start as usize).min(source.len());
    let end = (class.span.end as usize).min(source.len()).max(start);
    let declaration = source[start..end]
        .split_once('{')
        .map_or(&source[start..end], |(head, _)| head);
    for token in php_name_tokens(declaration) {
        if normalize_class_name(&token) == normalized_dependency {
            return display_class_name(&token);
        }
        if class_name_tail(&token).eq_ignore_ascii_case(class_name_tail(&normalized_dependency))
            && let Some(display) = class_dependency_namespace_display_name(
                &source,
                class,
                &token,
                &normalized_dependency,
            )
        {
            return display;
        }
    }
    normalized_dependency
}

fn class_dependency_import_display_name(
    source: &str,
    class: &php_ir::module::ClassEntry,
    normalized_dependency: &str,
) -> Option<String> {
    let header_end = (class.span.start as usize).min(source.len());
    let header = source.get(..header_end)?;
    let dependency_tail = class_name_tail(normalized_dependency);
    for line in header.lines() {
        let line = line.trim();
        let Some(imports) = line.strip_prefix("use ") else {
            continue;
        };
        if let Some(display) = class_dependency_import_display_name_from_imports(
            imports,
            dependency_tail,
            normalized_dependency,
        ) {
            return Some(display);
        }
    }
    for statement in header.split(';') {
        let statement = statement.trim();
        let Some(imports) = statement.strip_prefix("use ") else {
            continue;
        };
        if let Some(display) = class_dependency_import_display_name_from_imports(
            imports,
            dependency_tail,
            normalized_dependency,
        ) {
            return Some(display);
        }
    }
    None
}

fn class_dependency_import_display_name_from_imports(
    imports: &str,
    dependency_tail: &str,
    normalized_dependency: &str,
) -> Option<String> {
    let imports = imports.trim().trim_end_matches(';').trim();
    if imports.starts_with("function ") || imports.starts_with("const ") {
        return None;
    }
    for import in imports.split(',') {
        let import = import.trim();
        if import.contains('{') || import.contains('}') {
            continue;
        }
        let (name, alias) = split_import_alias(import);
        let name = name.trim().trim_start_matches('\\');
        if name.is_empty() {
            continue;
        }
        let alias = alias
            .map(str::trim)
            .filter(|alias| !alias.is_empty())
            .unwrap_or_else(|| class_name_tail(name));
        if alias.eq_ignore_ascii_case(dependency_tail)
            && normalize_class_name(name) == normalized_dependency
        {
            return Some(name.to_owned());
        }
    }
    None
}

fn class_dependency_namespace_display_name(
    source: &str,
    class: &php_ir::module::ClassEntry,
    token: &str,
    normalized_dependency: &str,
) -> Option<String> {
    if token.contains('\\') {
        return None;
    }
    let namespace = class_declaration_namespace_display_name(source, class)?;
    let candidate = format!("{namespace}\\{token}");
    (normalize_class_name(&candidate) == normalized_dependency).then_some(candidate)
}

fn class_declaration_namespace_display_name(
    source: &str,
    class: &php_ir::module::ClassEntry,
) -> Option<String> {
    let header_end = (class.span.start as usize).min(source.len());
    let header = source.get(..header_end)?;
    for statement in header.split(';') {
        let statement = statement.trim();
        let marker = "namespace ";
        let Some(index) = statement.find(marker) else {
            continue;
        };
        let namespace = statement[index + marker.len()..].trim();
        if namespace.is_empty() || namespace.starts_with('{') {
            continue;
        }
        let namespace = namespace
            .split_whitespace()
            .next()
            .unwrap_or(namespace)
            .trim_matches('{')
            .trim();
        if !namespace.is_empty() {
            return Some(namespace.trim_start_matches('\\').to_owned());
        }
    }
    None
}

fn split_import_alias(import: &str) -> (&str, Option<&str>) {
    let lower = import.to_ascii_lowercase();
    if let Some(index) = lower.rfind(" as ") {
        (&import[..index], Some(&import[index + 4..]))
    } else {
        (import, None)
    }
}

fn class_name_tail(name: &str) -> &str {
    name.trim_start_matches('\\')
        .rsplit('\\')
        .next()
        .unwrap_or(name)
}

fn should_defer_class_dependency_validation(class: &php_ir::module::ClassEntry) -> bool {
    class.name.starts_with("__phrust_anonymous_") || class.display_name.starts_with("anonymous#")
}

fn php_name_tokens(source: &str) -> Vec<String> {
    let mut tokens = Vec::new();
    let mut current = String::new();
    for ch in source.chars() {
        if ch == '\\' || ch == '_' || ch.is_alphanumeric() {
            current.push(ch);
        } else if !current.is_empty() {
            tokens.push(std::mem::take(&mut current));
        }
    }
    if !current.is_empty() {
        tokens.push(current);
    }
    tokens
}

fn is_valid_autoload_class_name(class_name: &str) -> bool {
    let name = class_name.strip_prefix('\\').unwrap_or(class_name);
    if name.is_empty() {
        return false;
    }
    name.split('\\')
        .all(|segment| is_valid_autoload_class_name_segment(segment.as_bytes()))
}

fn is_valid_autoload_class_name_segment(segment: &[u8]) -> bool {
    let Some((&first, rest)) = segment.split_first() else {
        return false;
    };
    is_php_name_start_byte(first) && rest.iter().copied().all(is_php_name_byte)
}

fn is_php_name_start_byte(byte: u8) -> bool {
    byte == b'_' || byte.is_ascii_alphabetic() || byte >= 0x80
}

fn is_php_name_byte(byte: u8) -> bool {
    byte == b'_' || byte.is_ascii_alphanumeric() || byte >= 0x80
}

impl AutoloadClassLookupKind {
    const fn exists_function_name(self) -> &'static str {
        match self {
            Self::ClassLike => "class_exists",
            Self::Class => "class_exists",
            Self::Interface => "interface_exists",
            Self::Trait => "trait_exists",
            Self::Enum => "enum_exists",
        }
    }
}

fn autoload_trace_origin_from_call_site(
    compiled: &CompiledUnit,
    function_name: &'static str,
    call_site: Option<(u64, FunctionId, BlockId, InstrId)>,
) -> Option<AutoloadTraceOrigin> {
    let (_, function_id, block_id, instruction_id) = call_site?;
    let function = compiled.unit().functions.get(function_id.index())?;
    let block = function.blocks.get(block_id.index())?;
    let instruction = block
        .instructions
        .iter()
        .find(|instruction| instruction.id == instruction_id)?;
    Some(AutoloadTraceOrigin {
        function_name,
        span: instruction.span,
    })
}

fn capture_autoload_trace(
    compiled: &CompiledUnit,
    stack: &CallStack,
    callback: &CallableValue,
    class_name: &str,
    origin: AutoloadTraceOrigin,
) -> String {
    let class_arg = format_trace_arg(&Value::string(class_name.as_bytes().to_vec()));
    let callback = autoload_trace_callback_name(callback);
    let mut lines = vec![format!("#0 [internal function]: {callback}({class_arg})")];
    let file = compiled
        .unit()
        .files
        .get(origin.span.file.index())
        .map(|file| file.path.clone())
        .unwrap_or_default();
    let line = source_span_display_line(compiled, origin.span, false)
        .unwrap_or_else(|| i64::from(origin.span.start));
    lines.push(format!(
        "#1 {file}({line}): {}({class_arg})",
        origin.function_name
    ));
    let rest = capture_backtrace_string_from_index(compiled, stack, 2);
    if !rest.is_empty() {
        lines.push(rest);
    }
    lines.join("\n")
}

fn autoload_trace_callback_name(callback: &CallableValue) -> String {
    match callback {
        CallableValue::UserFunction { name } | CallableValue::InternalBuiltin { name } => {
            name.clone()
        }
        CallableValue::Closure(_) => "{closure}".to_owned(),
        CallableValue::BoundMethod { target, method, .. } => {
            let target = match target {
                CallableMethodTarget::Object(object) => object.display_name(),
                CallableMethodTarget::Class(class_name) => class_name.clone(),
            };
            format!("{target}->{method}")
        }
        CallableValue::MethodPlaceholder { target }
        | CallableValue::UnresolvedDynamic { target } => target.clone(),
    }
}

fn dynamic_class_owner_in_state(state: &ExecutionState, class_name: &str) -> Option<CompiledUnit> {
    let unit_index = dynamic_class_owner_index_in_state(state, class_name)?;
    state.dynamic_units.get(unit_index).cloned()
}

fn class_owner_in_state(
    compiled: &CompiledUnit,
    state: &ExecutionState,
    class_name: &str,
) -> CompiledUnit {
    dynamic_class_owner_in_state(state, class_name).unwrap_or_else(|| compiled.clone())
}

fn destructor_entry_owner(
    compiled: &CompiledUnit,
    state: &ExecutionState,
    entry: &DestructorEntry,
) -> CompiledUnit {
    entry
        .owner_dynamic_unit_index
        .and_then(|unit_index| state.dynamic_units.get(unit_index).cloned())
        .unwrap_or_else(|| compiled.clone())
}

fn dynamic_class_owner_index_in_state(state: &ExecutionState, class_name: &str) -> Option<usize> {
    let normalized = normalize_class_name(class_name);
    if let Some(entry) = dynamic_class_entry_by_normalized_name(state, &normalized)
        && state.dynamic_units.get(entry.unit_index).is_some()
    {
        return Some(entry.unit_index);
    }
    state.dynamic_units.iter().rposition(|unit| {
        unit.lookup_class(&normalized)
            .is_some_and(|class| normalize_class_name(&class.name) == normalized)
    })
}

struct ResolvedConstantValue {
    value: Value,
    predefined: Option<&'static php_std::ConstantDescriptor>,
}

fn global_constant_lookup(
    compiled: &CompiledUnit,
    state: &mut ExecutionState,
    stack: &CallStack,
    name: &str,
) -> Result<Option<ResolvedConstantValue>, String> {
    if let Some(constant) = compiled.lookup_constant(name) {
        Ok(Some(ResolvedConstantValue {
            value: inline_constant_value(constant),
            predefined: None,
        }))
    } else if let Some(value) = dynamic_constant_value_in_state(state, name)? {
        Ok(Some(ResolvedConstantValue {
            value,
            predefined: None,
        }))
    } else if let Some(value) = state.user_constants.get(name) {
        Ok(Some(ResolvedConstantValue {
            value: value.clone(),
            predefined: None,
        }))
    } else if let Some(value) = class_constant_value_by_name(compiled, state, stack, name)? {
        Ok(Some(ResolvedConstantValue {
            value,
            predefined: None,
        }))
    } else {
        Ok(predefined_constant_lookup_for_state(state, name))
    }
}

fn global_constant_value(
    compiled: &CompiledUnit,
    state: &mut ExecutionState,
    stack: &CallStack,
    name: &str,
) -> Result<Option<Value>, String> {
    Ok(global_constant_lookup(compiled, state, stack, name)?.map(|resolved| resolved.value))
}

fn lexical_constant_lookup(
    compiled: &CompiledUnit,
    state: &mut ExecutionState,
    stack: &CallStack,
    name: &str,
) -> Result<Option<ResolvedConstantValue>, String> {
    if let Some(resolved) = global_constant_lookup(compiled, state, stack, name)? {
        return Ok(Some(resolved));
    }
    let Some((_, global_name)) = name.rsplit_once('\\') else {
        return Ok(None);
    };
    if global_name.is_empty() {
        return Ok(None);
    }
    global_constant_lookup(compiled, state, stack, global_name)
}

fn lexical_constant_value(
    compiled: &CompiledUnit,
    state: &mut ExecutionState,
    stack: &CallStack,
    name: &str,
) -> Result<Option<Value>, String> {
    Ok(lexical_constant_lookup(compiled, state, stack, name)?.map(|resolved| resolved.value))
}

fn dynamic_constant_value_in_state(
    state: &ExecutionState,
    name: &str,
) -> Result<Option<Value>, String> {
    let Some(entry_index) = state.dynamic_constant_index.get(name).copied() else {
        return Ok(None);
    };
    let Some(entry) = state.dynamic_constants.get(entry_index) else {
        return Ok(None);
    };
    debug_assert_eq!(entry.name, name);
    let Some(owner) = state.dynamic_units.get(entry.unit_index) else {
        return Ok(None);
    };
    constant_value(owner.unit(), entry.value).map(Some)
}

fn class_constant_value_by_name(
    compiled: &CompiledUnit,
    state: &mut ExecutionState,
    stack: &CallStack,
    name: &str,
) -> Result<Option<Value>, String> {
    let Some((class_name, constant_name)) = name.split_once("::") else {
        return Ok(None);
    };
    let Some(class) = lookup_class_in_state(compiled, state, class_name) else {
        return Ok(None);
    };
    if constant_name.eq_ignore_ascii_case("class") {
        return Ok(Some(Value::String(PhpString::from_test_str(
            &class.display_name,
        ))));
    }
    if let Some(value) = pdo_class_constant_value(class_name, constant_name) {
        return Ok(Some(value));
    }
    if let Some(value) = zip_class_constant_value(class_name, constant_name) {
        return Ok(Some(value));
    }
    if let Some(value) = redis_class_constant_value(class_name, constant_name) {
        return Ok(Some(value));
    }
    if let Some(value) = memcached_class_constant_value(class_name, constant_name) {
        return Ok(Some(value));
    }
    if let Some(value) = intl_class_constant_value(class_name, constant_name) {
        return Ok(Some(value));
    }
    if let Some(value) = xml_class_constant_value(class_name, constant_name) {
        return Ok(Some(value));
    }
    if let Some(value) = date_time_class_constant_value(class_name, constant_name) {
        return Ok(Some(value));
    }
    if let Some(value) =
        spl_class_constant_value_in_state(compiled, state, class_name, constant_name)
    {
        return Ok(Some(value));
    }
    if class.flags.is_enum
        && let Some(case) = class
            .enum_cases
            .iter()
            .find(|case| case.name.eq_ignore_ascii_case(constant_name))
    {
        let object = enum_case_object(compiled, state, &class, case, &|constant| {
            constant_value(compiled.unit(), constant)
        })
        .map_err(|message| {
            format!(
                "E_PHP_VM_ENUM_CASE_CONSTANT_VALUE: failed to build enum case {}::{}: {message}",
                class.display_name, case.name
            )
        })?;
        return Ok(Some(Value::Object(object)));
    }
    let Some((resolved_class, resolved_constant)) = lookup_class_constant_in_state(
        compiled,
        state,
        &class.name,
        &class.display_name,
        constant_name,
    )?
    else {
        return Ok(None);
    };
    validate_constant_access(compiled, stack, &resolved_class, &resolved_constant)?;
    if let Some(value) = resolved_constant.value {
        let owner = class_owner_in_state(compiled, state, &resolved_class.name);
        runtime_constant_value(compiled, state, stack, owner.unit(), value).map(Some)
    } else if let Some(reference) = &resolved_constant.value_class_constant {
        class_constant_reference_value(compiled, state, reference).map(Some)
    } else if let Some(reference) = &resolved_constant.value_named_constant {
        named_constant_reference_value(compiled, state, reference).map(Some)
    } else {
        Ok(Some(Value::Null))
    }
}

fn named_constant_reference_value(
    compiled: &CompiledUnit,
    state: &ExecutionState,
    reference: &NamedConstantReference,
) -> Result<Value, String> {
    for name in &reference.names {
        if let Some(constant) = compiled.lookup_constant(name) {
            return Ok(inline_constant_value(constant));
        }
        if let Some(value) = dynamic_constant_value_in_state(state, name)? {
            return Ok(value);
        }
        if let Some(value) = state.user_constants.get(name) {
            return Ok(value.clone());
        }
        if let Some(value) = predefined_constant_value_for_state(state, name) {
            return Ok(value);
        }
    }
    Err(format!(
        "E_PHP_VM_UNDEFINED_CONSTANT: Undefined constant \"{}\"",
        if reference.display_name.is_empty() {
            reference
                .names
                .first()
                .map(String::as_str)
                .unwrap_or_default()
        } else {
            &reference.display_name
        }
    ))
}

fn class_constant_reference_value(
    compiled: &CompiledUnit,
    state: &ExecutionState,
    reference: &ClassConstantReference,
) -> Result<Value, String> {
    class_constant_reference_value_inner(compiled, state, reference, &mut Vec::new())
}

fn class_constant_reference_value_inner(
    compiled: &CompiledUnit,
    state: &ExecutionState,
    reference: &ClassConstantReference,
    visiting: &mut Vec<(String, String)>,
) -> Result<Value, String> {
    let key = (
        normalize_class_name(&reference.class_name),
        reference.constant_name.clone(),
    );
    if visiting.iter().any(|entry| entry == &key) {
        return Err(format!(
            "E_PHP_VM_CLASS_CONSTANT_CYCLE: class constant {}::{} has a recursive initializer",
            reference.class_name, reference.constant_name
        ));
    }
    visiting.push(key);
    let (class, constant) = lookup_class_constant_in_state(
        compiled,
        state,
        &reference.class_name,
        &reference.display_class_name,
        &reference.constant_name,
    )?
    .ok_or_else(|| {
        format!(
            "E_PHP_VM_UNKNOWN_CLASS_CONSTANT: Undefined constant {}::{}",
            class_constant_reference_display_class(reference),
            reference.constant_name
        )
    })?;
    let value = if let Some(value) = constant.value {
        let owner = class_owner_in_state(compiled, state, &class.name);
        constant_value(owner.unit(), value)?
    } else if let Some(next) = &constant.value_class_constant {
        class_constant_reference_value_inner(compiled, state, next, visiting)?
    } else if let Some(reference) = &constant.value_named_constant {
        named_constant_reference_value(compiled, state, reference)?
    } else {
        Value::Null
    };
    visiting.pop();
    Ok(value)
}

fn lookup_class_constant_in_state(
    compiled: &CompiledUnit,
    state: &ExecutionState,
    class_name: &str,
    reference_display_class_name: &str,
    constant_name: &str,
) -> Result<
    Option<(
        Arc<php_ir::module::ClassEntry>,
        php_ir::module::ClassConstantEntry,
    )>,
    String,
> {
    let Some(class) = lookup_class_in_state(compiled, state, class_name) else {
        return Err(format!(
            "E_PHP_VM_UNKNOWN_CLASS: Class \"{}\" not found",
            if reference_display_class_name.is_empty() {
                display_class_name(class_name)
            } else {
                reference_display_class_name.to_owned()
            }
        ));
    };
    lookup_class_constant_in_state_inner(compiled, state, class, constant_name, &mut Vec::new())
}

fn lookup_class_constant_in_state_inner(
    compiled: &CompiledUnit,
    state: &ExecutionState,
    class: Arc<php_ir::module::ClassEntry>,
    constant_name: &str,
    seen: &mut Vec<String>,
) -> Result<
    Option<(
        Arc<php_ir::module::ClassEntry>,
        php_ir::module::ClassConstantEntry,
    )>,
    String,
> {
    let normalized = normalize_class_name(&class.name);
    if seen.iter().any(|name| name == &normalized) {
        return Err(format!(
            "E_PHP_VM_CLASS_INHERITANCE_CYCLE: class {} participates in an inheritance cycle",
            class.name
        ));
    }
    seen.push(normalized);
    if let Some(constant) = class
        .constants
        .iter()
        .find(|entry| entry.name == constant_name)
        .cloned()
    {
        seen.pop();
        return Ok(Some((class, constant)));
    }
    if let Some(parent_name) = class.parent.as_deref() {
        let Some(parent) = lookup_class_in_state(compiled, state, parent_name) else {
            return Err(format!(
                "E_PHP_VM_UNKNOWN_PARENT_CLASS: class {} extends missing class {}",
                class.name, parent_name
            ));
        };
        let resolved =
            lookup_class_constant_in_state_inner(compiled, state, parent, constant_name, seen)?;
        if resolved
            .as_ref()
            .is_some_and(|(_, constant)| constant.flags.is_private)
        {
            seen.pop();
            return Ok(None);
        }
        if resolved.is_some() {
            seen.pop();
            return Ok(resolved);
        }
    }
    for interface_name in &class.interfaces {
        let Some(interface) = lookup_class_in_state(compiled, state, interface_name) else {
            continue;
        };
        if let Some(resolved) =
            lookup_class_constant_in_state_inner(compiled, state, interface, constant_name, seen)?
        {
            seen.pop();
            return Ok(Some(resolved));
        }
    }
    seen.pop();
    Ok(None)
}

fn class_constant_reference_display_class(reference: &ClassConstantReference) -> String {
    if reference.display_class_name.is_empty() {
        display_class_name(&reference.class_name)
    } else {
        reference.display_class_name.clone()
    }
}

fn predefined_constant_lookup(name: &str) -> Option<ResolvedConstantValue> {
    let constant = php_std::ExtensionRegistry::standard_library().enabled_constant(name)?;
    Some(ResolvedConstantValue {
        value: php_std::constants::constant_to_value(constant.value()?),
        predefined: Some(constant),
    })
}

fn predefined_constant_lookup_for_state(
    state: &ExecutionState,
    name: &str,
) -> Option<ResolvedConstantValue> {
    match name {
        "PHP_SAPI" => Some(ResolvedConstantValue {
            value: Value::string(state.sapi_name.clone()),
            predefined: None,
        }),
        "PHP_BINARY" => Some(ResolvedConstantValue {
            value: Value::string(state.php_binary.clone()),
            predefined: None,
        }),
        _ => predefined_constant_lookup(name),
    }
}

fn predefined_constant_value_for_state(state: &ExecutionState, name: &str) -> Option<Value> {
    predefined_constant_lookup_for_state(state, name).map(|resolved| resolved.value)
}

fn ini_option_name(value: &Value) -> Result<String, String> {
    to_string(value).map(|name| name.to_string_lossy())
}

fn session_ini_cannot_change_when_active(option: &str) -> bool {
    matches!(
        option.to_ascii_lowercase().as_str(),
        "session.save_path"
            | "session.name"
            | "session.save_handler"
            | "session.gc_probability"
            | "session.gc_divisor"
            | "session.gc_maxlifetime"
            | "session.serialize_handler"
            | "session.sid_length"
            | "session.sid_bits_per_character"
            | "session.use_strict_mode"
            | "session.cookie_lifetime"
            | "session.cookie_path"
            | "session.cookie_domain"
            | "session.cookie_secure"
            | "session.cookie_partitioned"
            | "session.cookie_httponly"
            | "session.cookie_samesite"
            | "session.use_cookies"
            | "session.use_only_cookies"
            | "session.referer_check"
            | "session.cache_expire"
            | "session.cache_limiter"
            | "session.use_trans_sid"
            | "session.lazy_write"
    )
}

fn session_sid_ini_deprecation(option: &str, value: &str) -> Option<String> {
    let (canonical, default) = if option.eq_ignore_ascii_case("session.sid_length") {
        ("session.sid_length", 32)
    } else if option.eq_ignore_ascii_case("session.sid_bits_per_character") {
        ("session.sid_bits_per_character", 4)
    } else {
        return None;
    };
    let parsed = value.trim().parse::<i64>().unwrap_or(0);
    (parsed != default).then(|| format!("ini_set(): {canonical} INI setting is deprecated"))
}

fn session_serialize_handler_ini_error(option: &str, value: &str) -> Option<String> {
    if !option.eq_ignore_ascii_case("session.serialize_handler") {
        return None;
    }
    match value {
        "php" | "php_binary" | "php_serialize" => None,
        _ => Some(format!(
            "ini_set(): Serialization handler \"{value}\" cannot be found"
        )),
    }
}

fn ini_set_effective_value(option: &str, value: String, cwd: &Path) -> String {
    if option.eq_ignore_ascii_case("open_basedir") {
        return normalize_open_basedir_ini_value(&value, cwd);
    }
    value
}

fn normalize_open_basedir_ini_value(value: &str, cwd: &Path) -> String {
    value
        .split(open_basedir_separator())
        .map(|entry| {
            let entry = entry.trim();
            if entry.is_empty() {
                String::new()
            } else {
                canonicalize_open_basedir_path(entry, cwd)
                    .to_string_lossy()
                    .into_owned()
            }
        })
        .collect::<Vec<_>>()
        .join(&open_basedir_separator().to_string())
}

fn session_save_path_open_basedir_ini_error(
    option: &str,
    value: &str,
    cwd: &Path,
    registry: &IniRegistry,
) -> Option<String> {
    if !option.eq_ignore_ascii_case("session.save_path") {
        return None;
    }
    let save_path = session_save_path_directory(value)?;
    let open_basedir = registry.get("open_basedir")?.trim();
    if open_basedir.is_empty() || open_basedir_allows_path(&save_path, open_basedir, cwd) {
        return None;
    }
    Some(format!(
        "ini_set(): open_basedir restriction in effect. File({save_path}) is not within the allowed path(s): ({open_basedir})"
    ))
}

fn session_save_path_directory(raw_path: &str) -> Option<String> {
    let path = raw_path
        .split(';')
        .next_back()
        .unwrap_or(raw_path)
        .trim()
        .to_owned();
    (!path.is_empty()).then_some(path)
}

fn open_basedir_allows_path(path: &str, open_basedir: &str, cwd: &Path) -> bool {
    let candidate = canonicalize_open_basedir_path(path, cwd);
    open_basedir
        .split(open_basedir_separator())
        .filter_map(|entry| {
            let entry = entry.trim();
            (!entry.is_empty()).then(|| canonicalize_open_basedir_path(entry, cwd))
        })
        .any(|allowed| candidate == allowed || candidate.starts_with(&allowed))
}

fn canonicalize_open_basedir_path(path: &str, cwd: &Path) -> PathBuf {
    let path = Path::new(path);
    let absolute = if path.is_absolute() {
        path.to_path_buf()
    } else {
        cwd.join(path)
    };
    fs::canonicalize(&absolute).unwrap_or_else(|_| normalize_open_basedir_path(&absolute))
}

fn normalize_open_basedir_path(path: &Path) -> PathBuf {
    let mut normalized = PathBuf::new();
    for component in path.components() {
        match component {
            std::path::Component::CurDir => {}
            std::path::Component::ParentDir => {
                normalized.pop();
            }
            component => normalized.push(component.as_os_str()),
        }
    }
    normalized
}

fn open_basedir_separator() -> char {
    if cfg!(windows) { ';' } else { ':' }
}

fn apply_float_string_precision(registry: &IniRegistry) {
    if let Some(precision) = registry
        .get("precision")
        .and_then(|value| value.trim().parse::<i32>().ok())
    {
        set_float_string_precision(precision);
    }
}

fn ini_get_all_array(registry: &IniRegistry, details: bool, extension: Option<&str>) -> PhpArray {
    let mut output = PhpArray::new();
    let entries = match extension {
        Some(extension) => registry.entries_for_extension(extension),
        None => registry.entries(),
    };
    for entry in entries {
        let value = if details {
            let mut detail = PhpArray::new();
            detail.insert(
                php_string_key("global_value"),
                Value::string(entry.global_value),
            );
            detail.insert(
                php_string_key("local_value"),
                Value::string(entry.local_value),
            );
            detail.insert(php_string_key("access"), Value::Int(entry.access));
            Value::Array(detail)
        } else {
            Value::string(entry.local_value)
        };
        output.insert(php_string_key(entry.name), value);
    }
    output
}

fn trim_error_handler_args(
    compiled: &CompiledUnit,
    state: &ExecutionState,
    callback: &CallableValue,
    values: Vec<Value>,
) -> Vec<Value> {
    let Some(max_args) = error_handler_callback_max_args(compiled, state, callback) else {
        return values;
    };
    values.into_iter().take(max_args).collect()
}

fn error_handler_callback_max_args(
    compiled: &CompiledUnit,
    state: &ExecutionState,
    callback: &CallableValue,
) -> Option<usize> {
    match callback {
        CallableValue::UserFunction { name } => {
            if let Some(function) = compiled
                .lookup_function(name)
                .and_then(|function| compiled.unit().functions.get(function.index()))
            {
                return Some(user_function_max_positional_args(function));
            }
            dynamic_function_in_state(state, name).and_then(|(owner, function)| {
                owner
                    .unit()
                    .functions
                    .get(function.index())
                    .map(user_function_max_positional_args)
            })
        }
        CallableValue::Closure(payload) => compiled
            .unit()
            .functions
            .get(FunctionId::new(payload.function).index())
            .map(user_function_max_positional_args),
        CallableValue::InternalBuiltin { .. }
        | CallableValue::BoundMethod { .. }
        | CallableValue::MethodPlaceholder { .. }
        | CallableValue::UnresolvedDynamic { .. } => None,
    }
}

fn user_function_max_positional_args(function: &IrFunction) -> usize {
    if function.params.iter().any(|param| param.variadic) {
        usize::MAX
    } else {
        function.params.len()
    }
}

fn current_error_reporting(state: &ExecutionState) -> i64 {
    state
        .ini
        .get("error_reporting")
        .and_then(|value| value.parse::<i64>().ok())
        .unwrap_or(-1)
}

fn error_reporting_allows(state: &ExecutionState, level: i64) -> bool {
    error_reporting_allows_level(current_error_reporting(state), level)
}

fn display_errors_enabled(state: &ExecutionState) -> bool {
    !matches!(
        state.ini.get("display_errors"),
        Some("") | Some("0") | Some("Off") | Some("off")
    )
}

fn diagnostic_display_options(state: &ExecutionState) -> php_runtime::PhpDiagnosticDisplayOptions {
    php_runtime::PhpDiagnosticDisplayOptions {
        display_errors: display_errors_enabled(state),
        error_reporting: current_error_reporting(state),
        ..php_runtime::PhpDiagnosticDisplayOptions::default()
    }
}

fn emit_vm_diagnostic(
    output: &mut OutputBuffer,
    state: &ExecutionState,
    diagnostic: &RuntimeDiagnostic,
    channel: php_runtime::PhpDiagnosticChannel,
    level: i64,
) -> bool {
    emit_vm_diagnostic_with_options(output, state, diagnostic, channel, level, true)
}

fn emit_vm_diagnostic_with_options(
    output: &mut OutputBuffer,
    state: &ExecutionState,
    diagnostic: &RuntimeDiagnostic,
    channel: php_runtime::PhpDiagnosticChannel,
    level: i64,
    leading_newline: bool,
) -> bool {
    let mut options = diagnostic_display_options(state);
    options.leading_newline = leading_newline;
    emit_php_diagnostic(output, diagnostic, channel, level, options)
}

fn runtime_source_span(compiled: &CompiledUnit, span: php_ir::IrSpan) -> RuntimeSourceSpan {
    RuntimeSourceSpan {
        file: compiled
            .unit()
            .files
            .get(span.file.index())
            .map(|file| file.path.clone()),
        start: span.start,
        end: span.end,
    }
}

fn is_supported_user_error_level(level: i64) -> bool {
    matches!(
        level,
        php_std::constants::E_USER_WARNING
            | php_std::constants::E_USER_NOTICE
            | php_std::constants::E_USER_DEPRECATED
            | php_std::constants::E_USER_ERROR
    )
}

fn error_level_channel(level: i64) -> php_runtime::PhpDiagnosticChannel {
    match level {
        php_std::constants::E_USER_NOTICE => php_runtime::PhpDiagnosticChannel::Notice,
        php_std::constants::E_USER_DEPRECATED => php_runtime::PhpDiagnosticChannel::Deprecated,
        php_std::constants::E_USER_ERROR => php_runtime::PhpDiagnosticChannel::FatalError,
        _ => php_runtime::PhpDiagnosticChannel::Warning,
    }
}

fn error_level_diagnostic_id(level: i64) -> &'static str {
    match level {
        php_std::constants::E_USER_NOTICE => "E_PHP_VM_USER_NOTICE",
        php_std::constants::E_USER_DEPRECATED => "E_PHP_VM_USER_DEPRECATED",
        php_std::constants::E_USER_ERROR => "E_PHP_VM_USER_ERROR",
        _ => "E_PHP_VM_USER_WARNING",
    }
}

fn error_level_severity(level: i64) -> RuntimeSeverity {
    match level {
        php_std::constants::E_USER_NOTICE => RuntimeSeverity::Notice,
        php_std::constants::E_USER_DEPRECATED => RuntimeSeverity::Deprecation,
        php_std::constants::E_USER_ERROR => RuntimeSeverity::FatalError,
        _ => RuntimeSeverity::Warning,
    }
}

fn state_include_path(state: &ExecutionState) -> Arc<Vec<PathBuf>> {
    Arc::clone(&state.parsed_include_path)
}

fn parse_ini_include_path(ini: &IniRegistry) -> Arc<Vec<PathBuf>> {
    Arc::new(
        ini.get("include_path")
            .unwrap_or(".")
            .split(':')
            .filter(|entry| !entry.is_empty())
            .map(PathBuf::from)
            .collect(),
    )
}

fn php_string_key(value: &str) -> ArrayKey {
    ArrayKey::String(PhpString::from_test_str(value))
}

fn php_object_vars_key(value: &str) -> ArrayKey {
    ArrayKey::from_php_string(PhpString::from_test_str(value))
}

fn object_from_value(value: &Value) -> Option<ObjectRef> {
    match value {
        Value::Object(object) => Some(object.clone()),
        Value::Reference(cell) => object_from_value(&cell.get()),
        _ => None,
    }
}

fn class_name_for_is_a_subject(
    value: &Value,
    allow_string: bool,
) -> Result<Option<String>, String> {
    match effective_value(value) {
        Value::Object(object) => Ok(Some(object.class_name())),
        Value::Callable(_) => Ok(Some("Closure".to_owned())),
        value if allow_string => to_string(&value).map(|name| Some(name.to_string_lossy())),
        _ => Ok(None),
    }
}

fn object_vars_array(
    compiled: &CompiledUnit,
    stack: &CallStack,
    object: &ObjectRef,
    mangled: bool,
) -> PhpArray {
    let mut array = PhpArray::new();
    let class = compiled.lookup_class(&object.class_name());
    let scope = current_scope_class(compiled, stack);

    for (storage_name, value) in object.properties_snapshot() {
        if !mangled && is_spl_internal_storage_property(object, &storage_name) {
            continue;
        }
        if let Some((declaring_class, property)) = private_storage_parts(&storage_name) {
            if mangled {
                let display_class =
                    class_display_name(compiled, &declaring_class).unwrap_or(declaring_class);
                array.insert(
                    ArrayKey::String(PhpString::from_test_str(&format!(
                        "\0{display_class}\0{property}"
                    ))),
                    value,
                );
            } else if scope.as_deref().is_some_and(|scope| {
                normalize_class_name(scope) == normalize_class_name(&declaring_class)
            }) {
                array.insert(php_string_key(&property), value);
            }
            continue;
        }

        let property = class.and_then(|class| {
            lookup_property_in_hierarchy(compiled, class, &storage_name, None)
                .ok()
                .flatten()
        });
        if mangled {
            let key = property
                .as_ref()
                .and_then(|resolved| {
                    if resolved.property.flags.is_protected {
                        Some(ArrayKey::String(PhpString::from_test_str(&format!(
                            "\0*\0{}",
                            resolved.property.name
                        ))))
                    } else {
                        None
                    }
                })
                .unwrap_or_else(|| php_string_key(&storage_name));
            array.insert(key, value);
            continue;
        }

        let visible = property.as_ref().is_none_or(|resolved| {
            class_member_visible(
                compiled,
                scope.as_deref(),
                resolved.class,
                resolved.property.flags.is_private,
                resolved.property.flags.is_protected,
            )
        });
        if visible {
            let key = property
                .as_ref()
                .map(|resolved| php_string_key(resolved.property.name.as_str()))
                .unwrap_or_else(|| php_object_vars_key(storage_name.as_str()));
            array.insert(key, value);
        }
    }

    array
}

fn is_spl_internal_storage_property(object: &ObjectRef, storage_name: &str) -> bool {
    if spl_runtime_marker(object).is_none() {
        return false;
    }
    matches!(
        storage_name,
        SPL_RUNTIME_CLASS_PROPERTY
            | "__append_entry_iterator_indices"
            | "__append_iterators"
            | "__attached_iterator_ids"
            | "__attached_iterators"
            | "__entries"
            | "__entry_depths"
            | "__extract_flags"
            | "__file_info_class"
            | "__flags"
            | "__inner_iterator"
            | "__iterator_class"
            | "__iterator_count"
            | "__limit_count"
            | "__limit_offset"
            | "__position"
            | "__regex_accept_pre_parent"
            | "__regex_flags"
            | "__regex_last_accept_result"
            | "__regex_mode"
            | "__regex_pattern"
            | "__rii_array_string_warning_positions"
            | "__rii_checked_child_results"
            | "__rii_checked_child_positions"
            | "__rii_direct_at_root"
            | "__rii_direct_root_consumed"
            | "__rii_end_iteration_called"
            | "__rii_entered_child_positions"
            | "__rii_flags"
            | "__rii_hook_depth"
            | "__rii_hook_iterators"
            | "__rii_iteration_active"
            | "__rii_last_call_has_children"
            | "__rii_mode"
            | "__rii_notified_position"
            | "__rii_pruned_branches"
            | "__rti_flags"
            | "__rti_prefix_parts"
            | "__snapshot_source_id"
            | "__storage"
            | "__sub_iterators"
    )
}

fn private_storage_parts(storage_name: &str) -> Option<(String, String)> {
    storage_name
        .strip_prefix("private:")
        .and_then(|rest| rest.split_once(':'))
        .map(|(class, property)| (class.to_owned(), property.to_owned()))
}

fn sleep_property_value(
    properties: &[(String, Value)],
    selected_name: &str,
) -> Option<(String, Value)> {
    properties.iter().find_map(|(storage_name, value)| {
        if storage_name == selected_name {
            return Some((storage_name.clone(), value.clone()));
        }
        if let Some((owner, property)) = private_storage_parts(storage_name)
            && (property == selected_name || selected_name == format!("\0{owner}\0{property}"))
        {
            return Some((storage_name.clone(), value.clone()));
        }
        if selected_name == format!("\0*\0{storage_name}") {
            return Some((storage_name.clone(), value.clone()));
        }
        None
    })
}

fn class_display_name(compiled: &CompiledUnit, normalized_class: &str) -> Option<String> {
    compiled
        .unit()
        .classes
        .iter()
        .find(|class| normalize_class_name(&class.name) == normalized_class)
        .map(|class| class.display_name.clone())
}

fn method_display_name(
    compiled: &CompiledUnit,
    method: &php_ir::module::ClassMethodEntry,
) -> String {
    compiled
        .unit()
        .functions
        .get(method.function.index())
        .and_then(|function| {
            function
                .name
                .split_once("::")
                .map(|(_, name)| name.to_owned())
        })
        .unwrap_or_else(|| method.name.clone())
}

fn visible_class_methods(
    compiled: &CompiledUnit,
    stack: &CallStack,
    state: &ExecutionState,
    class: &php_ir::module::ClassEntry,
) -> Vec<String> {
    let scope = current_scope_class(compiled, stack);
    let mut methods = Vec::new();
    let mut seen = BTreeSet::new();
    for class in class_hierarchy(compiled, state, class) {
        for method in &class.methods {
            let normalized = normalize_method_name(&method.name);
            if seen.contains(&normalized) {
                continue;
            }
            seen.insert(normalized);
            if class_member_visible(
                compiled,
                scope.as_deref(),
                &class,
                method.flags.is_private,
                method.flags.is_protected,
            ) {
                methods.push(method_display_name(compiled, method));
            }
        }
    }
    methods
}

fn visible_class_vars(
    compiled: &CompiledUnit,
    stack: &CallStack,
    state: &mut ExecutionState,
    class: &php_ir::module::ClassEntry,
) -> PhpArray {
    let scope = current_scope_class(compiled, stack);
    let mut array = PhpArray::new();
    let mut classes = class_hierarchy(compiled, state, class);
    classes.reverse();
    for class in classes {
        for property in &class.properties {
            if class_member_visible(
                compiled,
                scope.as_deref(),
                &class,
                property.flags.is_private,
                property.flags.is_protected,
            ) {
                let value = static_property_default(compiled, state, stack, &class, property)
                    .unwrap_or(Value::Uninitialized);
                array.insert(php_string_key(&property.name), value);
            }
        }
    }
    array
}

fn class_hierarchy(
    compiled: &CompiledUnit,
    state: &ExecutionState,
    class: &php_ir::module::ClassEntry,
) -> Vec<Arc<php_ir::module::ClassEntry>> {
    // Shared handles: entries are large (method/property tables) and callers
    // only read; one clone for the starting borrow, none per ancestor.
    let mut classes = Vec::new();
    let mut current = Some(Arc::new(class.clone()));
    let mut seen = BTreeSet::new();
    while let Some(class) = current {
        let normalized = normalize_class_name(&class.name);
        if !seen.insert(normalized) {
            break;
        }
        current = class
            .parent
            .as_deref()
            .and_then(|parent| lookup_class_in_state(compiled, state, parent));
        classes.push(class);
    }
    classes
}

fn class_member_visible(
    compiled: &CompiledUnit,
    scope: Option<&str>,
    declaring_class: &php_ir::module::ClassEntry,
    is_private: bool,
    is_protected: bool,
) -> bool {
    if is_private {
        return scope.is_some_and(|scope| {
            normalize_class_name(scope) == normalize_class_name(&declaring_class.name)
        });
    }
    if is_protected {
        return scope.is_some_and(|scope| {
            class_is_or_extends(compiled, scope, &declaring_class.name).unwrap_or(false)
        });
    }
    true
}

/// Consuming variant of [`call_args_from_php_array`]: argument arrays that
/// reach `call_user_func_array` as sole-owner temporaries (hook dispatch
/// building `array_slice(...)` results) move their values into the call
/// instead of cloning every element.
fn call_args_from_owned_php_array(array: PhpArray) -> Vec<CallArgument> {
    array
        .into_pairs()
        .into_iter()
        .map(|(key, value)| {
            let mut arg = CallArgument::positional(value);
            if let ArrayKey::String(name) = key {
                arg.name = Some(name.to_string_lossy());
            }
            arg
        })
        .collect()
}

fn call_args_from_php_array(array: &PhpArray) -> Vec<CallArgument> {
    array
        .iter()
        .map(|(key, value)| {
            let mut arg = CallArgument::positional(value.clone());
            if let ArrayKey::String(name) = key {
                arg.name = Some(name.to_string_lossy());
            }
            arg
        })
        .collect()
}

fn class_name_from_object_or_string(value: &Value) -> Result<String, String> {
    if let Some(object) = object_from_value(value) {
        return Ok(object.class_name());
    }
    to_string(value).map(|name| name.to_string_lossy())
}

fn dynamic_static_class_name_from_value(value: &Value) -> Result<String, String> {
    match effective_value(value) {
        Value::String(name) => Ok(display_class_name(&name.to_string_lossy())),
        Value::Object(object) => Ok(object.class_name()),
        other => Err(format!(
            "E_PHP_VM_INVALID_DYNAMIC_CLASS_NAME: class name must be string or object, {} given",
            value_type_name(&other)
        )),
    }
}

fn lookup_method_in_state(
    compiled: &CompiledUnit,
    state: &ExecutionState,
    class_name: &str,
    method: &str,
) -> Result<Option<php_ir::module::ClassMethodEntry>, String> {
    lookup_resolved_method_in_state(compiled, state, class_name, method, None)
        .map(|resolved| resolved.map(|resolved| resolved.method))
}

fn lookup_resolved_method_in_state(
    compiled: &CompiledUnit,
    state: &ExecutionState,
    class_name: &str,
    method: &str,
    caller_scope: Option<&str>,
) -> Result<Option<ResolvedMethodOwned>, String> {
    let Some(class) = lookup_class_in_state_ref(compiled, state, class_name) else {
        return Ok(None);
    };
    if let Some(resolved) = lookup_private_method_in_caller_scope_in_state(
        compiled,
        state,
        class.as_ref(),
        method,
        caller_scope,
    )? {
        return Ok(Some(resolved));
    }
    lookup_resolved_method_in_state_inner(
        compiled,
        state,
        class.into_arc(),
        method,
        caller_scope,
        &mut Vec::new(),
    )
}

fn lookup_private_method_in_caller_scope_in_state(
    compiled: &CompiledUnit,
    state: &ExecutionState,
    class: &php_ir::module::ClassEntry,
    method: &str,
    caller_scope: Option<&str>,
) -> Result<Option<ResolvedMethodOwned>, String> {
    let Some(scope) = caller_scope else {
        return Ok(None);
    };
    if !class_is_a_in_state(compiled, state, &class.name, scope)? {
        return Ok(None);
    }
    let Some(scope_class) = lookup_class_in_state_ref(compiled, state, scope) else {
        return Ok(None);
    };
    let normalized = normalize_method_name(method);
    let Some(scope_method) = scope_class
        .as_ref()
        .methods
        .iter()
        .find(|entry| entry.flags.is_private && normalize_method_name(&entry.name) == normalized)
        .cloned()
    else {
        return Ok(None);
    };
    Ok(Some(ResolvedMethodOwned {
        class: scope_class.into_arc(),
        method: scope_method,
    }))
}

fn lookup_resolved_method_in_state_inner(
    compiled: &CompiledUnit,
    state: &ExecutionState,
    class: Arc<php_ir::module::ClassEntry>,
    method: &str,
    caller_scope: Option<&str>,
    seen: &mut Vec<String>,
) -> Result<Option<ResolvedMethodOwned>, String> {
    let class_name = normalize_class_name(&class.name);
    if seen.iter().any(|name| name == &class_name) {
        return Err(format!(
            "E_PHP_VM_CLASS_INHERITANCE_CYCLE: class {} participates in an inheritance cycle",
            class.name
        ));
    }
    seen.push(class_name.clone());
    let normalized = normalize_method_name(method);
    if let Some(method) = class
        .methods
        .iter()
        .find(|entry| normalize_method_name(&entry.name) == normalized)
    {
        if method.flags.is_private
            && caller_scope.is_some_and(|scope| normalize_class_name(scope) != class_name)
            && class.parent.is_some()
            && let Some(parent_class) = class
                .parent
                .as_deref()
                .and_then(|parent| lookup_class_in_state_ref(compiled, state, parent))
            && let Some(parent_method) = lookup_resolved_method_in_state_inner(
                compiled,
                state,
                parent_class.into_arc(),
                method.name.as_str(),
                caller_scope,
                seen,
            )?
        {
            seen.pop();
            return Ok(Some(parent_method));
        }
        seen.pop();
        return Ok(Some(ResolvedMethodOwned {
            class: Arc::clone(&class),
            method: method.clone(),
        }));
    }
    if let Some(parent_class) = class
        .parent
        .as_deref()
        .and_then(|parent| lookup_class_in_state_ref(compiled, state, parent))
    {
        let resolved = lookup_resolved_method_in_state_inner(
            compiled,
            state,
            parent_class.into_arc(),
            method,
            caller_scope,
            seen,
        )?;
        seen.pop();
        return Ok(resolved);
    }
    seen.pop();
    Ok(None)
}

fn lookup_property_in_state(
    compiled: &CompiledUnit,
    state: &ExecutionState,
    class_name: &str,
    property: &str,
) -> Result<Option<php_ir::module::ClassPropertyEntry>, String> {
    let Some(class) = lookup_class_in_state_ref(compiled, state, class_name) else {
        return Ok(None);
    };
    lookup_property_in_state_inner(compiled, state, class.as_ref(), property, &mut Vec::new())
}

fn lookup_resolved_property_in_state(
    compiled: &CompiledUnit,
    state: &ExecutionState,
    class: &php_ir::module::ClassEntry,
    property: &str,
    caller_scope: Option<&str>,
) -> Result<Option<ResolvedPropertyOwned>, String> {
    if let Some(resolved) = lookup_private_property_in_state_caller_scope(
        compiled,
        state,
        class,
        property,
        caller_scope,
    )? {
        return Ok(Some(resolved));
    }
    lookup_resolved_property_in_state_inner(
        compiled,
        state,
        class,
        property,
        caller_scope,
        &mut Vec::new(),
    )
}

fn lookup_private_property_in_state_caller_scope(
    compiled: &CompiledUnit,
    state: &ExecutionState,
    class: &php_ir::module::ClassEntry,
    property: &str,
    caller_scope: Option<&str>,
) -> Result<Option<ResolvedPropertyOwned>, String> {
    let Some(scope) = caller_scope else {
        return Ok(None);
    };
    if !class_is_subclass_of_in_state(compiled, state, &class.name, scope)?
        && normalize_class_name(&class.name) != normalize_class_name(scope)
    {
        return Ok(None);
    }
    let Some(scope_class) = lookup_class_in_state_ref(compiled, state, scope) else {
        return Ok(None);
    };
    let Some(scope_property) = scope_class
        .as_ref()
        .properties
        .iter()
        .find(|entry| entry.flags.is_private && entry.name == property)
        .cloned()
    else {
        return Ok(None);
    };
    Ok(Some(ResolvedPropertyOwned {
        class: scope_class.into_arc(),
        property: scope_property,
    }))
}

fn lookup_resolved_property_in_state_inner(
    compiled: &CompiledUnit,
    state: &ExecutionState,
    class: &php_ir::module::ClassEntry,
    property: &str,
    caller_scope: Option<&str>,
    seen: &mut Vec<String>,
) -> Result<Option<ResolvedPropertyOwned>, String> {
    let class_name = normalize_class_name(&class.name);
    if seen.iter().any(|name| name == &class_name) {
        return Err(format!(
            "E_PHP_VM_CLASS_INHERITANCE_CYCLE: class {} participates in an inheritance cycle",
            class.name
        ));
    }
    seen.push(class_name.clone());
    if let Some(entry) = class.properties.iter().find(|entry| entry.name == property) {
        if entry.flags.is_private
            && caller_scope.is_some_and(|scope| normalize_class_name(scope) != class_name)
            && class.parent.is_some()
            && let Some(parent_class) = class
                .parent
                .as_deref()
                .and_then(|parent| lookup_class_in_state_ref(compiled, state, parent))
            && let Some(parent_property) = lookup_resolved_property_in_state_inner(
                compiled,
                state,
                parent_class.as_ref(),
                entry.name.as_str(),
                caller_scope,
                seen,
            )?
        {
            seen.pop();
            return Ok(Some(parent_property));
        }
        seen.pop();
        return Ok(Some(ResolvedPropertyOwned {
            class: Arc::new(class.clone()),
            property: entry.clone(),
        }));
    }
    if let Some(parent_name) = class.parent.as_deref() {
        let Some(parent_class) = lookup_class_in_state_ref(compiled, state, parent_name) else {
            return Err(format!(
                "E_PHP_VM_UNKNOWN_PARENT_CLASS: class {} extends missing class {}",
                class.name, parent_name
            ));
        };
        let resolved = lookup_resolved_property_in_state_inner(
            compiled,
            state,
            parent_class.as_ref(),
            property,
            caller_scope,
            seen,
        )?;
        seen.pop();
        return Ok(resolved);
    }
    seen.pop();
    Ok(None)
}

fn lookup_property_in_state_inner(
    compiled: &CompiledUnit,
    state: &ExecutionState,
    class: &php_ir::module::ClassEntry,
    property: &str,
    seen: &mut Vec<String>,
) -> Result<Option<php_ir::module::ClassPropertyEntry>, String> {
    let class_name = normalize_class_name(&class.name);
    if seen.iter().any(|name| name == &class_name) {
        return Err(format!(
            "E_PHP_VM_CLASS_INHERITANCE_CYCLE: class {} participates in an inheritance cycle",
            class.name
        ));
    }
    seen.push(class_name);
    if let Some(property) = class.properties.iter().find(|entry| entry.name == property) {
        seen.pop();
        return Ok(Some(property.clone()));
    }
    if let Some(parent_class) = class
        .parent
        .as_deref()
        .and_then(|parent| lookup_class_in_state_ref(compiled, state, parent))
    {
        let resolved =
            lookup_property_in_state_inner(compiled, state, parent_class.as_ref(), property, seen)?;
        seen.pop();
        return Ok(resolved);
    }
    seen.pop();
    Ok(None)
}

fn class_is_subclass_of_in_state(
    compiled: &CompiledUnit,
    state: &ExecutionState,
    class_name: &str,
    target_name: &str,
) -> Result<bool, String> {
    let class_name = normalize_class_name(class_name);
    let target_name = normalize_class_name(target_name);
    if class_name == target_name {
        return Ok(false);
    }
    class_extends_in_state(compiled, state, &class_name, &target_name, &mut Vec::new())?
        .then_some(true)
        .map(Ok)
        .unwrap_or_else(|| {
            class_implements_in_state(compiled, state, &class_name, &target_name, &mut Vec::new())
        })
}

fn class_is_a_in_state(
    compiled: &CompiledUnit,
    state: &ExecutionState,
    class_name: &str,
    target_name: &str,
) -> Result<bool, String> {
    let class_name = normalize_class_name(class_name);
    let target_name = normalize_class_name(target_name);
    if class_name == target_name {
        return Ok(class_exists_for_is_a(compiled, state, &class_name));
    }
    class_is_subclass_of_in_state(compiled, state, &class_name, &target_name)
}

fn class_is_or_extends_internal_throwable_in_state(
    compiled: &CompiledUnit,
    state: &ExecutionState,
    class_name: &str,
) -> Result<bool, String> {
    let mut current = normalize_class_name(class_name);
    let mut seen = Vec::new();
    loop {
        if internal_throwable_instanceof(&current, "throwable").is_some() {
            return Ok(true);
        }
        let Some(class) = lookup_class_in_state(compiled, state, &current) else {
            return Ok(false);
        };
        let normalized = normalize_class_name(&class.name);
        if seen.iter().any(|name| name == &normalized) {
            return Err(format!(
                "E_PHP_VM_CLASS_INHERITANCE_CYCLE: class {} participates in an inheritance cycle",
                class.name
            ));
        }
        seen.push(normalized);
        let Some(parent) = class.parent.as_deref() else {
            return Ok(false);
        };
        current = normalize_class_name(parent);
    }
}

fn iterator_function_accepts_iterable(
    compiled: &CompiledUnit,
    state: &ExecutionState,
    value: &Value,
) -> Result<bool, String> {
    match effective_value(value) {
        Value::Array(_) | Value::Generator(_) => Ok(true),
        Value::Object(object) => {
            let class_name = object.class_name();
            if let Some(spl_class) = spl_runtime_marker(&object) {
                return Ok(internal_spl_iterator_instanceof(&spl_class, "Traversable")
                    .or_else(|| internal_spl_container_instanceof(&spl_class, "Traversable"))
                    .or_else(|| internal_spl_heap_instanceof(&spl_class, "Traversable"))
                    .or_else(|| internal_spl_file_instanceof(&spl_class, "Traversable"))
                    .unwrap_or(false));
            }
            Ok(
                class_is_a_in_state(compiled, state, &class_name, "Iterator")?
                    || class_is_a_in_state(compiled, state, &class_name, "IteratorAggregate")?,
            )
        }
        _ => Ok(false),
    }
}

fn class_exists_for_is_a(
    compiled: &CompiledUnit,
    state: &ExecutionState,
    class_name: &str,
) -> bool {
    lookup_class_in_state(compiled, state, class_name).is_some()
}

fn class_extends_in_state(
    compiled: &CompiledUnit,
    state: &ExecutionState,
    class_name: &str,
    target_name: &str,
    seen: &mut Vec<String>,
) -> Result<bool, String> {
    let Some(class) = lookup_class_in_state(compiled, state, class_name) else {
        return Ok(false);
    };
    let current = normalize_class_name(&class.name);
    if seen.iter().any(|name| name == &current) {
        return Err(format!(
            "E_PHP_VM_CLASS_INHERITANCE_CYCLE: class {} participates in an inheritance cycle",
            class.name
        ));
    }
    seen.push(current);
    let Some(parent) = class.parent.as_deref() else {
        seen.pop();
        return Ok(false);
    };
    let parent = normalize_class_name(parent);
    if parent == target_name {
        seen.pop();
        return Ok(true);
    }
    let result = class_extends_in_state(compiled, state, &parent, target_name, seen)?;
    seen.pop();
    Ok(result)
}

fn class_implements_in_state(
    compiled: &CompiledUnit,
    state: &ExecutionState,
    class_name: &str,
    target_name: &str,
    seen: &mut Vec<String>,
) -> Result<bool, String> {
    let target_name = normalize_class_name(target_name);
    let Some(class) = lookup_class_in_state(compiled, state, class_name) else {
        return Ok(false);
    };
    let current = normalize_class_name(&class.name);
    if seen.iter().any(|name| name == &current) {
        return Err(format!(
            "E_PHP_VM_CLASS_INHERITANCE_CYCLE: class {} participates in an inheritance cycle",
            class.name
        ));
    }
    seen.push(current);
    for interface in &class.interfaces {
        let interface = normalize_class_name(interface);
        if interface == target_name
            || interface_extends_in_state(
                compiled,
                state,
                &interface,
                &target_name,
                &mut Vec::new(),
            )?
        {
            seen.pop();
            return Ok(true);
        }
    }
    if let Some(parent) = class.parent.as_deref()
        && class_implements_in_state(compiled, state, parent, &target_name, seen)?
    {
        seen.pop();
        return Ok(true);
    }
    seen.pop();
    Ok(false)
}

fn userland_arrayaccess_object(
    compiled: &CompiledUnit,
    state: &ExecutionState,
    value: &Value,
) -> Result<Option<ObjectRef>, String> {
    let Value::Object(object) = effective_value(value) else {
        return Ok(None);
    };
    userland_arrayaccess_object_from_object(compiled, state, object)
}

fn userland_arrayaccess_object_from_object(
    compiled: &CompiledUnit,
    state: &ExecutionState,
    object: ObjectRef,
) -> Result<Option<ObjectRef>, String> {
    if spl_runtime_marker(&object).is_some_and(|class| is_spl_array_access_runtime_class(&class)) {
        return Ok(None);
    }
    if class_implements_in_state(
        compiled,
        state,
        &object.class_name(),
        "ArrayAccess",
        &mut Vec::new(),
    )? {
        Ok(Some(object))
    } else {
        Ok(None)
    }
}

fn arrayaccess_object(
    compiled: &CompiledUnit,
    state: &ExecutionState,
    value: &Value,
) -> Result<Option<ObjectRef>, String> {
    let Value::Object(object) = effective_value(value) else {
        return Ok(None);
    };
    if spl_runtime_marker(&object).is_some_and(|class| is_spl_array_access_runtime_class(&class)) {
        return Ok(Some(object));
    }
    userland_arrayaccess_object(compiled, state, &Value::Object(object))
}

fn interface_extends_in_state(
    compiled: &CompiledUnit,
    state: &ExecutionState,
    interface_name: &str,
    target_name: &str,
    seen: &mut Vec<String>,
) -> Result<bool, String> {
    let interface_name = normalize_class_name(interface_name);
    let target_name = normalize_class_name(target_name);
    if interface_name == target_name {
        return Ok(true);
    }
    let Some(interface) = lookup_class_in_state(compiled, state, &interface_name) else {
        for parent in internal_class_interfaces(&interface_name) {
            if interface_extends_in_state(compiled, state, &parent, &target_name, seen)? {
                return Ok(true);
            }
        }
        return Ok(false);
    };
    if seen.iter().any(|name| name == &interface_name) {
        return Err(format!(
            "E_PHP_VM_INTERFACE_INHERITANCE_CYCLE: interface {} participates in an inheritance cycle",
            interface.name
        ));
    }
    seen.push(interface_name);
    for parent in &interface.interfaces {
        if interface_extends_in_state(compiled, state, parent, &target_name, seen)? {
            seen.pop();
            return Ok(true);
        }
    }
    seen.pop();
    Ok(false)
}

fn declared_classes_in_state(
    compiled: &CompiledUnit,
    state: &ExecutionState,
) -> Vec<php_ir::module::ClassEntry> {
    let mut seen = BTreeSet::new();
    let mut classes = Vec::new();
    for class in compiled.unit().classes.iter().chain(
        state
            .dynamic_classes
            .iter()
            .map(|entry| entry.class.as_ref()),
    ) {
        let normalized = normalize_class_name(&class.name);
        if seen.insert(normalized) {
            classes.push(class.clone());
        }
    }
    classes
}

fn eval_failure(
    output: &OutputBuffer,
    message: impl Into<String>,
    stack_trace: Vec<RuntimeStackFrame>,
) -> VmResult {
    let message = message.into();
    VmResult::runtime_error_with_diagnostic(
        output.clone(),
        message.clone(),
        RuntimeDiagnostic::new(
            eval_failure_id(&message).to_owned(),
            RuntimeSeverity::FatalError,
            message,
            RuntimeSourceSpan::default(),
            stack_trace,
            None,
        ),
    )
}

fn eval_failure_id(message: &str) -> &str {
    message
        .split_once(':')
        .and_then(|(id, _)| id.starts_with("E_").then_some(id))
        .unwrap_or("E_PHP_VM_EVAL_ERROR")
}

fn current_source_path(compiled: &CompiledUnit, stack: &CallStack) -> Option<PathBuf> {
    let frame = stack.current()?;
    let function = compiled.unit().functions.get(frame.function.index())?;
    let file = compiled.unit().files.get(function.span.file.index())?;
    Some(PathBuf::from(&file.path))
}

fn dense_instruction_span(dense: &DenseBytecodeUnit, instruction: &DenseInstruction) -> IrSpan {
    dense
        .spans
        .get(instruction.span.index())
        .copied()
        .unwrap_or_default()
}

fn is_synthetic_eof_return(
    function: &IrFunction,
    terminator_span: IrSpan,
    return_value: Option<&Value>,
) -> bool {
    function.flags.is_top_level
        && terminator_span == function.span
        && matches!(return_value, None | Some(Value::Null))
}

fn include_return_value(return_value: Option<Value>, returned_explicitly: bool) -> Option<Value> {
    if returned_explicitly {
        Some(return_value.unwrap_or(Value::Null))
    } else {
        None
    }
}

fn shared_locals_from_current_frame(
    compiled: &CompiledUnit,
    stack: &CallStack,
) -> HashMap<String, Slot> {
    let Some(frame) = stack.current() else {
        return HashMap::new();
    };
    let Some(function) = compiled.unit().functions.get(frame.function.index()) else {
        return HashMap::new();
    };
    function
        .locals
        .iter()
        .enumerate()
        .filter_map(|(index, name)| {
            frame
                .locals
                .get_slot(LocalId::new(index as u32))
                .map(|slot| (name.clone(), slot.clone()))
        })
        .collect()
}

fn import_shared_locals(
    function: &IrFunction,
    stack: &mut CallStack,
    state: &mut ExecutionState,
    shared: &HashMap<String, Slot>,
    bind_missing_globals: bool,
) {
    let Some(frame) = stack.current_mut() else {
        return;
    };
    for (index, name) in function.locals.iter().enumerate() {
        if let Some(slot) = shared.get(name) {
            let _ = frame
                .locals
                .set_slot(LocalId::new(index as u32), slot.clone());
        } else if bind_missing_globals && name != "GLOBALS" {
            let cell = state
                .globals
                .ensure_slot(name.clone(), Value::Uninitialized);
            let _ = frame
                .locals
                .bind_reference_cell(LocalId::new(index as u32), cell);
        }
    }
}

fn current_frame_is_top_level(compiled: &CompiledUnit, stack: &CallStack) -> bool {
    let Some(frame) = stack.current() else {
        return false;
    };
    compiled
        .unit()
        .functions
        .get(frame.function.index())
        .is_some_and(|function| function.flags.is_top_level)
}

fn auto_start_session_if_configured(state: &mut ExecutionState, source_span: RuntimeSourceSpan) {
    if !ini_bool(&state.ini, "session.auto_start")
        || state.session.status() == php_runtime::PHP_SESSION_ACTIVE
    {
        return;
    }
    if state.session.needs_lazy_load() {
        let id = state.session.id().to_owned();
        if let Some(loader) = &state.session_loader
            && let Ok(data) = loader.load(&id)
        {
            state.session.load_data(data);
        }
    }
    let id_length = session_sid_length_from_ini(&state.ini);
    let strict_mode = ini_bool(&state.ini, "session.use_strict_mode");
    state.session.start_with_policy(id_length, strict_mode);
    state.session.mark_started_automatically();
    let location = php_runtime::PhpDiagnosticLocation::from_span(&source_span);
    state
        .session
        .record_start_location(location.file, location.line);
    state.globals.set("_SESSION", state.session.data_value());
}

fn session_sid_length_from_ini(ini: &IniRegistry) -> usize {
    ini.get("session.sid_length")
        .and_then(|value| value.trim().parse::<usize>().ok())
        .filter(|value| (22..=256).contains(value))
        .unwrap_or(32)
}

fn ini_bool(ini: &IniRegistry, name: &str) -> bool {
    ini.get(name).is_some_and(|value| {
        !matches!(
            value.trim().to_ascii_lowercase().as_str(),
            "" | "0" | "false" | "off" | "no"
        )
    })
}

fn seed_runtime_globals(globals: &mut GlobalSymbolTable, context: &RuntimeContext) {
    for name in [
        "argc", "argv", "_SERVER", "_ENV", "_GET", "_POST", "_COOKIE", "_FILES", "_REQUEST",
        "_SESSION",
    ] {
        if let Some(value) = context.global_value(name) {
            globals.set(name, value);
        }
    }
}

fn sync_session_state_from_globals(state: &mut ExecutionState) {
    let Some(Value::Array(array)) = state.globals.get("_SESSION") else {
        return;
    };
    state.session.set_data(array);
}

fn env_entries_array(entries: &[(String, String)]) -> PhpArray {
    let mut array = PhpArray::new();
    for (key, value) in entries {
        array.insert(
            ArrayKey::String(PhpString::from_test_str(key)),
            Value::string(value.clone()),
        );
    }
    array
}

fn set_env_entry(entries: &mut Vec<(String, String)>, key: String, value: Option<String>) {
    entries.retain(|(entry_key, _)| entry_key != &key);
    if let Some(value) = value {
        entries.push((key, value));
        entries.sort_by(|left, right| left.0.cmp(&right.0).then(left.1.cmp(&right.1)));
    }
}

fn php_uname_value(mode: &str) -> String {
    match mode.chars().next().unwrap_or('a').to_ascii_lowercase() {
        's' => "Phrust".to_string(),
        'n' => "localhost".to_string(),
        'r' => php_source::reference_php_version().to_string(),
        'v' => "Stdlib".to_string(),
        'm' => "generic".to_string(),
        _ => format!(
            "Phrust localhost {} Stdlib generic",
            php_source::reference_php_version()
        ),
    }
}

fn script_owner_uid(script_path: Option<&str>) -> i64 {
    script_path
        .and_then(|path| fs::metadata(path).ok())
        .map_or_else(current_directory_uid, |metadata| {
            metadata_owner_uid(&metadata)
        })
}

fn script_owner_gid(script_path: Option<&str>) -> i64 {
    script_path
        .and_then(|path| fs::metadata(path).ok())
        .map_or_else(current_directory_gid, |metadata| {
            metadata_owner_gid(&metadata)
        })
}

#[cfg(unix)]
fn metadata_owner_uid(metadata: &fs::Metadata) -> i64 {
    use std::os::unix::fs::MetadataExt as _;

    metadata.uid() as i64
}

#[cfg(not(unix))]
fn metadata_owner_uid(_metadata: &fs::Metadata) -> i64 {
    0
}

#[cfg(unix)]
fn metadata_owner_gid(metadata: &fs::Metadata) -> i64 {
    use std::os::unix::fs::MetadataExt as _;

    metadata.gid() as i64
}

#[cfg(not(unix))]
fn metadata_owner_gid(_metadata: &fs::Metadata) -> i64 {
    0
}

fn current_directory_uid() -> i64 {
    fs::metadata(".").map_or(0, |metadata| metadata_owner_uid(&metadata))
}

fn current_directory_gid() -> i64 {
    fs::metadata(".").map_or(0, |metadata| metadata_owner_gid(&metadata))
}

fn validate_process_arity(name: &str, argc: usize) -> Option<String> {
    let valid = match name {
        "proc_open" => (3..=6).contains(&argc),
        "proc_close" | "proc_get_status" | "pclose" => argc == 1,
        "popen" => argc == 2,
        "shell_exec" | "system" => argc == 1,
        "exec" => (1..=3).contains(&argc),
        "passthru" => (1..=2).contains(&argc),
        _ => false,
    };
    if valid {
        None
    } else {
        Some(format!(
            "E_PHP_VM_PROCESS_ARITY: {name} received {argc} argument(s)"
        ))
    }
}

fn process_disabled_result(
    output: &OutputBuffer,
    name: &str,
    stack_trace: Vec<RuntimeStackFrame>,
) -> VmResult {
    process_warning_result(
        output,
        name,
        "E_PHP_VM_PROCESS_CAPABILITY_DISABLED",
        format!("{name}(): process execution is disabled by runtime capabilities"),
        process_failure_value(name),
        stack_trace,
    )
}

fn process_unsupported_mock_result(
    output: &OutputBuffer,
    name: &str,
    stack_trace: Vec<RuntimeStackFrame>,
) -> VmResult {
    process_warning_result(
        output,
        name,
        "E_PHP_VM_PROCESS_RESOURCE_MOCK_UNSUPPORTED",
        format!("{name}(): process resource APIs are not implemented by the standard-library mock"),
        process_failure_value(name),
        stack_trace,
    )
}

fn process_warning_result(
    _output: &OutputBuffer,
    _name: &str,
    id: &'static str,
    message: String,
    return_value: Value,
    stack_trace: Vec<RuntimeStackFrame>,
) -> VmResult {
    VmResult::success_with_diagnostics_no_output(
        Some(return_value),
        vec![RuntimeDiagnostic::new(
            id,
            RuntimeSeverity::Warning,
            message,
            RuntimeSourceSpan::default(),
            stack_trace,
            Some(php_runtime::PhpReferenceClassification::Warning),
        )],
    )
}

fn process_failure_value(name: &str) -> Value {
    match name {
        "shell_exec" | "passthru" => Value::Bool(false),
        _ => Value::Bool(false),
    }
}

fn process_output_lines_array(output: &str) -> Value {
    Value::packed_array(
        output
            .lines()
            .map(|line| Value::string(line.to_owned()))
            .collect(),
    )
}

fn process_last_output_line(output: &str) -> String {
    output.lines().last().unwrap_or_default().to_owned()
}

fn assign_process_ref_arg(
    stack: &mut CallStack,
    arg: &CallArgument,
    value: Value,
) -> Result<(), String> {
    let Some(local) = arg.by_ref_local else {
        return Ok(());
    };
    let frame = stack.current_mut().ok_or_else(|| {
        "E_PHP_VM_NO_ACTIVE_FRAME: cannot bind process reference argument".to_owned()
    })?;
    let _source = layout_source::enter(layout_source::BY_REF_ARGUMENT_BINDING);
    frame.locals.ensure_reference_cell(local)?.set(value);
    Ok(())
}

fn should_skip_top_level_auto_global_bind(
    function: &IrFunction,
    instruction: &Instruction,
) -> bool {
    let InstructionKind::BindGlobal { local, name } = &instruction.kind else {
        return false;
    };
    function.flags.is_top_level
        && is_auto_global_name(name)
        && function
            .locals
            .get(local.index())
            .is_some_and(|local_name| local_name == name)
}

fn is_auto_global_name(name: &str) -> bool {
    matches!(
        name,
        "argc"
            | "argv"
            | "_SERVER"
            | "_ENV"
            | "_GET"
            | "_POST"
            | "_COOKIE"
            | "_FILES"
            | "_REQUEST"
            | "_SESSION"
    )
}

fn bind_top_level_global_locals(
    function: &IrFunction,
    stack: &mut CallStack,
    state: &mut ExecutionState,
) {
    let Some(frame) = stack.current_mut() else {
        return;
    };
    for (index, name) in function.locals.iter().enumerate() {
        if name == "GLOBALS" {
            continue;
        }
        let cell = state
            .globals
            .ensure_slot(name.clone(), Value::Uninitialized);
        let _ = frame
            .locals
            .bind_reference_cell(LocalId::new(index as u32), cell);
    }
}

fn export_shared_locals_at_frame(
    function: &IrFunction,
    stack: &CallStack,
    frame_index: usize,
    shared: &mut HashMap<String, Slot>,
) {
    let Some(frame) = stack.frames().get(frame_index) else {
        return;
    };
    for (index, name) in function.locals.iter().enumerate() {
        if let Some(slot) = frame.locals.get_slot(LocalId::new(index as u32)) {
            shared.insert(name.clone(), slot.clone());
        }
    }
}

fn export_shared_locals(
    function: &IrFunction,
    stack: &CallStack,
    shared: &mut HashMap<String, Slot>,
) {
    let Some(frame_index) = stack.len().checked_sub(1) else {
        return;
    };
    export_shared_locals_at_frame(function, stack, frame_index, shared);
}

fn write_shared_locals_to_current_frame(
    compiled: &CompiledUnit,
    stack: &mut CallStack,
    shared: &HashMap<String, Slot>,
) {
    let Some(frame) = stack.current_mut() else {
        return;
    };
    let Some(function) = compiled.unit().functions.get(frame.function.index()) else {
        return;
    };
    for (index, name) in function.locals.iter().enumerate() {
        if let Some(slot) = shared.get(name) {
            let _ = frame
                .locals
                .set_slot(LocalId::new(index as u32), slot.clone());
        }
    }
}

fn stack_trace(compiled: &CompiledUnit, stack: &CallStack) -> Vec<RuntimeStackFrame> {
    stack
        .frames()
        .iter()
        .rev()
        .map(|frame| {
            let name = compiled
                .unit()
                .functions
                .get(frame.function.index())
                .map(|function| function.name.as_str())
                .unwrap_or("<missing>");
            RuntimeStackFrame::new(name)
        })
        .collect()
}

fn debug_backtrace_array(
    compiled: &CompiledUnit,
    stack: &CallStack,
    options: i64,
    limit: usize,
) -> PhpArray {
    let ignore_args = options & 2 != 0;
    let mut trace = PhpArray::new();
    for frame in debug_backtrace_frames(compiled, stack, limit) {
        let mut entry = PhpArray::new();
        let (file, line) = frame_source_location(compiled, frame);
        if !file.is_empty() {
            entry.insert(string_key("file"), Value::string(file));
        }
        if line > 0 {
            entry.insert(string_key("line"), Value::Int(line));
        }
        entry.insert(
            string_key("function"),
            Value::string(frame_function_display_name(compiled, frame)),
        );
        if !ignore_args {
            entry.insert(
                string_key("args"),
                Value::Array(frame_trace_args_array(compiled, frame)),
            );
        }
        trace.append(Value::Array(entry));
    }
    trace
}

fn capture_debug_print_backtrace_string(
    compiled: &CompiledUnit,
    stack: &CallStack,
    options: i64,
    limit: usize,
) -> String {
    let ignore_args = options & 2 != 0;
    debug_backtrace_frames(compiled, stack, limit)
        .into_iter()
        .enumerate()
        .map(|(index, frame)| {
            let (file, line) = frame_source_location(compiled, frame);
            let args = if ignore_args {
                String::new()
            } else {
                format_frame_trace_args(compiled, frame)
            };
            format!(
                "#{index} {file}({line}): {}({args})",
                frame_function_display_name(compiled, frame)
            )
        })
        .collect::<Vec<_>>()
        .join("\n")
}

fn debug_backtrace_frames<'a>(
    compiled: &CompiledUnit,
    stack: &'a CallStack,
    limit: usize,
) -> Vec<&'a Frame> {
    let frames = stack.frames().iter().rev().filter(|frame| {
        compiled
            .unit()
            .functions
            .get(frame.function.index())
            .is_some_and(|function| !function.flags.is_top_level)
    });
    if limit == 0 {
        frames.collect()
    } else {
        frames.take(limit).collect()
    }
}

fn string_key(name: &str) -> ArrayKey {
    ArrayKey::String(PhpString::from_test_str(name))
}

fn defined_symbol_names_array(names: &BTreeSet<String>) -> PhpArray {
    PhpArray::from_packed(names.iter().cloned().map(Value::string).collect())
}

fn frame_source_location(compiled: &CompiledUnit, frame: &Frame) -> (String, i64) {
    let function = compiled.unit().functions.get(frame.function.index());
    let display_span = frame
        .call_span
        .or_else(|| function.map(|function| function.span));
    let file = display_span
        .and_then(|span| compiled.unit().files.get(span.file.index()))
        .map(|file| file.path.clone())
        .unwrap_or_default();
    let line = display_span
        .and_then(|span| source_span_display_line(compiled, span, false))
        .or_else(|| display_span.map(|span| i64::from(span.start)))
        .unwrap_or(0);
    (file, line)
}

fn frame_function_display_name(compiled: &CompiledUnit, frame: &Frame) -> String {
    let Some(function) = compiled.unit().functions.get(frame.function.index()) else {
        return "{closure}".to_owned();
    };
    if function.flags.is_closure {
        let span = runtime_source_span(compiled, function.span);
        return format!(
            "{{closure:{}:{}}}",
            span.file.unwrap_or_default(),
            source_span_display_line(compiled, function.span, false)
                .unwrap_or_else(|| i64::from(function.span.start))
        );
    }
    if function.flags.is_method && function.name.contains("::") {
        let has_this = function
            .locals
            .iter()
            .position(|local| local == "this")
            .and_then(|index| frame.locals.get(LocalId::new(index as u32)))
            .is_some_and(|value| matches!(value, Value::Object(_)));
        if has_this {
            return function.name.replacen("::", "->", 1);
        }
    }
    function.name.clone()
}

/// Materializes a frame's backtrace arguments (see [`TraceArguments`]).
///
/// The lazy variant reconstructs from the live parameter locals — matching the
/// reference engine, where traces show the *current* slot values, parameter
/// mutations included — with the `arguments` vector supplying positional
/// extras beyond the declared parameters. A variadic tail expands its
/// collected array (named-argument labels preserved as string keys). Sensitive
/// parameters redact exactly as the eager builder did. When the frame's
/// function is not resolvable in `compiled` (foreign-unit frame), the raw
/// `arguments` vector is the fallback, mirroring the previous empty-snapshot
/// behavior.
fn materialized_frame_trace_arguments(
    compiled: &CompiledUnit,
    frame: &Frame,
) -> Vec<FrameTraceArgument> {
    let arg_count = match &frame.trace_arguments {
        TraceArguments::Materialized(entries) => return entries.clone(),
        TraceArguments::Lazy { arg_count } => *arg_count as usize,
    };
    let raw_fallback = |values: &[Value]| -> Vec<FrameTraceArgument> {
        values
            .iter()
            .map(|value| FrameTraceArgument {
                name: None,
                value: value.clone(),
            })
            .collect()
    };
    let Some(function) = compiled.unit().functions.get(frame.function.index()) else {
        return raw_fallback(&frame.arguments);
    };
    // A parameter local can be unbound when the frame failed argument
    // binding (a bind-time TypeError's own trace still shows the raw
    // argument, as the reference engine does) — fall back to the preserved
    // arguments vector by position.
    let live_local = |local: LocalId, index: usize| -> Value {
        match frame.locals.get_slot(local) {
            Some(Slot::Value(value)) if !value.is_uninitialized() => value.clone(),
            Some(Slot::Reference(cell)) => cell.get(),
            _ => frame.arguments.get(index).cloned().unwrap_or(Value::Null),
        }
    };
    let mut out = Vec::with_capacity(arg_count);
    for (index, param) in function.params.iter().enumerate() {
        if param.variadic {
            let sensitive = param_is_sensitive(param);
            if let Value::Array(array) = live_local(param.local, index) {
                for (key, value) in array.iter() {
                    let name = match key {
                        ArrayKey::String(name) => Some(name.to_string_lossy()),
                        ArrayKey::Int(_) => None,
                    };
                    out.push(FrameTraceArgument {
                        name,
                        value: trace_value_for_param(value, sensitive),
                    });
                }
            }
            return out;
        }
        if index >= arg_count {
            return out;
        }
        let value = live_local(param.local, index);
        out.push(FrameTraceArgument {
            name: None,
            value: trace_value_for_param(&value, param_is_sensitive(param)),
        });
    }
    // Positional extras beyond the declared parameters come from the
    // preserved arguments vector (they have no bound local).
    for value in frame
        .arguments
        .iter()
        .take(arg_count)
        .skip(function.params.len())
    {
        out.push(FrameTraceArgument {
            name: None,
            value: value.clone(),
        });
    }
    out
}

fn frame_trace_args_array(compiled: &CompiledUnit, frame: &Frame) -> PhpArray {
    let entries = materialized_frame_trace_arguments(compiled, frame);
    if entries.is_empty() {
        return PhpArray::from_packed(frame.arguments.clone());
    }
    let mut array = PhpArray::new();
    for arg in entries {
        // By-ref parameters store the live cell; PHP-visible trace args
        // carry the current value, not the reference wrapper.
        let value = match arg.value {
            Value::Reference(cell) => cell.get(),
            value => value,
        };
        if let Some(name) = arg.name {
            array.insert(ArrayKey::String(PhpString::from(name.as_str())), value);
        } else {
            array.append(value);
        }
    }
    array
}

fn format_frame_trace_args(compiled: &CompiledUnit, frame: &Frame) -> String {
    let entries = materialized_frame_trace_arguments(compiled, frame);
    if entries.is_empty() {
        return frame
            .arguments
            .iter()
            .map(format_trace_arg)
            .collect::<Vec<_>>()
            .join(", ");
    }
    entries
        .iter()
        .map(|arg| {
            let value = format_trace_arg(&arg.value);
            if let Some(name) = &arg.name {
                format!("{name}: {value}")
            } else {
                value
            }
        })
        .collect::<Vec<_>>()
        .join(", ")
}

/// Renders one argument as it appears in a PHP stack trace.
fn format_trace_arg(value: &Value) -> String {
    match value {
        Value::Reference(cell) => format_trace_arg(&cell.get()),
        Value::Null | Value::Uninitialized => "NULL".to_owned(),
        Value::Bool(true) => "true".to_owned(),
        Value::Bool(false) => "false".to_owned(),
        Value::Int(value) => value.to_string(),
        Value::Float(value) => {
            let value = value.to_f64();
            if value.fract() == 0.0 && value.is_finite() {
                format!("{value:.1}")
            } else {
                format!("{value}")
            }
        }
        Value::String(value) => {
            let text = value.to_string_lossy();
            if let Some(preview) = trace_string_preview(&text, 15) {
                format!("'{preview}...'")
            } else {
                format!("'{text}'")
            }
        }
        Value::Array(_) => "Array".to_owned(),
        Value::Object(object) => format!("Object({})", object.display_name()),
        Value::Fiber(_) => "Object(Fiber)".to_owned(),
        Value::Generator(_) => "Object(Generator)".to_owned(),
        Value::Resource(_) => "Resource".to_owned(),
        Value::Callable(_) => "Object(Closure)".to_owned(),
    }
}

fn trace_string_preview(text: &str, max_chars: usize) -> Option<&str> {
    text.char_indices()
        .nth(max_chars)
        .map(|(index, _)| &text[..index])
}

/// Renders a frame's `Class->method(args)` / `func(args)` call descriptor.
fn format_trace_call(compiled: &CompiledUnit, frame: &Frame) -> String {
    if compiled
        .unit()
        .functions
        .get(frame.function.index())
        .is_none()
    {
        return "{closure}()".to_owned();
    }
    let args = format_frame_trace_args(compiled, frame);
    let name = frame_function_display_name(compiled, frame);
    format!("{name}({args})")
}

/// Captures the current call stack as PHP's `Stack trace:` body, newest frame
/// first, ending with `#N {main}`.
fn capture_backtrace_string(compiled: &CompiledUnit, stack: &CallStack) -> String {
    capture_backtrace_string_from_index(compiled, stack, 0)
}

fn capture_backtrace_string_with_failed_call(
    compiled: &CompiledUnit,
    stack: &CallStack,
    function: &IrFunction,
    call_span: php_ir::IrSpan,
) -> String {
    let file = compiled
        .unit()
        .files
        .get(call_span.file.index())
        .map(|file| file.path.clone())
        .unwrap_or_default();
    let line = source_span_display_line(compiled, call_span, false)
        .unwrap_or_else(|| i64::from(call_span.start));
    let name = if function.flags.is_method && function.name.contains("::") {
        function.name.replacen("::", "->", 1)
    } else {
        function.name.clone()
    };
    let mut lines = vec![format!("#0 {file}({line}): {name}()")];
    let rest = capture_backtrace_string_from_index(compiled, stack, 1);
    if !rest.is_empty() {
        lines.push(rest);
    }
    lines.join("\n")
}

fn capture_backtrace_string_with_builtin_failed_call(
    compiled: &CompiledUnit,
    stack: &CallStack,
    function: &str,
    values: &[Value],
    call_span: php_ir::IrSpan,
) -> String {
    let file = compiled
        .unit()
        .files
        .get(call_span.file.index())
        .map(|file| file.path.clone())
        .unwrap_or_default();
    let line = source_span_display_line(compiled, call_span, false)
        .unwrap_or_else(|| i64::from(call_span.start));
    let args = values
        .iter()
        .map(format_trace_arg)
        .collect::<Vec<_>>()
        .join(", ");
    let mut lines = vec![format!("#0 {file}({line}): {function}({args})")];
    let rest = capture_backtrace_string_from_index(compiled, stack, 1);
    if !rest.is_empty() {
        lines.push(rest);
    }
    lines.join("\n")
}

fn builtin_failed_call_trace_array(
    compiled: &CompiledUnit,
    function: &str,
    values: &[Value],
    call_span: php_ir::IrSpan,
) -> PhpArray {
    let mut trace = PhpArray::new();
    let mut frame = PhpArray::new();
    if let Some(file) = compiled.unit().files.get(call_span.file.index()) {
        frame.insert(
            string_key("file"),
            Value::string(file.path.clone().into_bytes()),
        );
    }
    let line = source_span_display_line(compiled, call_span, false)
        .unwrap_or_else(|| i64::from(call_span.start));
    frame.insert(string_key("line"), Value::Int(line));
    frame.insert(
        string_key("function"),
        Value::string(function.as_bytes().to_vec()),
    );
    frame.insert(
        string_key("args"),
        Value::Array(PhpArray::from_packed(values.to_vec())),
    );
    trace.append(Value::Array(frame));
    trace
}

fn attach_builtin_failed_call_trace(
    throwable: &Value,
    compiled: &CompiledUnit,
    stack: &CallStack,
    function: &str,
    values: &[Value],
    call_span: php_ir::IrSpan,
) -> String {
    let trace_string = capture_backtrace_string_with_builtin_failed_call(
        compiled, stack, function, values, call_span,
    );
    if let Value::Object(object) = throwable {
        set_throwable_property(
            object,
            "trace",
            Value::Array(builtin_failed_call_trace_array(
                compiled, function, values, call_span,
            )),
        );
        set_throwable_property(
            object,
            "trace_string",
            Value::string(trace_string.clone().into_bytes()),
        );
    }
    trace_string
}

fn attach_tokenizer_static_error_handler_throw_trace(
    compiled: &CompiledUnit,
    stack: &CallStack,
    state: &mut ExecutionState,
    result: &VmResult,
    context: &TokenizerStaticCallTraceContext,
    level: i64,
    diagnostic: &RuntimeDiagnostic,
) {
    let handler_trace = state
        .pending_trace
        .take()
        .unwrap_or_else(|| capture_backtrace_string(compiled, stack));
    let trace = capture_backtrace_string_with_internal_error_handler_static_call(
        compiled,
        stack,
        context,
        &handler_trace,
        level,
        diagnostic,
    );
    if let Some(Value::Object(object)) = state
        .pending_throw
        .as_ref()
        .cloned()
        .or_else(|| runtime_error_throwable(result))
    {
        set_throwable_property(
            &object,
            "trace_string",
            Value::string(trace.clone().into_bytes()),
        );
    }
    state.pending_trace = Some(trace);
}

fn capture_backtrace_string_with_internal_error_handler_static_call(
    compiled: &CompiledUnit,
    stack: &CallStack,
    context: &TokenizerStaticCallTraceContext,
    handler_trace: &str,
    level: i64,
    diagnostic: &RuntimeDiagnostic,
) -> String {
    let file = compiled
        .unit()
        .files
        .get(context.call_span.file.index())
        .map(|file| file.path.clone())
        .unwrap_or_default();
    let line = source_span_display_line(compiled, context.call_span, false)
        .unwrap_or_else(|| i64::from(context.call_span.start));
    let args = context
        .values
        .iter()
        .map(format_trace_arg)
        .collect::<Vec<_>>()
        .join(", ");
    let mut handler_lines = handler_trace.lines();
    let first = handler_lines
        .next()
        .and_then(trace_line_call_descriptor)
        .map(|call| {
            let name = trace_call_name(call);
            let span = diagnostic.source_span();
            let handler_args = [
                Value::Int(level),
                Value::string(diagnostic.message()),
                Value::string(span.file.clone().unwrap_or_default()),
                Value::Int(span.start as i64),
            ]
            .iter()
            .map(format_trace_arg)
            .collect::<Vec<_>>()
            .join(", ");
            format!("{name}({handler_args})")
        })
        .unwrap_or_else(|| "{closure}()".to_owned());
    let mut lines = vec![
        format!("#0 [internal function]: {first}"),
        format!("#1 {file}({line}): {}({args})", context.call),
    ];
    let mut index = 2;
    let mut appended_rest = false;
    for line in handler_lines {
        lines.push(format!("#{index} {}", trace_line_without_index(line)));
        index += 1;
        appended_rest = true;
    }
    if !appended_rest {
        let rest = capture_backtrace_string_from_index(compiled, stack, 1);
        if !rest.is_empty() {
            for line in rest.lines() {
                lines.push(format!("#{index} {}", trace_line_without_index(line)));
                index += 1;
            }
        }
    }
    lines.join("\n")
}

fn trace_line_call_descriptor(line: &str) -> Option<&str> {
    line.split_once(": ").map(|(_, call)| call)
}

fn trace_call_name(call: &str) -> &str {
    call.split_once('(').map_or(call, |(name, _)| name)
}

fn trace_line_without_index(line: &str) -> &str {
    let Some(rest) = line.strip_prefix('#') else {
        return line;
    };
    let Some((index, rest)) = rest.split_once(' ') else {
        return line;
    };
    if index.chars().all(|char| char.is_ascii_digit()) {
        rest
    } else {
        line
    }
}

fn capture_backtrace_string_with_internal_iterator_builtin_call(
    compiled: &CompiledUnit,
    stack: &CallStack,
    function: &str,
    values: &[Value],
    call_span: php_ir::IrSpan,
) -> String {
    let file = compiled
        .unit()
        .files
        .get(call_span.file.index())
        .map(|file| file.path.clone())
        .unwrap_or_default();
    let line = source_span_display_line(compiled, call_span, false)
        .unwrap_or_else(|| i64::from(call_span.start));
    let args = values
        .iter()
        .map(format_trace_arg)
        .collect::<Vec<_>>()
        .join(", ");
    let mut lines = vec![
        format!(
            "#0 [internal function]: {}",
            format_internal_iterator_trace_call(compiled, values.first())
        ),
        format!("#1 {file}({line}): {function}({args})"),
    ];
    let rest = capture_backtrace_string_from_index(compiled, stack, 2);
    if !rest.is_empty() {
        lines.push(rest);
    }
    lines.join("\n")
}

fn append_throwable_internal_iterator_trace_arg_frame(
    throwable: &Value,
    compiled: &CompiledUnit,
    function: &str,
    values: &[Value],
    call_span: php_ir::IrSpan,
) {
    let Value::Object(object) = throwable else {
        return;
    };
    let mut trace = match get_throwable_property(object, "trace") {
        Some(Value::Array(array)) => array,
        _ => PhpArray::new(),
    };
    let mut frame = PhpArray::new();
    if let Some(file) = compiled.unit().files.get(call_span.file.index()) {
        frame.insert(
            string_key("file"),
            Value::string(file.path.clone().into_bytes()),
        );
    }
    let line = source_span_display_line(compiled, call_span, false)
        .unwrap_or_else(|| i64::from(call_span.start));
    frame.insert(string_key("line"), Value::Int(line));
    frame.insert(
        string_key("function"),
        Value::string(function.as_bytes().to_vec()),
    );
    frame.insert(
        string_key("args"),
        Value::Array(PhpArray::from_packed(values.to_vec())),
    );
    trace.append(Value::Array(frame));
    set_throwable_property(object, "trace", Value::Array(trace));
}

fn format_internal_iterator_trace_call(compiled: &CompiledUnit, value: Option<&Value>) -> String {
    let Some(Value::Generator(generator)) = value.map(effective_value) else {
        return "{closure}()".to_owned();
    };
    let Some(function) = compiled
        .unit()
        .functions
        .get(FunctionId::new(generator.function()).index())
    else {
        return "{closure}()".to_owned();
    };
    if function.flags.is_closure {
        let span = runtime_source_span(compiled, function.span);
        return format!(
            "{{closure:{}:{}}}()",
            span.file.unwrap_or_default(),
            source_span_display_line(compiled, function.span, false)
                .unwrap_or_else(|| i64::from(function.span.start))
        );
    }
    format!("{}()", function.name)
}

fn capture_backtrace_string_with_internal_spl_method_call(
    compiled: &CompiledUnit,
    stack: &CallStack,
    internal_call: &str,
    builtin_call: &str,
    call_span: php_ir::IrSpan,
) -> String {
    let file = compiled
        .unit()
        .files
        .get(call_span.file.index())
        .map(|file| file.path.clone())
        .unwrap_or_default();
    let line = source_span_display_line(compiled, call_span, false)
        .unwrap_or_else(|| i64::from(call_span.start));
    let mut lines = vec![
        format!("#0 [internal function]: {internal_call}()"),
        format!("#1 {file}({line}): {builtin_call}()"),
    ];
    let rest = capture_backtrace_string_from_index(compiled, stack, 2);
    if !rest.is_empty() {
        lines.push(rest);
    }
    lines.join("\n")
}

fn capture_backtrace_string_with_constant_expression(
    compiled: &CompiledUnit,
    stack: &CallStack,
    call_span: php_ir::IrSpan,
) -> String {
    let file = compiled
        .unit()
        .files
        .get(call_span.file.index())
        .map(|file| file.path.clone())
        .unwrap_or_default();
    let line = source_span_display_line(compiled, call_span, false)
        .unwrap_or_else(|| i64::from(call_span.start));
    let mut lines = vec![format!("#0 {file}({line}): [constant expression]()")];
    let rest = capture_backtrace_string_from_index(compiled, stack, 1);
    if !rest.is_empty() {
        lines.push(rest);
    }
    lines.join("\n")
}

fn capture_backtrace_string_from_index(
    compiled: &CompiledUnit,
    stack: &CallStack,
    start_index: usize,
) -> String {
    let mut lines = Vec::new();
    let mut index = start_index;
    for frame in stack.frames().iter().rev() {
        let function = compiled.unit().functions.get(frame.function.index());
        if function.is_some_and(|function| function.flags.is_top_level) {
            lines.push(format!("#{index} {{main}}"));
            index += 1;
            continue;
        }
        let display_span = frame
            .call_span
            .or_else(|| function.map(|function| function.span));
        let file = display_span
            .and_then(|span| compiled.unit().files.get(span.file.index()))
            .map(|file| file.path.clone())
            .unwrap_or_default();
        let line = display_span
            .and_then(|span| source_span_display_line(compiled, span, false))
            .or_else(|| display_span.map(|span| i64::from(span.start)))
            .unwrap_or(0);
        lines.push(format!(
            "#{index} {file}({line}): {}",
            format_trace_call(compiled, frame)
        ));
        index += 1;
    }
    if lines.is_empty() {
        lines.push("#0 {main}".to_owned());
    }
    lines.join("\n")
}

/// Determines whether a value is callable, matching PHP's `is_callable`. When
/// `syntax_only` is set, only the structural shape (string, or `[target, name]`
/// array) is checked, not whether the target actually exists.
fn value_is_callable(
    compiled: &CompiledUnit,
    state: &ExecutionState,
    value: &Value,
    syntax_only: bool,
) -> bool {
    match effective_value(value) {
        // Closures, first-class callables, and resolved function/builtin callables.
        Value::Callable(_) => true,
        Value::Object(object) => {
            lookup_method_in_state(compiled, state, &object.class_name(), "__invoke")
                .map(|method| method.is_some())
                .unwrap_or(false)
        }
        Value::String(name) => {
            let name = name.to_string_lossy();
            if syntax_only {
                return true;
            }
            if let Some((class, method)) = name.split_once("::") {
                lookup_method_in_state(compiled, state, class, method)
                    .map(|method| method.is_some_and(|method| method.flags.is_static))
                    .unwrap_or(false)
            } else {
                let normalized = normalize_function_name(&name);
                compiled.lookup_function(&normalized).is_some()
                    || dynamic_function_in_state(state, &normalized).is_some()
                    || BuiltinRegistry::new().contains(&normalized)
            }
        }
        Value::Array(array) => {
            let (Some(target), Some(method)) =
                (array.get(&ArrayKey::Int(0)), array.get(&ArrayKey::Int(1)))
            else {
                return false;
            };
            let Ok(method) = to_string(method) else {
                return false;
            };
            let Ok(class) = class_name_from_object_or_string(target) else {
                return false;
            };
            if syntax_only {
                return true;
            }
            let method = method.to_string_lossy();
            match effective_value(target) {
                Value::Object(_) => {
                    lookup_method_in_state(compiled, state, &class, &method)
                        .map(|method| method.is_some())
                        .unwrap_or(false)
                        || class_has_public_magic_call_in_state(compiled, state, &class)
                            .unwrap_or(false)
                }
                _ => {
                    lookup_method_in_state(compiled, state, &class, &method)
                        .map(|method| method.is_some_and(|method| method.flags.is_static))
                        .unwrap_or(false)
                        || class_has_public_magic_call_static_in_state(compiled, state, &class)
                            .unwrap_or(false)
                }
            }
        }
        _ => false,
    }
}

fn callable_name_for_is_callable(
    compiled: &CompiledUnit,
    state: &ExecutionState,
    value: &Value,
) -> Option<String> {
    match effective_value(value) {
        Value::Callable(callable) => match *callable {
            CallableValue::UserFunction { name } => Some(name),
            CallableValue::InternalBuiltin { name } => Some(name),
            CallableValue::Closure(payload) => {
                let function = compiled.unit().functions.get(payload.function as usize)?;
                payload
                    .debug
                    .map(|debug| debug.name)
                    .or_else(|| Some(function.name.clone()))
            }
            CallableValue::MethodPlaceholder { target }
            | CallableValue::UnresolvedDynamic { target } => Some(target),
            CallableValue::BoundMethod { target, method, .. } => {
                let class_name = match target {
                    CallableMethodTarget::Object(object) => {
                        callable_class_display_name(compiled, state, &object.class_name())
                    }
                    CallableMethodTarget::Class(class_name) => {
                        callable_class_display_name(compiled, state, &class_name)
                    }
                };
                Some(format!("{class_name}::{method}"))
            }
        },
        Value::Object(object) => Some(format!(
            "{}::__invoke",
            callable_class_display_name(compiled, state, &object.class_name())
        )),
        Value::String(name) => Some(name.to_string_lossy()),
        Value::Array(array) => callable_array_name_for_is_callable(compiled, state, &array),
        _ => None,
    }
}

fn callable_array_name_for_is_callable(
    compiled: &CompiledUnit,
    state: &ExecutionState,
    array: &PhpArray,
) -> Option<String> {
    let target = array.get(&ArrayKey::Int(0))?;
    let method = array.get(&ArrayKey::Int(1))?;
    let method = to_string(method).ok()?.to_string_lossy();
    match effective_value(target) {
        Value::Object(object) => Some(format!(
            "{}::{method}",
            callable_class_display_name(compiled, state, &object.class_name())
        )),
        Value::String(class_name) => {
            let class_name = class_name.to_string_lossy();
            Some(format!(
                "{}::{method}",
                callable_class_display_name(compiled, state, &class_name)
            ))
        }
        _ => None,
    }
}

fn autoload_callback_public_value(
    compiled: &CompiledUnit,
    state: &ExecutionState,
    callback: &CallableValue,
) -> Value {
    match callback {
        CallableValue::UserFunction { name } => {
            Value::string(user_function_display_name(compiled, state, name))
        }
        CallableValue::InternalBuiltin { name } => Value::string(name.clone()),
        CallableValue::Closure(_) => Value::Callable(Box::new(callback.clone())),
        CallableValue::BoundMethod { target, method, .. } => {
            if method.eq_ignore_ascii_case("__invoke")
                && let CallableMethodTarget::Object(object) = target
            {
                return Value::Object(object.clone());
            }
            let target = match target {
                CallableMethodTarget::Object(object) => Value::Object(object.clone()),
                CallableMethodTarget::Class(class_name) => {
                    Value::string(callable_class_display_name(compiled, state, class_name))
                }
            };
            Value::Array(PhpArray::from_packed(vec![
                target,
                Value::string(method.clone()),
            ]))
        }
        CallableValue::MethodPlaceholder { target }
        | CallableValue::UnresolvedDynamic { target } => Value::string(target.clone()),
    }
}

fn user_function_display_name(
    compiled: &CompiledUnit,
    state: &ExecutionState,
    normalized_name: &str,
) -> String {
    if let Some(function) = compiled.lookup_function(normalized_name)
        && let Some(function) = compiled.unit().functions.get(function.index())
    {
        return function.name.clone();
    }
    if let Some((owner, function)) = dynamic_function_in_state(state, normalized_name)
        && let Some(function) = owner.unit().functions.get(function.index())
    {
        return function.name.clone();
    }
    normalized_name.to_owned()
}

fn callable_class_display_name(
    compiled: &CompiledUnit,
    state: &ExecutionState,
    class_name: &str,
) -> String {
    lookup_class_in_state(compiled, state, class_name)
        .map(|class| class.display_name.clone())
        .or_else(|| {
            php_std::ExtensionRegistry::standard_library()
                .enabled_class(class_name)
                .map(|class| class.name().to_owned())
        })
        .unwrap_or_else(|| class_name.to_owned())
}

fn acquire_callable_value(
    compiled: &CompiledUnit,
    state: &ExecutionState,
    stack: &CallStack,
    value: Value,
) -> Result<Value, String> {
    let value = effective_value(&value);
    match value {
        Value::Callable(_) => Ok(value),
        Value::String(name) => {
            let name_text = name.to_string_lossy();
            validate_string_callable_acquisition(compiled, state, stack, &name_text)?;
            Ok(Value::String(name))
        }
        Value::Array(array) => acquire_array_callable(compiled, state, stack, &array),
        Value::Object(object) => {
            validate_object_method_callable_acquisition(
                compiled,
                state,
                stack,
                &object.class_name(),
                "__invoke",
                false,
            )?;
            Ok(Value::Object(object))
        }
        other => Err(format!(
            "E_PHP_VM_FIRST_CLASS_CALLABLE_NOT_CALLABLE: Value of type {} is not callable",
            value_type_name(&other)
        )),
    }
}

fn validate_string_callable_acquisition(
    compiled: &CompiledUnit,
    state: &ExecutionState,
    stack: &CallStack,
    name: &str,
) -> Result<(), String> {
    if let Some((class_name, method)) = name.split_once("::") {
        return validate_static_method_callable_acquisition(
            compiled, state, stack, class_name, method, true,
        );
    }
    let normalized = normalize_function_name(name);
    if function_callable_exists(compiled, state, &normalized) {
        Ok(())
    } else {
        Err(format!(
            "E_PHP_VM_FIRST_CLASS_CALLABLE_UNDEFINED_FUNCTION: Call to undefined function {name}()"
        ))
    }
}

fn acquire_array_callable(
    compiled: &CompiledUnit,
    state: &ExecutionState,
    stack: &CallStack,
    array: &PhpArray,
) -> Result<Value, String> {
    let (Some(target), Some(method)) = (array.get(&ArrayKey::Int(0)), array.get(&ArrayKey::Int(1)))
    else {
        return Err(
            "E_PHP_VM_FIRST_CLASS_CALLABLE_NOT_CALLABLE: Value of type array is not callable"
                .to_owned(),
        );
    };
    if array.len() != 2 {
        return Err(
            "E_PHP_VM_FIRST_CLASS_CALLABLE_NOT_CALLABLE: Value of type array is not callable"
                .to_owned(),
        );
    }
    let method = to_string(method)
        .map_err(|_| {
            "E_PHP_VM_FIRST_CLASS_CALLABLE_NOT_CALLABLE: Value of type array is not callable"
                .to_owned()
        })?
        .to_string_lossy();
    match effective_value(target) {
        Value::Object(object) => {
            validate_object_method_callable_acquisition(
                compiled,
                state,
                stack,
                &object.class_name(),
                &method,
                true,
            )?;
            Ok(Value::bound_method_callable(
                CallableMethodTarget::Object(object),
                method,
                current_scope_class(compiled, stack),
            ))
        }
        Value::Callable(callable) if method.eq_ignore_ascii_case("__invoke") => {
            Ok(Value::Callable(callable))
        }
        Value::String(class_name) => {
            let class_name = class_name.to_string_lossy();
            validate_static_method_callable_acquisition(
                compiled,
                state,
                stack,
                &class_name,
                &method,
                true,
            )?;
            Ok(Value::bound_method_callable(
                CallableMethodTarget::Class(class_name),
                method,
                current_scope_class(compiled, stack),
            ))
        }
        other => Err(format!(
            "E_PHP_VM_FIRST_CLASS_CALLABLE_NOT_CALLABLE: Value of type {} is not callable",
            value_type_name(&other)
        )),
    }
}

fn validate_object_method_callable_acquisition(
    compiled: &CompiledUnit,
    state: &ExecutionState,
    stack: &CallStack,
    class_name: &str,
    method: &str,
    allow_magic_call: bool,
) -> Result<(), String> {
    let Some(class) = lookup_class_in_state(compiled, state, class_name) else {
        let class_name = callable_class_display_name(compiled, state, class_name);
        return Err(format!(
            "E_PHP_VM_FIRST_CLASS_CALLABLE_UNDEFINED_METHOD: Call to undefined method {class_name}::{method}()"
        ));
    };
    let scope = current_scope_class(compiled, stack);
    let resolved =
        lookup_resolved_method_in_state(compiled, state, class_name, method, scope.as_deref())?;
    let Some(resolved) = resolved else {
        if allow_magic_call && class_has_public_magic_call_in_state(compiled, state, class_name)? {
            return Ok(());
        }
        return Err(format!(
            "E_PHP_VM_FIRST_CLASS_CALLABLE_UNDEFINED_METHOD: Call to undefined method {}::{method}()",
            class.display_name
        ));
    };
    validate_method_callable_for_acquisition_in_state(
        compiled,
        state,
        stack,
        &resolved.class,
        &resolved.method,
        method,
    )
}

fn validate_static_method_callable_acquisition(
    compiled: &CompiledUnit,
    state: &ExecutionState,
    stack: &CallStack,
    class_name: &str,
    method: &str,
    allow_magic_call_static: bool,
) -> Result<(), String> {
    let Some(class) = lookup_class_in_state(compiled, state, class_name) else {
        let class_name = callable_class_display_name(compiled, state, class_name);
        return Err(format!(
            "E_PHP_VM_FIRST_CLASS_CALLABLE_UNDEFINED_METHOD: Call to undefined method {class_name}::{method}()"
        ));
    };
    let scope = current_scope_class(compiled, stack);
    let resolved =
        lookup_resolved_method_in_state(compiled, state, class_name, method, scope.as_deref())?;
    let Some(resolved) = resolved else {
        if allow_magic_call_static
            && class_has_public_magic_call_static_in_state(compiled, state, class_name)?
        {
            return Ok(());
        }
        return Err(format!(
            "E_PHP_VM_FIRST_CLASS_CALLABLE_UNDEFINED_METHOD: Call to undefined method {}::{method}()",
            class.display_name
        ));
    };
    if !resolved.method.flags.is_static {
        return Err(format!(
            "E_PHP_VM_FIRST_CLASS_CALLABLE_NON_STATIC_METHOD: Non-static method {}::{}() cannot be called statically",
            resolved.class.display_name, method
        ));
    }
    validate_method_callable_for_acquisition_in_state(
        compiled,
        state,
        stack,
        &resolved.class,
        &resolved.method,
        method,
    )
}

fn class_has_public_magic_call_in_state(
    compiled: &CompiledUnit,
    state: &ExecutionState,
    class_name: &str,
) -> Result<bool, String> {
    Ok(
        lookup_resolved_method_in_state(compiled, state, class_name, "__call", None)?.is_some_and(
            |resolved| {
                !resolved.method.flags.is_static
                    && !resolved.method.flags.is_private
                    && !resolved.method.flags.is_protected
            },
        ),
    )
}

fn class_has_public_magic_call_static_in_state(
    compiled: &CompiledUnit,
    state: &ExecutionState,
    class_name: &str,
) -> Result<bool, String> {
    Ok(
        lookup_resolved_method_in_state(compiled, state, class_name, "__callStatic", None)?
            .is_some_and(|resolved| {
                resolved.method.flags.is_static
                    && !resolved.method.flags.is_private
                    && !resolved.method.flags.is_protected
            }),
    )
}

fn validate_method_callable_for_acquisition_in_state(
    compiled: &CompiledUnit,
    state: &ExecutionState,
    stack: &CallStack,
    class: &php_ir::module::ClassEntry,
    method: &php_ir::module::ClassMethodEntry,
    display_method: &str,
) -> Result<(), String> {
    if method.flags.is_abstract {
        return Err(format!(
            "E_PHP_VM_FIRST_CLASS_CALLABLE_UNDEFINED_METHOD: Cannot call abstract method {}::{display_method}()",
            class.display_name
        ));
    }
    if method.flags.is_private {
        let scope = current_scope_class(compiled, stack);
        if scope.as_deref() != Some(normalize_class_name(&class.name).as_str()) {
            return Err(format!(
                "E_PHP_VM_FIRST_CLASS_CALLABLE_UNDEFINED_METHOD: Call to private method {}::{display_method}() from {}",
                class.display_name,
                scope_description(scope.as_deref())
            ));
        }
    }
    if method.flags.is_protected {
        let scope = current_scope_class(compiled, stack);
        let allowed = scope.as_deref().is_some_and(|scope| {
            class_is_a_in_state(compiled, state, scope, &class.name).unwrap_or(false)
        });
        if !allowed {
            return Err(format!(
                "E_PHP_VM_FIRST_CLASS_CALLABLE_UNDEFINED_METHOD: Call to protected method {}::{display_method}() from {}",
                class.display_name,
                scope_description(scope.as_deref())
            ));
        }
    }
    Ok(())
}

fn function_callable_exists(
    compiled: &CompiledUnit,
    state: &ExecutionState,
    normalized_name: &str,
) -> bool {
    compiled.lookup_function(normalized_name).is_some()
        || dynamic_function_in_state(state, normalized_name).is_some()
        || is_callable_builtin_name(normalized_name)
}

fn is_callable_builtin_name(name: &str) -> bool {
    is_supported_builtin(name)
        || is_autoload_builtin_name(name)
        || is_symbol_introspection_builtin_name(name)
        || is_config_builtin_name(name)
        || is_error_handling_builtin_name(name)
        || is_output_buffering_builtin_name(name)
        || is_environment_builtin_name(name)
        || is_process_builtin_name(name)
        || is_filter_callback_builtin_name(name)
        || is_pcre_callback_builtin_name(name)
        || is_array_callback_builtin_name(name)
        || is_array_sort_builtin_name(name)
}

fn resolve_callable(
    compiled: &CompiledUnit,
    state: &ExecutionState,
    callable: &CallableKind,
) -> Result<Value, String> {
    match callable {
        CallableKind::FunctionName { name } => {
            if compiled.lookup_function(name).is_some()
                || dynamic_function_in_state(state, name).is_some()
            {
                Ok(Value::user_function_callable(name.clone()))
            } else if is_callable_builtin_name(name) {
                Ok(Value::internal_builtin_callable(name.clone()))
            } else {
                Err(format!(
                    "E_PHP_VM_FIRST_CLASS_CALLABLE_UNDEFINED_FUNCTION: Call to undefined function {name}()"
                ))
            }
        }
        CallableKind::MethodPlaceholder { target } => {
            Ok(Value::method_callable_placeholder(target.clone()))
        }
        CallableKind::UnresolvedDynamic { target } => Err(format!(
            "E_PHP_VM_FIRST_CLASS_CALLABLE_UNRESOLVED_DYNAMIC: callable {target} could not be resolved"
        )),
    }
}

fn is_supported_builtin(name: &str) -> bool {
    BuiltinRegistry::new().contains(name)
}

fn value_is_numeric_string_key_ambiguity(value: &Value) -> bool {
    let Value::String(string) = effective_value(value) else {
        return false;
    };
    php_runtime::numeric_string::array_key_has_numeric_string_ambiguity(&string)
}

fn value_needs_vm_string_coercion_in_state(
    compiled: &CompiledUnit,
    state: &ExecutionState,
    value: &Value,
) -> bool {
    match value {
        Value::Object(object) => object_has_public_to_string_in_state(compiled, state, object),
        Value::Reference(cell) => {
            value_needs_vm_string_coercion_in_state(compiled, state, &cell.get())
        }
        _ => false,
    }
}

fn internal_builtin_string_arg_positions(name: &str, arity: usize) -> &'static [usize] {
    match name {
        "addslashes"
        | "bin2hex"
        | "crc32"
        | "hex2bin"
        | "htmlentities"
        | "htmlspecialchars"
        | "htmlspecialchars_decode"
        | "lcfirst"
        | "ltrim"
        | "md5"
        | "ord"
        | "pack"
        | "rawurldecode"
        | "rawurlencode"
        | "rtrim"
        | "sha1"
        | "str_split"
        | "stripslashes"
        | "stripcslashes"
        | "strlen"
        | "strrev"
        | "strtolower"
        | "strtoupper"
        | "strval"
        | "trim"
        | "ucfirst"
        | "urlencode"
        | "urldecode" => &[0],
        "explode" | "str_contains" | "str_ends_with" | "str_starts_with" | "strstr" | "stristr"
        | "strpbrk" | "strpos" | "stripos" | "strrchr" | "strrpos" | "strripos"
        | "substr_count" | "strcmp" | "strcasecmp" | "strnatcmp" | "strnatcasecmp"
        | "version_compare" => &[0, 1],
        "str_repeat" | "str_pad" | "substr" | "substr_compare" | "strncmp" | "strncasecmp"
        | "strspn" | "strcspn" => &[0, 1],
        "strtr" if arity == 2 => &[0],
        "str_replace" | "strtr" | "substr_replace" => &[0, 1, 2],
        "print" | "printf" | "sprintf" | "vprintf" | "vsprintf" => &[0],
        "fprintf" | "vfprintf" => &[1],
        "ucwords" => &[0, 1],
        "unpack" => &[0, 1],
        "preg_grep" | "preg_match" | "preg_match_all" | "preg_split" => &[0, 1],
        "preg_quote" => &[0, 1],
        _ => &[],
    }
}

fn internal_function_dispatch_cacheable(name: &str) -> bool {
    name == "count"
        || name == "strlen"
        || name.starts_with("is_")
        || matches!(
            name,
            "array_chunk"
                | "array_column"
                | "array_combine"
                | "array_count_values"
                | "array_fill"
                | "array_flip"
                | "array_is_list"
                | "array_key_exists"
                | "array_keys"
                | "array_merge"
                | "array_pad"
                | "array_pop"
                | "array_push"
                | "array_reverse"
                | "array_search"
                | "array_shift"
                | "array_slice"
                | "array_splice"
                | "array_sum"
                | "array_unshift"
                | "array_values"
                | "implode"
                | "join"
                | "lcfirst"
                | "ltrim"
                | "rtrim"
                | "str_contains"
                | "str_ends_with"
                | "str_repeat"
                | "str_replace"
                | "str_split"
                | "str_starts_with"
                | "strtolower"
                | "strtoupper"
                | "substr"
                | "trim"
        )
}

#[derive(Clone, Copy, Debug, Eq, PartialEq)]
enum BuiltinIntrinsicKind {
    ArrayKeyExists,
    CountArray,
    ExplodeSingleByte,
    HtmlSpecialCharsDefault,
    IsArray,
    IsBool,
    IsFloat,
    IsInt,
    IsNull,
    IsNumeric,
    IsObject,
    IsScalar,
    IsString,
    PointerCurrent,
    PointerKey,
    ArrayKeysAll,
    ImplodeStringParts,
    StrContains,
    StrEndsWith,
    StrLen,
    StrReplaceScalar,
    StrStartsWith,
    StrToLower,
    StrToUpper,
    SubstrBytes,
    TrimDefault,
    InArrayStrict,
}

#[derive(Clone, Copy, Debug, Eq, PartialEq)]
struct BuiltinIntrinsicParam {
    name: &'static str,
    type_decl: &'static str,
    optional: bool,
    by_ref: bool,
}

#[derive(Clone, Copy, Debug, Eq, PartialEq)]
struct BuiltinIntrinsicSpec {
    name: &'static str,
    /// Counter label under `intrinsic_hits`/`intrinsic_misses`; carries the
    /// specialized-case suffix where the fast path covers only one shape.
    counter_name: &'static str,
    return_type: &'static str,
    params: &'static [BuiltinIntrinsicParam],
    /// Lowest supplied-argument count the fast path accepts.
    min_arity: usize,
    /// Highest supplied-argument count the fast path accepts.
    exact_arity: usize,
    kind: BuiltinIntrinsicKind,
}

