fn non_numeric_string_type_error(
    output: &mut OutputBuffer,
    compiled: &CompiledUnit,
    stack: &CallStack,
    lhs: &Value,
    op: BinaryOp,
    rhs: &Value,
    source_span: RuntimeSourceSpan,
) -> VmResult {
    let message = format!(
        "Unsupported operand types: {} {} {}",
        value_type_name(lhs),
        binary_operator_symbol(op),
        value_type_name(rhs)
    );
    let file = source_span.file.clone().unwrap_or_default();
    let line = runtime_source_span_display_line(&source_span).unwrap_or(0);
    let trace = capture_backtrace_string(compiled, stack);
    output.write_test_str(&format!(
        "\nFatal error: Uncaught TypeError: {message} in {file}:{line}\nStack trace:\n{trace}\n  thrown in {file} on line {line}\n"
    ));
    let diagnostic_message = format!("E_PHP_RUNTIME_NON_NUMERIC_STRING: {message}");
    let diagnostic = RuntimeDiagnostic::new(
        "E_PHP_RUNTIME_NON_NUMERIC_STRING",
        RuntimeSeverity::FatalError,
        diagnostic_message.clone(),
        source_span,
        stack_trace_from_captured_trace(&trace).unwrap_or_else(|| stack_trace(compiled, stack)),
        Some(php_runtime::PhpReferenceClassification::TypeError),
    );
    VmResult::runtime_error_with_diagnostic(output.clone(), diagnostic_message, diagnostic)
}

fn object_has_public_to_string(compiled: &CompiledUnit, object: &ObjectRef) -> bool {
    if is_php_token_runtime_class(&object.class_name()) {
        return true;
    }
    let Some(class) = compiled.lookup_class(&object.class_name()) else {
        return false;
    };
    let Ok(Some(resolved)) = lookup_method_in_hierarchy(compiled, class, "__toString", None) else {
        return false;
    };
    !resolved.method.flags.is_static
        && !resolved.method.flags.is_private
        && !resolved.method.flags.is_protected
}

fn object_has_public_to_string_in_state(
    compiled: &CompiledUnit,
    state: &ExecutionState,
    object: &ObjectRef,
) -> bool {
    if is_php_token_runtime_class(&object.class_name()) {
        return true;
    }
    let Ok(Some(resolved)) =
        lookup_resolved_method_in_state(compiled, state, &object.class_name(), "__toString", None)
    else {
        return false;
    };
    !resolved.method.flags.is_static
        && !resolved.method.flags.is_private
        && !resolved.method.flags.is_protected
}

fn bitwise_string_bytes(op: BinaryOp, lhs: &[u8], rhs: &[u8]) -> Vec<u8> {
    match op {
        BinaryOp::BitAnd => lhs
            .iter()
            .zip(rhs.iter())
            .map(|(left, right)| left & right)
            .collect(),
        BinaryOp::BitXor => lhs
            .iter()
            .zip(rhs.iter())
            .map(|(left, right)| left ^ right)
            .collect(),
        BinaryOp::BitOr => {
            let (longer, shorter, lhs_is_longer) = if lhs.len() >= rhs.len() {
                (lhs, rhs, true)
            } else {
                (rhs, lhs, false)
            };
            let mut bytes = Vec::with_capacity(longer.len());
            for index in 0..longer.len() {
                let byte = match (longer.get(index), shorter.get(index)) {
                    (Some(long), Some(short)) if lhs_is_longer => long | short,
                    (Some(long), Some(short)) => short | long,
                    (Some(long), None) => *long,
                    _ => unreachable!("bounded by longer length"),
                };
                bytes.push(byte);
            }
            bytes
        }
        BinaryOp::Add
        | BinaryOp::Sub
        | BinaryOp::Mul
        | BinaryOp::Div
        | BinaryOp::Mod
        | BinaryOp::Concat
        | BinaryOp::Pow
        | BinaryOp::ShiftLeft
        | BinaryOp::ShiftRight => unreachable!("not a string bitwise op"),
    }
}

fn execute_unary(op: UnaryOp, src: &Value) -> Result<Value, String> {
    match op {
        UnaryOp::Plus => match to_number(src)? {
            NumericValue::Int(value) => Ok(Value::Int(value)),
            NumericValue::Float(value) => Ok(Value::float(value)),
        },
        UnaryOp::Minus => match to_number(src)? {
            NumericValue::Int(value) => Ok(value
                .checked_neg()
                .map(Value::Int)
                .unwrap_or_else(|| Value::float(-(value as f64)))),
            NumericValue::Float(value) => Ok(Value::float(-value)),
        },
        UnaryOp::Not => Ok(Value::Bool(!to_bool(src)?)),
        UnaryOp::BitNot => match src {
            Value::Int(value) => Ok(Value::Int(!value)),
            Value::String(value) => {
                let bytes: Vec<u8> = value.as_bytes().iter().map(|byte| !byte).collect();
                Ok(Value::String(PhpString::from_bytes(bytes)))
            }
            _ => Err("bitwise not is only implemented for int and string operands".to_owned()),
        },
    }
}

fn execute_compare(op: CompareOp, lhs: &Value, rhs: &Value) -> Result<Value, String> {
    let value = match op {
        CompareOp::Equal => Value::Bool(equal(lhs, rhs)?),
        CompareOp::NotEqual => Value::Bool(!equal(lhs, rhs)?),
        CompareOp::Identical => Value::Bool(identical(lhs, rhs)),
        CompareOp::NotIdentical => Value::Bool(!identical(lhs, rhs)),
        CompareOp::Less => Value::Bool(compare(lhs, rhs)?.is_lt()),
        CompareOp::LessEqual => Value::Bool(!compare(lhs, rhs)?.is_gt()),
        CompareOp::Greater => Value::Bool(compare(lhs, rhs)?.is_gt()),
        CompareOp::GreaterEqual => Value::Bool(!compare(lhs, rhs)?.is_lt()),
        CompareOp::Spaceship => {
            let result = match compare(lhs, rhs)? {
                std::cmp::Ordering::Less => -1,
                std::cmp::Ordering::Equal => 0,
                std::cmp::Ordering::Greater => 1,
            };
            Value::Int(result)
        }
    };
    Ok(value)
}

